import React, { useEffect, useState, useMemo } from 'react';
import { DocumentService, UserService } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LineChart, Line, AreaChart, Area 
} from 'recharts';
import { 
    TrendingUp, Users, AlertTriangle, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase
} from 'lucide-react';

interface Props {
    user: User;
}

const COLORS = ['#94a3b8', '#60a5fa', '#a78bfa', '#f97316', '#22c55e', '#ef4444'];

const Reports: React.FC<Props> = ({ user }) => {
    const [docs, setDocs] = useState<Document[]>([]);
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [filterProject, setFilterProject] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll()
            ]);
            setDocs(d);
            setUsers(u);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    // --- DATA PROCESSING ---

    const filteredDocs = useMemo(() => {
        if (!filterProject) return docs;
        return docs.filter(d => d.project === filterProject);
    }, [docs, filterProject]);

    // 1. KPI CARDS DATA
    const kpis = useMemo(() => {
        const total = filteredDocs.length;
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED).length;
        const rejected = filteredDocs.filter(d => d.state === DocState.REJECTED).length;

        // Calculate "Stalled" (No update in 15 days and not approved)
        const twoWeeksAgo = new Date();
        twoWeeksAgo.setDate(twoWeeksAgo.getDate() - 15);
        const stalled = filteredDocs.filter(d => 
            d.state !== DocState.APPROVED && 
            d.state !== DocState.NOT_STARTED &&
            new Date(d.updatedAt) < twoWeeksAgo
        ).length;

        const avgProgress = total > 0 
            ? Math.round(filteredDocs.reduce((acc, curr) => acc + curr.progress, 0) / total) 
            : 0;

        return { total, approved, rejected, stalled, avgProgress };
    }, [filteredDocs]);

    // 2. CHART: State Distribution (Internal Processes)
    const stateData = useMemo(() => {
        const counts: Record<string, number> = {};
        filteredDocs.forEach(d => {
            // Simplify states for cleaner chart
            let key = 'En Proceso';
            if (d.state === DocState.NOT_STARTED) key = 'No Iniciado';
            else if (d.state === DocState.APPROVED) key = 'Aprobado';
            else if (d.state === DocState.REJECTED) key = 'Rechazado';
            else if (d.state === DocState.INTERNAL_REVIEW || d.state === DocState.SENT_TO_REFERENT || d.state === DocState.SENT_TO_CONTROL) key = 'En Revisión';

            counts[key] = (counts[key] || 0) + 1;
        });

        return Object.keys(counts).map(name => ({ name, value: counts[name] }));
    }, [filteredDocs]);

    // 3. CHART: Analyst Performance (Learning & Growth)
    const analystData = useMemo(() => {
        const stats: Record<string, { assigned: number, approved: number }> = {};

        filteredDocs.forEach(d => {
            if (d.assignees && d.assignees.length > 0) {
                d.assignees.forEach(uid => {
                    if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0 };
                    stats[uid].assigned += 1;
                    if (d.state === DocState.APPROVED) stats[uid].approved += 1;
                });
            } else {
                // Fallback to legacy authorId if no assignees
                const uid = d.authorId;
                if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0 };
                stats[uid].assigned += 1;
                if (d.state === DocState.APPROVED) stats[uid].approved += 1;
            }
        });

        return Object.keys(stats).map(uid => {
            const userObj = users.find(u => u.id === uid);
            return {
                name: userObj ? (userObj.nickname || userObj.name.split(' ')[0]) : 'Desc.',
                Asignados: stats[uid].assigned,
                Completados: stats[uid].approved,
                Eficiencia: stats[uid].assigned > 0 ? Math.round((stats[uid].approved / stats[uid].assigned) * 100) : 0
            };
        }).sort((a, b) => b.Asignados - a.Asignados).slice(0, 8); // Top 8 active analysts
    }, [filteredDocs, users]);

    // 4. CHART: Progress by Project (Results Perspective)
    const projectData = useMemo(() => {
        const projStats: Record<string, { total: number, progressSum: number }> = {};

        // Use all docs for this chart regardless of filter to show comparison, unless filtered specifically
        const sourceDocs = filterProject ? filteredDocs : docs;

        sourceDocs.forEach(d => {
            const p = d.project || 'Sin Proyecto';
            if (!projStats[p]) projStats[p] = { total: 0, progressSum: 0 };
            projStats[p].total += 1;
            projStats[p].progressSum += d.progress;
        });

        return Object.keys(projStats).map(p => ({
            name: p,
            avance: Math.round(projStats[p].progressSum / projStats[p].total),
            docs: projStats[p].total
        })).sort((a, b) => b.avance - a.avance);
    }, [docs, filteredDocs, filterProject]);

    // 5. CHART: Monthly Velocity (Customer Perspective - Speed)
    const velocityData = useMemo(() => {
        const monthly: Record<string, number> = {};
        const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];

        filteredDocs.forEach(d => {
            const date = new Date(d.updatedAt);
            const key = `${months[date.getMonth()]}`; // Simple grouping by month name
            // Count activity (updates)
            monthly[key] = (monthly[key] || 0) + 1;
        });

        // Ensure order relative to current year is tricky without full dates, 
        // simplified to show distribution of available data
        return Object.keys(monthly).map(m => ({
            name: m,
            actividad: monthly[m]
        }));
    }, [filteredDocs]);

    const availableProjects = useMemo(() => Array.from(new Set(docs.map(d => d.project).filter(Boolean))), [docs]);

    if (loading) return <div className="p-8 text-center text-slate-500">Generando reporte integral...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" />
                        Cuadro de Mando Integral
                    </h1>
                    <p className="text-slate-500">Reportes estratégicos y métricas de desempeño.</p>
                </div>

                <div className="flex items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select 
                        value={filterProject} 
                        onChange={(e) => setFilterProject(e.target.value)}
                        className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px]"
                    >
                        <option value="">Todos los Proyectos</option>
                        {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                </div>
            </div>

            {/* ROW 1: KPI CARDS */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                <KPICard title="Total Documentos" value={kpis.total} icon={FileText} color="indigo" sub="En alcance" />
                <KPICard title="Avance Global" value={`${kpis.avgProgress}%`} icon={TrendingUp} color="blue" sub="Promedio ponderado" />
                <KPICard title="Aprobados" value={kpis.approved} icon={CheckCircle} color="green" sub={`${((kpis.approved/kpis.total)*100 || 0).toFixed(1)}% Completitud`} />
                <KPICard title="Estancados" value={kpis.stalled} icon={Clock} color="orange" sub="> 15 días sin mov." />
                <KPICard title="Tasa Rechazo" value={kpis.rejected} icon={AlertTriangle} color="red" sub={`${((kpis.rejected/kpis.total)*100 || 0).toFixed(1)}% Devoluciones`} />
            </div>

            {/* ROW 2: MAIN CHARTS */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* 1. PERSPECTIVA INTERNA: ESTADO DE LOS DOCUMENTOS */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-1 flex flex-col">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Briefcase size={16} /> Procesos Internos
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Distribución actual por estado de flujo.</p>

                    <div className="flex-1 min-h-[250px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={stateData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={60}
                                    outerRadius={80}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {stateData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                    ))}
                                </Pie>
                                <Tooltip />
                                <Legend verticalAlign="bottom" height={36}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 2. PERSPECTIVA APRENDIZAJE: DESEMPEÑO DEL EQUIPO */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Users size={16} /> Aprendizaje y Crecimiento (Equipo)
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Carga de trabajo vs. Aprobaciones por Analista (Top 8).</p>

                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                data={analystData}
                                margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <Tooltip 
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    cursor={{fill: '#f8fafc'}}
                                />
                                <Legend />
                                <Bar dataKey="Asignados" stackId="a" fill="#94a3b8" radius={[4, 4, 0, 0]} barSize={30} />
                                <Bar dataKey="Completados" stackId="b" fill="#22c55e" radius={[4, 4, 0, 0]} barSize={30} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

            {/* ROW 3: TRENDS & RESULTS */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* 3. PERSPECTIVA RESULTADOS: AVANCE POR PROYECTO */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <TrendingUp size={16} /> Resultados: Avance por Proyecto
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Promedio de avance % por unidad de proyecto.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                layout="vertical"
                                data={projectData}
                                margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                                <XAxis type="number" domain={[0, 100]} hide />
                                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                                <Tooltip />
                                <Bar dataKey="avance" fill="#6366f1" radius={[0, 4, 4, 0]} barSize={20} name="% Avance">
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 4. PERSPECTIVA CLIENTE: VELOCIDAD */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Clock size={16} /> Cliente: Ritmo de Actividad
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Volumen de interacciones/actualizaciones por mes.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <AreaChart
                                data={velocityData}
                                margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
                            >
                                <defs>
                                    <linearGradient id="colorAct" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#8884d8" stopOpacity={0.8}/>
                                        <stop offset="95%" stopColor="#8884d8" stopOpacity={0}/>
                                    </linearGradient>
                                </defs>
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <Tooltip />
                                <Area type="monotone" dataKey="actividad" stroke="#8884d8" fillOpacity={1} fill="url(#colorAct)" />
                            </AreaChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>
        </div>
    );
};

// --- SUBCOMPONENTS ---

const KPICard = ({ title, value, icon: Icon, color, sub }: any) => {
    const colorClasses: Record<string, string> = {
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100',
        blue: 'bg-blue-50 text-blue-600 border-blue-100',
        green: 'bg-green-50 text-green-600 border-green-100',
        orange: 'bg-orange-50 text-orange-600 border-orange-100',
        red: 'bg-red-50 text-red-600 border-red-100',
    };

    return (
        <div className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} transition-transform hover:scale-105`}>
            <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span>
                <Icon size={18} />
            </div>
            <div>
                <span className="text-2xl font-bold">{value}</span>
                <p className="text-[10px] opacity-80 mt-1 font-medium">{sub}</p>
            </div>
        </div>
    );
};

export default Reports;

import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { Menu, X, FileText, BarChart2, PlusCircle, LogOut, User as UserIcon, Users, ClipboardList, Inbox, Database, Settings, ListTodo, Network, PieChart } from 'lucide-react';
import { User, UserRole, DocState, Document } from '../types';
import { NotificationService } from '../services/firebaseBackend';

interface LayoutProps {
  children: React.ReactNode;
  user: User;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, user, onLogout }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [inboxCount, setInboxCount] = useState(0);
  const location = useLocation();

  const isActive = (path: string) => location.pathname === path ? 'bg-slate-800 text-white' : 'text-slate-300 hover:bg-slate-800 hover:text-white';

  // Fetch Inbox Count Logic (Real-time)
  useEffect(() => {
    // Suscribirse a cambios en tiempo real en las notificaciones no leídas
    const unsubscribe = NotificationService.subscribeToUnreadCount(user.id, (count) => {
        setInboxCount(count);
    });

    // Cleanup subscription on unmount
    return () => unsubscribe();
  }, [user.id]); 

  const NavItem = ({ to, icon: Icon, label, badge }: { to: string, icon: any, label: string, badge?: number }) => (
    <Link
      to={to}
      onClick={() => setIsSidebarOpen(false)}
      className={`flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${isActive(to)}`}
    >
      <Icon size={20} />
      <span className="font-medium flex-1">{label}</span>
      {badge !== undefined && badge > 0 && (
          <span className="bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full ml-auto">
              {badge}
          </span>
      )}
    </Link>
  );

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-20 md:hidden" 
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white transform transition-transform duration-200 ease-in-out md:translate-x-0 md:static md:flex-shrink-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-slate-800 flex justify-between items-center flex-shrink-0">
            <div>
                <h1 className="text-xl font-bold tracking-tight">SGD</h1>
                <p className="text-xs text-slate-400">Gestión Documental</p>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden text-slate-400">
                <X size={24} />
            </button>
          </div>

          <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto custom-scrollbar">

            {/* Group 1: Gestión */}
            <div className="pb-2 text-xs font-semibold text-slate-500 uppercase tracking-wider px-4">Gestión</div>
            <NavItem to="/" icon={BarChart2} label="Dashboard" />
            <NavItem to="/inbox" icon={Inbox} label="Bandeja de Entrada" badge={inboxCount} />
            <NavItem to="/worklist" icon={ListTodo} label="Lista de Trabajo" />
            <NavItem to="/new" icon={PlusCircle} label="Nueva Solicitud" />

            {/* Group 2: Administración */}
            {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
              <>
                <div className="pt-4 pb-2 text-xs font-semibold text-slate-500 uppercase tracking-wider px-4">Administración</div>

                {/* Reports (CMI) */}
                <NavItem to="/admin/reports" icon={PieChart} label="Reportes (CMI)" />

                {/* Estructura (Module A) */}
                <NavItem to="/admin/structure" icon={Network} label="Estructura" />

                {/* Asignaciones (Module B) */}
                <NavItem to="/admin/assignments" icon={ClipboardList} label="Asignaciones" />

                {/* Admin Only Items - Alphabetical Order */}
                {user.role === UserRole.ADMIN && (
                    <>
                        <NavItem to="/admin/database" icon={Database} label="Base de Datos" />
                        <NavItem to="/admin/users" icon={Users} label="Usuarios" />
                    </>
                )}
              </>
            )}

            {/* Group 3: Cuenta */}
            <div className="pt-4 pb-2 text-xs font-semibold text-slate-500 uppercase tracking-wider px-4">Cuenta</div>
            <NavItem to="/profile" icon={Settings} label="Mi Perfil" />
          </nav>

          <div className="p-4 border-t border-slate-800 flex-shrink-0">
            <div className="flex items-center space-x-3 mb-4 px-2">
                <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-sm font-bold overflow-hidden flex-shrink-0">
                    {user.avatar && user.avatar.startsWith('http') ? (
                        <img src={user.avatar} alt="avatar" className="w-full h-full object-cover" />
                    ) : (
                        user.name.charAt(0)
                    )}
                </div>
                <div className="overflow-hidden min-w-0">
                    <p className="text-sm font-medium truncate">{user.name}</p>
                    <p className="text-xs text-slate-400 truncate capitalize">{user.role.toLowerCase()}</p>
                </div>
            </div>
            <button 
                onClick={onLogout}
                className="w-full flex items-center justify-center space-x-2 bg-slate-800 hover:bg-slate-700 p-2 rounded-md transition-colors text-sm"
            >
                <LogOut size={16} />
                <span>Cerrar Sesión</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Mobile Header */}
        <header className="bg-white border-b border-gray-200 p-4 flex items-center justify-between md:hidden flex-shrink-0">
            <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600">
                <Menu size={24} />
            </button>
            <span className="font-semibold text-slate-800">SGD Mobile</span>
            <div className="w-6" /> {/* Spacer */}
        </header>

        <main className="flex-1 overflow-y-auto p-4 md:p-8">
            {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React, { useEffect, useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Login from './views/Login';
import Dashboard from './views/Dashboard';
import CreateDocument from './views/CreateDocument';
import DocumentDetail from './views/DocumentDetail';
import AdminUsers from './views/AdminUsers';
import AdminAssignments from './views/AdminAssignments';
import AdminHierarchy from './views/AdminHierarchy'; 
import AdminDatabase from './views/AdminDatabase';
import Reports from './views/Reports'; // Import Reports View
import Buffer from './views/Buffer';
import WorkList from './views/WorkList';
import Profile from './views/Profile';
import { UserRole } from './types'; 
import { logoutUser } from './services/firebaseAuthService'; 
import { useAuthStatus } from './hooks/useAuthStatus'; 
import { RefreshCw } from 'lucide-react';

const App: React.FC = () => {
    const { user, cargando } = useAuthStatus(); 

    const handleLogout = async () => {
        await logoutUser(); 
        // Eliminado window.location.reload() para permitir redirección suave por estado
    };

    if (cargando) {
        return (
            <div className="flex flex-col h-screen items-center justify-center bg-slate-50 gap-4">
                <div className="flex items-center gap-2 text-indigo-600 font-semibold animate-pulse">
                    <RefreshCw className="animate-spin" />
                    Cargando aplicación...
                </div>
            </div>
        );
    }

    return (
        <HashRouter>
            <Routes>
                <Route 
                    path="/login" 
                    element={!user ? <Login /> : <Navigate to="/" />} 
                />

                <Route
                    path="*"
                    element={
                        user ? (
                            <Layout user={user} onLogout={handleLogout}>
                                <Routes>
                                    <Route path="/" element={<Dashboard user={user} />} />

                                    <Route path="/inbox" element={<Buffer user={user} />} />
                                    <Route path="/worklist" element={<WorkList user={user} />} />
                                    <Route path="/new" element={<CreateDocument user={user} />} />
                                    <Route path="/doc/:id" element={<DocumentDetail user={user} />} />

                                    <Route path="/profile" element={<Profile user={user} onUpdate={() => window.location.reload()} />} /> 

                                    {/* Rutas de Administración */}
                                    <Route 
                                        path="/admin/users" 
                                        element={user.role === UserRole.ADMIN ? <AdminUsers /> : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/assignments" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? <AdminAssignments user={user} /> : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/structure" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? <AdminHierarchy user={user} /> : <Navigate to="/" />} 
                                    />
                                    {/* New Reports Route */}
                                    <Route 
                                        path="/admin/reports" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? <Reports user={user} /> : <Navigate to="/" />} 
                                    />

                                    <Route 
                                        path="/admin/database" 
                                        element={user.role === UserRole.ADMIN ? <AdminDatabase /> : <Navigate to="/" />} 
                                    />
                                    <Route path="*" element={<Navigate to="/" />} />
                                </Routes>
                            </Layout>
                        ) : (
                            <Navigate to="/login" />
                        )
                    }
                />
            </Routes>
        </HashRouter>
    );
};

export default App;

