import React, { useEffect, useState, useMemo } from 'react';
import { DocumentService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType } from '../types';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area 
} from 'recharts';
import { 
    TrendingUp, Users, AlertTriangle, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2
} from 'lucide-react';

interface Props {
    user: User;
}

// Extends Document to handle "Virtual" documents (not yet created but required)
interface ReportDoc extends Document {
    isVirtual?: boolean;
    requiredType?: string;
}

const COLORS = ['#94a3b8', '#60a5fa', '#a78bfa', '#f97316', '#22c55e', '#ef4444'];

const Reports: React.FC<Props> = ({ user }) => {
    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [filterProject, setFilterProject] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    // --- DATA PROCESSING (Link Matriz vs Realidad) ---

    // Genera el universo completo de documentos (Real + Virtual) basado en la Matriz
    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];

        const unifiedList: ReportDoc[] = [];

        // 1. Indexar documentos reales para búsqueda rápida
        const realDocMap = new Map<string, Document>();
        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                // Keep most recent
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        // 2. Recorrer la Jerarquía (Lo que DEBE existir)
        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    const nodes = hierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        // Skip inactive nodes in hierarchy for reporting
                        if (node.active === false) return;

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                            if (realDocMap.has(key)) {
                                // Existe documento real
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    // Ensure assignees are synced with matrix if doc is old
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false
                                });
                            } else {
                                // No existe -> Documento Virtual "No Iniciado"
                                unifiedList.push({
                                    id: `virtual-${key}`,
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [], // Here we link analysts from Assignments Matrix
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(),
                                    hasPendingRequest: false,
                                    isVirtual: true,
                                    requiredType: type
                                });
                            }
                        });
                    });
                });
            });
        });

        return unifiedList;
    }, [realDocs, hierarchy]);


    const filteredDocs = useMemo(() => {
        if (!filterProject) return unifiedData;
        return unifiedData.filter(d => d.project === filterProject);
    }, [unifiedData, filterProject]);


    // 1. KPI CARDS DATA
    const kpis = useMemo(() => {
        const total = filteredDocs.length; // Total Required based on Matrix
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED).length;
        const rejected = filteredDocs.filter(d => d.state === DocState.REJECTED).length;

        // Estancados: Documentos iniciados pero sin movimiento reciente
        const twoWeeksAgo = new Date();
        twoWeeksAgo.setDate(twoWeeksAgo.getDate() - 15);

        const stalled = filteredDocs.filter(d => 
            d.state !== DocState.APPROVED && 
            d.state !== DocState.NOT_STARTED && // Don't count "Not Started" as stalled, just pending
            new Date(d.updatedAt) < twoWeeksAgo
        ).length;

        // Progress average across ALL required documents (including 0% for Not Started)
        const avgProgress = total > 0 
            ? Math.round(filteredDocs.reduce((acc, curr) => acc + curr.progress, 0) / total) 
            : 0;

        return { total, approved, rejected, stalled, avgProgress };
    }, [filteredDocs]);

    // 2. CHART: State Distribution
    const stateData = useMemo(() => {
        const counts: Record<string, number> = {};

        // Initialize specific keys order
        counts['No Iniciado'] = 0;
        counts['En Proceso'] = 0;
        counts['En Revisión'] = 0;
        counts['Rechazado'] = 0;
        counts['Aprobado'] = 0;

        filteredDocs.forEach(d => {
            let key = 'En Proceso';
            if (d.state === DocState.NOT_STARTED) key = 'No Iniciado';
            else if (d.state === DocState.APPROVED) key = 'Aprobado';
            else if (d.state === DocState.REJECTED) key = 'Rechazado';
            else if (d.state === DocState.INTERNAL_REVIEW || d.state === DocState.SENT_TO_REFERENT || d.state === DocState.SENT_TO_CONTROL || d.state === DocState.REFERENT_REVIEW || d.state === DocState.CONTROL_REVIEW) key = 'En Revisión';

            counts[key] = (counts[key] || 0) + 1;
        });

        return Object.keys(counts).filter(k => counts[k] > 0).map(name => ({ name, value: counts[name] }));
    }, [filteredDocs]);

    // 3. CHART: Analyst Performance (Using Assigned Matrix Data)
    const analystData = useMemo(() => {
        const stats: Record<string, { assigned: number, approved: number, inProgress: number }> = {};

        filteredDocs.forEach(d => {
            // Count for all assignees found in the Matrix (or doc legacy)
            if (d.assignees && d.assignees.length > 0) {
                d.assignees.forEach(uid => {
                    if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0, inProgress: 0 };

                    stats[uid].assigned += 1;

                    if (d.state === DocState.APPROVED) {
                        stats[uid].approved += 1;
                    } else if (d.state !== DocState.NOT_STARTED) {
                        stats[uid].inProgress += 1;
                    }
                });
            } else {
                // Unassigned bucket?
                const uid = 'unassigned';
                if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0, inProgress: 0 };
                stats[uid].assigned += 1;
            }
        });

        return Object.keys(stats)
            .filter(uid => uid !== 'unassigned')
            .map(uid => {
                const userObj = users.find(u => u.id === uid);
                return {
                    name: userObj ? (userObj.nickname || userObj.name.split(' ')[0]) : 'Desc.',
                    Total: stats[uid].assigned,
                    Completados: stats[uid].approved,
                    Avance: stats[uid].inProgress,
                    Eficiencia: stats[uid].assigned > 0 ? Math.round((stats[uid].approved / stats[uid].assigned) * 100) : 0
                };
            })
            .sort((a, b) => b.Total - a.Total)
            .slice(0, 10); // Top 10
    }, [filteredDocs, users]);

    // 4. CHART: Progress by Project
    const projectData = useMemo(() => {
        const projStats: Record<string, { total: number, progressSum: number }> = {};

        const sourceDocs = filterProject ? filteredDocs : unifiedData;

        sourceDocs.forEach(d => {
            const p = d.project || 'Sin Proyecto';
            if (!projStats[p]) projStats[p] = { total: 0, progressSum: 0 };
            projStats[p].total += 1;
            projStats[p].progressSum += d.progress;
        });

        return Object.keys(projStats).map(p => ({
            name: p,
            avance: Math.round(projStats[p].progressSum / projStats[p].total),
            docs: projStats[p].total
        })).sort((a, b) => b.avance - a.avance);
    }, [unifiedData, filteredDocs, filterProject]);

    // 5. CHART: Monthly Activity (Correct Chronological Order)
    const velocityData = useMemo(() => {
        const activityMap: Record<string, number> = {};

        // Only count real updates, ignore virtual not started docs
        const activeDocs = filteredDocs.filter(d => !d.isVirtual && d.state !== DocState.NOT_STARTED);

        activeDocs.forEach(d => {
            const date = new Date(d.updatedAt);
            // Key format YYYY-MM for correct sorting
            const sortKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
            activityMap[sortKey] = (activityMap[sortKey] || 0) + 1;
        });

        // Sort keys chronologically
        const sortedKeys = Object.keys(activityMap).sort();

        // Map to display format
        const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];

        return sortedKeys.map(key => {
            const [year, month] = key.split('-');
            const monthIndex = parseInt(month, 10) - 1;
            return {
                name: `${months[monthIndex]}`, // e.g., "Sep"
                fullLabel: `${months[monthIndex]} ${year}`,
                actividad: activityMap[key]
            };
        });
    }, [filteredDocs]);

    const availableProjects = useMemo(() => Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))), [unifiedData]);

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Calculando métricas del universo completo...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" />
                        Reportes de Gestión
                    </h1>
                    <p className="text-slate-500">Métricas basadas en la Matriz de Asignaciones (Universo Total).</p>
                </div>

                <div className="flex items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select 
                        value={filterProject} 
                        onChange={(e) => setFilterProject(e.target.value)}
                        className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px]"
                    >
                        <option value="">Todos los Proyectos</option>
                        {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                </div>
            </div>

            {/* ROW 1: KPI CARDS */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                <KPICard title="Total Requeridos" value={kpis.total} icon={FileText} color="indigo" sub="Definidos en Matriz" />
                <KPICard title="Cumplimiento Real" value={`${kpis.avgProgress}%`} icon={TrendingUp} color="blue" sub="Sobre total requerido" />
                <KPICard title="Finalizados" value={kpis.approved} icon={CheckCircle} color="green" sub={`${((kpis.approved/kpis.total)*100 || 0).toFixed(1)}% del Universo`} />
                <KPICard title="Sin Avance" value={kpis.stalled} icon={Clock} color="orange" sub="Iniciados s/mov. >15d" />
                <KPICard title="Tasa Devolución" value={kpis.rejected} icon={AlertTriangle} color="red" sub={`${((kpis.rejected/kpis.total)*100 || 0).toFixed(1)}% Rechazos`} />
            </div>

            {/* ROW 2: MAIN CHARTS */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* 1. PERSPECTIVA INTERNA: ESTADO DE LOS DOCUMENTOS */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-1 flex flex-col">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Briefcase size={16} /> Estado del Universo
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Incluye documentos "No Iniciados" definidos en asignaciones.</p>

                    <div className="flex-1 min-h-[250px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={stateData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={60}
                                    outerRadius={80}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {stateData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                    ))}
                                </Pie>
                                <Tooltip />
                                <Legend verticalAlign="bottom" height={36}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 2. PERSPECTIVA APRENDIZAJE: DESEMPEÑO DEL EQUIPO */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Users size={16} /> Gestión por Analista (Top 10)
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Total Asignado en Matriz vs. Documentos Completados.</p>

                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                data={analystData}
                                margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <Tooltip 
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    cursor={{fill: '#f8fafc'}}
                                />
                                <Legend />
                                <Bar dataKey="Total" name="Asignados (Matriz)" fill="#94a3b8" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="Avance" name="En Gestión" stackId="a" fill="#60a5fa" radius={[0, 0, 0, 0]} barSize={20} />
                                <Bar dataKey="Completados" name="Aprobados" stackId="a" fill="#22c55e" radius={[4, 4, 0, 0]} barSize={20} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

            {/* ROW 3: TRENDS & RESULTS */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* 3. PERSPECTIVA RESULTADOS: AVANCE POR PROYECTO */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <TrendingUp size={16} /> Cumplimiento por Proyecto
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Promedio de avance considerando el 100% de la carga requerida.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                layout="vertical"
                                data={projectData}
                                margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                                <XAxis type="number" domain={[0, 100]} hide />
                                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                                <Tooltip />
                                <Bar dataKey="avance" fill="#6366f1" radius={[0, 4, 4, 0]} barSize={20} name="% Cumplimiento">
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 4. PERSPECTIVA CLIENTE: VELOCIDAD */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Clock size={16} /> Evolución Mensual
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Volumen de actividad (actualizaciones) ordenado cronológicamente.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <AreaChart
                                data={velocityData}
                                margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
                            >
                                <defs>
                                    <linearGradient id="colorAct" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#8884d8" stopOpacity={0.8}/>
                                        <stop offset="95%" stopColor="#8884d8" stopOpacity={0}/>
                                    </linearGradient>
                                </defs>
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <Tooltip labelFormatter={(label, payload) => payload[0]?.payload.fullLabel || label} />
                                <Area type="monotone" dataKey="actividad" stroke="#8884d8" fillOpacity={1} fill="url(#colorAct)" />
                            </AreaChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>
        </div>
    );
};

// --- SUBCOMPONENTS ---

const KPICard = ({ title, value, icon: Icon, color, sub }: any) => {
    const colorClasses: Record<string, string> = {
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100',
        blue: 'bg-blue-50 text-blue-600 border-blue-100',
        green: 'bg-green-50 text-green-600 border-green-100',
        orange: 'bg-orange-50 text-orange-600 border-orange-100',
        red: 'bg-red-50 text-red-600 border-red-100',
    };

    return (
        <div className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} transition-transform hover:scale-105`}>
            <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span>
                <Icon size={18} />
            </div>
            <div>
                <span className="text-2xl font-bold">{value}</span>
                <p className="text-[10px] opacity-80 mt-1 font-medium">{sub}</p>
            </div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area 
} from 'recharts';
import { 
    TrendingUp, Users, AlertTriangle, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, User as UserIcon, ArrowRight
} from 'lucide-react';

interface Props {
    user: User;
}

// Extends Document to handle "Virtual" documents (not yet created but required)
interface ReportDoc extends Document {
    isVirtual?: boolean;
    requiredType?: string;
}

const COLORS = ['#94a3b8', '#60a5fa', '#a78bfa', '#f97316', '#22c55e', '#ef4444', '#1e293b', '#cbd5e1'];

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    // --- DATA PROCESSING (Link Matriz vs Realidad) ---

    // Genera el universo completo de documentos (Real + Virtual) basado en la Matriz
    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];

        const unifiedList: ReportDoc[] = [];

        // 1. Indexar documentos reales para búsqueda rápida
        const realDocMap = new Map<string, Document>();
        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                // Keep most recent
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        // 2. Recorrer la Jerarquía (Lo que DEBE existir)
        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    const nodes = hierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        // Skip inactive nodes in hierarchy for reporting
                        if (node.active === false) return;

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                            if (realDocMap.has(key)) {
                                // Existe documento real
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    // Ensure assignees are synced with matrix if doc is old
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false
                                });
                            } else {
                                // No existe -> Documento Virtual "No Iniciado"
                                unifiedList.push({
                                    id: `virtual-${key}`, // Special ID for virtual docs
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [], // Here we link analysts from Assignments Matrix
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(),
                                    hasPendingRequest: false,
                                    isVirtual: true,
                                    requiredType: type
                                });
                            }
                        });
                    });
                });
            });
        });

        return unifiedList;
    }, [realDocs, hierarchy]);


    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);


    // 1. KPI CARDS DATA (Updated Structure)
    const kpis = useMemo(() => {
        const total = filteredDocs.length;
        const totalIds = filteredDocs.map(d => d.id);

        const approvedDocs = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const approvedIds = approvedDocs.map(d => d.id);

        // Calculate 30 days threshold
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

        // Helper to check stall
        const isStalled = (d: ReportDoc) => {
            if (d.isVirtual || d.state === DocState.NOT_STARTED) return false;
            return new Date(d.updatedAt) < thirtyDaysAgo;
        };

        // Internal Stalled (Initiated, In Process, Internal Review)
        const internalStates = [DocState.INITIATED, DocState.IN_PROCESS, DocState.INTERNAL_REVIEW];
        const stalledInternalDocs = filteredDocs.filter(d => internalStates.includes(d.state) && isStalled(d));
        const stalledInternalIds = stalledInternalDocs.map(d => d.id);

        // Referent Stalled
        const referentStates = [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW];
        const stalledReferentDocs = filteredDocs.filter(d => referentStates.includes(d.state) && isStalled(d));
        const stalledReferentIds = stalledReferentDocs.map(d => d.id);

        // Control Stalled
        const controlStates = [DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW];
        const stalledControlDocs = filteredDocs.filter(d => controlStates.includes(d.state) && isStalled(d));
        const stalledControlIds = stalledControlDocs.map(d => d.id);

        return { 
            total, totalIds,
            approved: approvedDocs.length, approvedIds,
            stalledInternal: stalledInternalDocs.length, stalledInternalIds,
            stalledReferent: stalledReferentDocs.length, stalledReferentIds,
            stalledControl: stalledControlDocs.length, stalledControlIds
        };
    }, [filteredDocs]);

    // 2. CHART: State Distribution (Using Dashboard Criteria)
    const stateData = useMemo(() => {
        const counts: Record<string, number> = {};

        // Initialize with all Dashboard states for consistency
        Object.keys(STATE_CONFIG).forEach(key => {
            counts[STATE_CONFIG[key as DocState].label.split('(')[0]] = 0;
        });

        filteredDocs.forEach(d => {
            const label = STATE_CONFIG[d.state].label.split('(')[0];
            counts[label] = (counts[label] || 0) + 1;
        });

        // Filter out zero values to clean up chart, map colors from constants if possible or palette
        return Object.keys(counts)
            .filter(name => counts[name] > 0)
            .map((name, index) => ({ 
                name, 
                value: counts[name] 
            }));
    }, [filteredDocs]);

    // 3. CHART: Analyst Performance (Independent by State, Renamed)
    const analystData = useMemo(() => {
        const stats: Record<string, { assigned: number, approved: number, inProgress: number }> = {};

        filteredDocs.forEach(d => {
            if (d.assignees && d.assignees.length > 0) {
                d.assignees.forEach(uid => {
                    if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0, inProgress: 0 };

                    // "Asignados" refers to Total in Matrix for that user
                    stats[uid].assigned += 1;

                    if (d.state === DocState.APPROVED) {
                        stats[uid].approved += 1;
                    } else if (d.state !== DocState.NOT_STARTED) {
                        stats[uid].inProgress += 1; // Anything started but not approved
                    }
                });
            }
        });

        return Object.keys(stats)
            .map(uid => {
                const userObj = users.find(u => u.id === uid);
                return {
                    name: userObj ? (userObj.nickname || userObj.name.split(' ')[0]) : 'Desc.',
                    Asignados: stats[uid].assigned,
                    Completados: stats[uid].approved,
                    EnCurso: stats[uid].inProgress,
                };
            })
            .sort((a, b) => b.Asignados - a.Asignados)
            .slice(0, 10);
    }, [filteredDocs, users]);

    // 4. CHART: Compliance by Project (Required vs Finished)
    const projectData = useMemo(() => {
        const projStats: Record<string, { required: number, finished: number }> = {};

        const sourceDocs = filterProject ? filteredDocs : unifiedData;

        sourceDocs.forEach(d => {
            const p = d.project || 'Sin Proyecto';
            if (!projStats[p]) projStats[p] = { required: 0, finished: 0 };

            projStats[p].required += 1;
            if (d.state === DocState.APPROVED) {
                projStats[p].finished += 1;
            }
        });

        return Object.keys(projStats).map(p => ({
            name: p,
            Requeridos: projStats[p].required,
            Terminados: projStats[p].finished,
            Cumplimiento: Math.round((projStats[p].finished / projStats[p].required) * 100) || 0
        })).sort((a, b) => b.Cumplimiento - a.Cumplimiento);
    }, [unifiedData, filteredDocs, filterProject]);

    // 5. CHART: Monthly Activity
    const velocityData = useMemo(() => {
        const activityMap: Record<string, number> = {};
        const activeDocs = filteredDocs.filter(d => !d.isVirtual && d.state !== DocState.NOT_STARTED);

        activeDocs.forEach(d => {
            const date = new Date(d.updatedAt);
            const sortKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
            activityMap[sortKey] = (activityMap[sortKey] || 0) + 1;
        });

        const sortedKeys = Object.keys(activityMap).sort();
        const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];

        return sortedKeys.map(key => {
            const [year, month] = key.split('-');
            const monthIndex = parseInt(month, 10) - 1;
            return {
                name: `${months[monthIndex]}`,
                fullLabel: `${months[monthIndex]} ${year}`,
                actividad: activityMap[key]
            };
        });
    }, [filteredDocs]);

    const availableProjects = useMemo(() => Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))), [unifiedData]);

    // Navigation Handler to Dashboard with Filter Package
    const goToDashboard = (ids: string[]) => {
        // We pass the IDs to the Dashboard to filter specifically
        navigate('/', { state: { filterIds: ids, fromReport: true } });
    };

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Generando reporte...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" />
                        Reportes de Gestión
                    </h1>
                    <p className="text-slate-500">Métricas basadas en la Matriz de Asignaciones (Universo Total).</p>
                </div>

                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />

                    {/* Project Filter */}
                    <select 
                        value={filterProject} 
                        onChange={(e) => setFilterProject(e.target.value)}
                        className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px] border-r border-slate-100"
                    >
                        <option value="">Todos los Proyectos</option>
                        {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    {/* Analyst Filter */}
                    <div className="flex items-center gap-1 px-2">
                        <UserIcon size={14} className="text-slate-400" />
                        <select 
                            value={filterAnalyst} 
                            onChange={(e) => setFilterAnalyst(e.target.value)}
                            className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px]"
                        >
                            <option value="">Todos los Analistas</option>
                            {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                </div>
            </div>

            {/* ROW 1: KPI CARDS (Updated Structure) */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                <KPICard 
                    title="Total Requeridos" 
                    value={kpis.total} 
                    icon={FileText} color="indigo" sub="Universo Total" 
                    onClick={() => goToDashboard(kpis.totalIds)}
                    canClick={kpis.total > 0}
                />

                {/* Stall Group */}
                <KPICard 
                    title="Interno > 30d" 
                    value={kpis.stalledInternal} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledInternalIds)}
                    canClick={kpis.stalledInternal > 0}
                />
                <KPICard 
                    title="Referente > 30d" 
                    value={kpis.stalledReferent} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledReferentIds)}
                    canClick={kpis.stalledReferent > 0}
                />
                <KPICard 
                    title="Control > 30d" 
                    value={kpis.stalledControl} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledControlIds)}
                    canClick={kpis.stalledControl > 0}
                />

                <KPICard 
                    title="Terminados" 
                    value={kpis.approved} 
                    icon={CheckCircle} color="green" sub="100% Aprobados" 
                    onClick={() => goToDashboard(kpis.approvedIds)}
                    canClick={kpis.approved > 0}
                />
            </div>

            {/* ROW 2: MAIN CHARTS */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* 1. PERSPECTIVA INTERNA: ESTADO DE LOS DOCUMENTOS */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-1 flex flex-col">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Briefcase size={16} /> Estado del Universo
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Distribución detallada por estado actual.</p>

                    <div className="flex-1 min-h-[250px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={stateData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={60}
                                    outerRadius={80}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {stateData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                    ))}
                                </Pie>
                                <Tooltip />
                                <Legend verticalAlign="bottom" height={36}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 2. PERSPECTIVA APRENDIZAJE: DESEMPEÑO DEL EQUIPO (Modificado) */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Users size={16} /> Gestión por Analista
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Comparativa: Asignados (Matriz) vs. Terminados.</p>

                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                data={analystData}
                                margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <Tooltip 
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    cursor={{fill: '#f8fafc'}}
                                />
                                <Legend />
                                <Bar dataKey="Asignados" fill="#94a3b8" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="Completados" fill="#22c55e" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="EnCurso" name="En Gestión" fill="#60a5fa" radius={[4, 4, 0, 0]} barSize={20} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

            {/* ROW 3: TRENDS & RESULTS */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* 3. PERSPECTIVA RESULTADOS: CUMPLIMIENTO POR PROYECTO (Modificado) */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <TrendingUp size={16} /> Cumplimiento por Proyecto
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Total Requeridos vs. Documentos Terminados.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                layout="vertical"
                                data={projectData}
                                margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                                <XAxis type="number" hide />
                                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                                <Tooltip />
                                <Legend />
                                <Bar dataKey="Requeridos" fill="#94a3b8" radius={[0, 4, 4, 0]} barSize={15} />
                                <Bar dataKey="Terminados" fill="#22c55e" radius={[0, 4, 4, 0]} barSize={15} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 4. PERSPECTIVA CLIENTE: VELOCIDAD */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Clock size={16} /> Evolución Mensual
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Volumen de actividad (actualizaciones) ordenado cronológicamente.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <AreaChart
                                data={velocityData}
                                margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
                            >
                                <defs>
                                    <linearGradient id="colorAct" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#8884d8" stopOpacity={0.8}/>
                                        <stop offset="95%" stopColor="#8884d8" stopOpacity={0}/>
                                    </linearGradient>
                                </defs>
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <Tooltip labelFormatter={(label, payload) => payload[0]?.payload.fullLabel || label} />
                                <Area type="monotone" dataKey="actividad" stroke="#8884d8" fillOpacity={1} fill="url(#colorAct)" />
                            </AreaChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>
        </div>
    );
};

// --- SUBCOMPONENTS ---

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = {
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100',
        blue: 'bg-blue-50 text-blue-600 border-blue-100',
        green: 'bg-green-50 text-green-600 border-green-100',
        orange: 'bg-orange-50 text-orange-600 border-orange-100',
        red: 'bg-red-50 text-red-600 border-red-100',
    };

    return (
        <div 
            onClick={canClick ? onClick : undefined}
            className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} 
                ${canClick ? 'cursor-pointer hover:shadow-md hover:ring-2 hover:ring-opacity-50 hover:ring-indigo-300 transition-all active:scale-95' : ''}
            `}
        >
            <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span>
                <Icon size={18} />
            </div>
            <div>
                <span className="text-2xl font-bold">{value}</span>
                <div className="flex justify-between items-center mt-1">
                    <p className="text-[10px] opacity-80 font-medium">{sub}</p>
                    {canClick && <ArrowRight size={12} className="opacity-60" />}
                </div>
            </div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

// Extend Document interface locally to handle the "Required" flag for the Dashboard view
interface DashboardDoc extends Document {
    isRequired: boolean; // True if it matches the Matrix, False if it's an extra historical doc
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); // Used to receive filters from Reports

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterAnalyst, setFilterAnalyst] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); // Dropdown state filter

  // External Filter (From Reports)
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);

  // Quick Stats Filter (Cards)
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'updatedAt',
    direction: 'desc'
  });

  useEffect(() => {
    // Check for incoming report filters
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        // Clear quick filter to avoid conflict logic
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  // Helper to normalize strings for robust comparison
  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);

        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        // 1. Map Real Docs for fast lookup & Deduplication
        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                // Assuming format "Microprocess Name - Type" if microprocess field is empty
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;

                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                // Keep the most recent version if duplicates exist (by updatedAt)
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        // 2. Generate Virtual List based on Hierarchy Rules (THE SOURCE OF TRUTH)
        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true // <--- MARK AS REQUIRED (Matches Matrix)
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                // Create Virtual Placeholder
                                finalDocsList.push({
                                    id: `virtual-${key}`, // Needs to match ID generation in Reports for linking to work (or close enough)
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true // <--- MARK AS REQUIRED (Placeholder from Matrix)
                                });
                            }
                        });
                    });
                });
            });
        });

        // 3. Add Orphans (Documents that exist but match NO active matrix requirement)
        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false // <--- MARK AS NOT REQUIRED (Extra/Historic)
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  // --- 1. CONTEXT FILTERING (Dropdowns + External) ---
  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      // PRIORITY: If external filter exists (from Reports), use it exclusively first
      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          // Standard Filters
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);

          if (filterAnalyst) {
              filtered = filtered.filter(d => {
                  return d.assignees && d.assignees.includes(filterAnalyst);
              });
          }

          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
      }

      return filtered;
  }, [mergedDocs, filterProject, filterAnalyst, filterMacro, filterProcess, filterDocType, filterState, externalFilterIds]);

  // --- 2. STATS CALCULATION (ONLY COUNT REQUIRED DOCS) ---
  const stats = useMemo(() => {
      // Filter the context to only include REQUIRED documents for stats
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  // --- 3. TABLE FILTERING (Context + Quick Filter) ---
  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      // Apply Quick Filter (Cards) - Applies to ALL documents (Required + Orphans) visible in table
      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  // --- 4. SORTING ---
  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          // Priority Sort: Required first, then Orphans
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;
          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;
              case 'project': return (a.project || '').localeCompare(b.project || '') * modifier;
              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);


  const chartData = [
    { name: 'No Iniciado', value: stats.notStarted, color: '#e2e8f0' },
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control', value: stats.control, color: '#f97316' },
    { name: 'Finalizado', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  const handleQuickFilter = (type: QuickFilterType) => {
      setQuickFilter(quickFilter === type ? 'ALL' : type);
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterAnalyst('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterDocType('');
      setFilterState('');
      setQuickFilter('ALL');
      setExternalFilterIds(null); // Clear external filter
      // Clear location state
      navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => {
      const set = new Set(mergedDocs.map(d => d.project).filter(Boolean));
      return Array.from(set).sort();
  }, [mergedDocs]);

  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      const set = new Set(docs.map(d => d.macroprocess).filter(Boolean));
      return Array.from(set).sort();
  }, [mergedDocs, filterProject]);

  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      const set = new Set(docs.map(d => d.process).filter(Boolean));
      return Array.from(set).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => {
      const u = allUsers.find(user => user.id === id);
      return u ? u.name : 'Sin Asignar';
  };

  const isAssignedToMe = (doc: DashboardDoc) => {
      return doc.assignees && doc.assignees.includes(user.id);
  };

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6">
                  <Database size={40} className="text-indigo-600" />
              </div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">
                  La matriz de procesos está vacía. Para visualizar el avance, es necesario cargar la estructura de procesos inicial.
              </p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? (
                  <Link 
                    to="/admin/assignments" 
                    className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95"
                  >
                      <Database size={18} className="mr-2" />
                      Ir a Carga de Datos
                  </Link>
              ) : (
                  <div className="flex items-center gap-2 text-amber-600 bg-amber-50 px-4 py-2 rounded-lg border border-amber-100">
                      <AlertTriangle size={18} />
                      <span>Contacte al administrador para inicializar el sistema.</span>
                  </div>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterAnalyst || filterMacro || filterProcess || filterDocType || filterState || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general</p></div>
        {user.role === UserRole.ANALYST && <Link to="/new" className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
      </div>

      {/* STATS CARDS */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600 border-slate-200" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600 border-slate-200" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600 border-blue-100" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600 border-purple-100" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600 border-orange-100" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600 border-green-100" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* MAIN TABLE */}
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">

            {/* FILTER BAR */}
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm">
                        <Filter size={16} /> Filtros de Visualización
                    </div>
                    {hasActiveFilters && (
                        <button 
                            onClick={clearFilters}
                            className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium transition-colors"
                        >
                            <X size={14} /> Limpiar filtros
                        </button>
                    )}
                </div>

                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">
                            Filtro Activo desde Reportes: Visualizando {externalFilterIds.length} documentos específicos.
                        </span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600 hover:bg-blue-50">
                            Mostrar Todo
                        </button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-3">
                        <select value={filterProject} onChange={(e) => { setFilterProject(e.target.value); setFilterMacro(''); setFilterProcess(''); }} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-32">
                            <option value="">Proyecto (Todos)</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>

                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-36">
                            <option value="">Analista (Todos)</option>
                            {allUsers.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>

                        <select value={filterMacro} onChange={(e) => { setFilterMacro(e.target.value); setFilterProcess(''); }} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Macro (Todos)</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>

                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Proceso (Todos)</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>

                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-32">
                            <option value="">Doc (Todos)</option>
                            {['AS IS', 'FCE', 'PM', 'TO BE'].map(t => <option key={t} value={t}>{t}</option>)}
                        </select>

                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-36">
                            <option value="">Estado (Todos)</option>
                            {Object.keys(STATE_CONFIG).map(k => <option key={k} value={k}>{STATE_CONFIG[k as DocState].label.split('(')[0]}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-xs text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO</th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO</th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL</th>
                            <th className="px-4 py-3 cursor-pointer group text-right" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {sortedDocs.length === 0 ? <tr><td colSpan={6} className="p-8 text-center text-slate-400">Sin resultados.</td></tr> : sortedDocs.map((doc, idx) => (
                            <tr 
                                key={`${doc.id}-${idx}`} 
                                className={`transition-colors ${
                                    !doc.isRequired 
                                        ? 'bg-gray-100 hover:bg-gray-200' // <--- VISUALIZACIÓN GRIS PARA DOCUMENTOS "EXTRA"
                                        : 'hover:bg-slate-50'
                                }`}
                            >
                                {/* PROYECTO */}
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>

                                {/* JERARQUÍA */}
                                <td className={`px-4 py-3 align-top ${!doc.isRequired ? 'text-gray-400' : ''}`}>
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className={`${!doc.isRequired ? 'text-gray-400' : 'text-slate-500'}`}>{doc.process}</div>
                                </td>

                                {/* MICROPROCESO & ANALISTA */}
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>
                                        {doc.microprocess}
                                        {!doc.isRequired && <span className="ml-2 text-[9px] uppercase bg-gray-200 text-gray-500 px-1 rounded">No Requerido</span>}
                                    </div>
                                    <div className={`flex items-center gap-1 ${!doc.isRequired ? 'text-gray-400' : 'text-slate-500'}`} title="Analista Asignado">
                                        <UserIcon size={10} />
                                        <span className={`text-[10px] font-medium ${!doc.isRequired ? 'text-gray-500' : 'text-indigo-600'}`}>
                                            {doc.assignees && doc.assignees.length > 0 
                                                ? getUserName(doc.assignees[0]) 
                                                : 'Sin Asignar'}
                                        </span>
                                    </div>
                                </td>

                                {/* DOCUMENTO (TYPE & LINK) */}
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${
                                        !doc.isRequired 
                                            ? 'bg-gray-200 text-gray-500 border-gray-300' 
                                            : 'bg-indigo-50 text-indigo-700 border-indigo-100'
                                    }`}>
                                        {doc.docType}
                                    </span>
                                    {/* LINK UNIFICADO "VER DETALLE" */}
                                    <Link 
                                        to={`/doc/${doc.id}`} 
                                        state={{ docData: doc }} // Pasamos el doc en state para manejar virtuales
                                        className={`flex items-center gap-1 text-[10px] font-bold ${!doc.isRequired ? 'text-gray-500 hover:text-gray-700' : 'text-indigo-500 hover:text-indigo-700'}`}
                                    >
                                        Ver Detalle <ArrowRight size={10}/>
                                    </Link>
                                </td>

                                {/* ESTADO ACTUAL */}
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${
                                        !doc.isRequired 
                                            ? 'bg-gray-200 text-gray-500 border-gray-300' 
                                            : STATE_CONFIG[doc.state].color
                                    }`}>
                                        {STATE_CONFIG[doc.state].label.split('(')[0]}
                                    </div>
                                    <div className={`text-[10px] font-mono ${!doc.isRequired ? 'text-gray-400' : 'text-slate-500'}`}>
                                        Ver: {doc.version} ({doc.progress}%)
                                    </div>
                                </td>

                                {/* ÚLTIMA ACTIVIDAD */}
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="flex flex-col items-end">
                                            <div className={`flex items-center gap-1 font-medium ${!doc.isRequired ? 'text-gray-500' : 'text-slate-600'}`}>
                                                <Calendar size={10} />
                                                {new Date(doc.updatedAt).toLocaleDateString()}
                                            </div>
                                            <span className="text-[10px] text-slate-400">
                                                {new Date(doc.updatedAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                            </span>
                                        </div>
                                    ) : (
                                        <span className="text-slate-300 text-[10px]">-</span>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>

        {/* RIGHT COLUMN: CHART & SUMMARY */}
        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-sm">Estado (Requeridos)</h3>
                {chartData.length > 0 ? (
                    <div className="h-48 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie 
                                    data={chartData} 
                                    cx="50%" cy="50%" 
                                    innerRadius={50} outerRadius={70} 
                                    paddingAngle={2} 
                                    dataKey="value"
                                >
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '12px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-xs">Sin datos requeridos.</p>}

                <div className="flex flex-wrap justify-center gap-2 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span>
                            <span className="text-[10px] text-slate-500">{d.name}</span>
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-sm mb-3">Resumen de Cumplimiento</h3>
                <p className="text-xs text-indigo-700 mb-3">
                    Visualizando {contextDocs.length} filas totales.<br/>
                    <strong>{stats.total} documentos requeridos.</strong>
                </p>
                <ul className="space-y-2 text-xs">
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-slate-600">
                        <span>No Iniciados:</span> <span>{stats.notStarted}</span>
                    </li>
                    <li className="flex justify-between text-blue-600 font-medium">
                        <span>En Proceso:</span> <span>{stats.inProcess}</span>
                    </li>
                    <li className="flex justify-between text-purple-600 font-medium">
                        <span>Referente:</span> <span>{stats.referent}</span>
                    </li>
                    <li className="flex justify-between text-orange-600 font-medium">
                        <span>Control Gestión:</span> <span>{stats.control}</span>
                    </li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold">
                        <span>Terminados:</span> <span>{stats.finished}</span>
                    </li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[10px] text-slate-500 flex items-center gap-2">
                    <Archive size={12} />
                    <span>Los registros en <span className="font-bold text-gray-500">GRIS</span> son históricos/extra y no suman al cumplimiento.</span>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-200 scale-105' : 'hover:border-indigo-300'} ${color}`}>
        <div className="p-1.5 bg-white/50 rounded-lg"><Icon size={18}/></div>
        <div>
            <p className="text-[9px] uppercase font-bold opacity-70">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area 
} from 'recharts';
import { 
    TrendingUp, Users, AlertTriangle, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, User as UserIcon, ArrowRight
} from 'lucide-react';

interface Props {
    user: User;
}

// Extends Document to handle "Virtual" documents (not yet created but required)
interface ReportDoc extends Document {
    isVirtual?: boolean;
    requiredType?: string;
}

// Color Map matching Dashboard
const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#e2e8f0', // Slate 200
    'En Proceso': '#3b82f6',  // Blue 500
    'En Revisión': '#a855f7', // Purple 500 (Mix of Referente/Control)
    'Rechazado': '#ef4444',   // Red 500
    'Aprobado': '#22c55e'     // Green 500
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    // --- DATA PROCESSING (Link Matriz vs Realidad) ---

    // Genera el universo completo de documentos (Real + Virtual) basado en la Matriz
    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];

        const unifiedList: ReportDoc[] = [];

        // 1. Indexar documentos reales para búsqueda rápida
        const realDocMap = new Map<string, Document>();
        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                // Keep most recent
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        // 2. Recorrer la Jerarquía (Lo que DEBE existir)
        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    const nodes = hierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        // Skip inactive nodes in hierarchy for reporting
                        if (node.active === false) return;

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                            if (realDocMap.has(key)) {
                                // Existe documento real
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    // Ensure assignees are synced with matrix if doc is old
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false
                                });
                            } else {
                                // No existe -> Documento Virtual "No Iniciado"
                                unifiedList.push({
                                    id: `virtual-${key}`, // Special ID for virtual docs
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [], // Here we link analysts from Assignments Matrix
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(),
                                    hasPendingRequest: false,
                                    isVirtual: true,
                                    requiredType: type
                                });
                            }
                        });
                    });
                });
            });
        });

        return unifiedList;
    }, [realDocs, hierarchy]);


    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);


    // 1. KPI CARDS DATA (Updated Structure)
    const kpis = useMemo(() => {
        const total = filteredDocs.length;
        const totalIds = filteredDocs.map(d => d.id);

        const approvedDocs = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const approvedIds = approvedDocs.map(d => d.id);

        // Calculate 30 days threshold
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

        // Helper to check stall
        const isStalled = (d: ReportDoc) => {
            if (d.isVirtual || d.state === DocState.NOT_STARTED) return false;
            return new Date(d.updatedAt) < thirtyDaysAgo;
        };

        // Internal Stalled (Initiated, In Process, Internal Review)
        const internalStates = [DocState.INITIATED, DocState.IN_PROCESS, DocState.INTERNAL_REVIEW];
        const stalledInternalDocs = filteredDocs.filter(d => internalStates.includes(d.state) && isStalled(d));
        const stalledInternalIds = stalledInternalDocs.map(d => d.id);

        // Referent Stalled
        const referentStates = [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW];
        const stalledReferentDocs = filteredDocs.filter(d => referentStates.includes(d.state) && isStalled(d));
        const stalledReferentIds = stalledReferentDocs.map(d => d.id);

        // Control Stalled
        const controlStates = [DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW];
        const stalledControlDocs = filteredDocs.filter(d => controlStates.includes(d.state) && isStalled(d));
        const stalledControlIds = stalledControlDocs.map(d => d.id);

        return { 
            total, totalIds,
            approved: approvedDocs.length, approvedIds,
            stalledInternal: stalledInternalDocs.length, stalledInternalIds,
            stalledReferent: stalledReferentDocs.length, stalledReferentIds,
            stalledControl: stalledControlDocs.length, stalledControlIds
        };
    }, [filteredDocs]);

    // 2. CHART: State Distribution (Using Dashboard Criteria Colors)
    const stateData = useMemo(() => {
        const counts: Record<string, number> = {};

        // Initialize specific keys order
        counts['No Iniciado'] = 0;
        counts['En Proceso'] = 0;
        counts['En Revisión'] = 0;
        counts['Rechazado'] = 0;
        counts['Aprobado'] = 0;

        filteredDocs.forEach(d => {
            let key = 'En Proceso';
            if (d.state === DocState.NOT_STARTED) key = 'No Iniciado';
            else if (d.state === DocState.APPROVED) key = 'Aprobado';
            else if (d.state === DocState.REJECTED) key = 'Rechazado';
            else if (d.state === DocState.INTERNAL_REVIEW || d.state === DocState.SENT_TO_REFERENT || d.state === DocState.SENT_TO_CONTROL || d.state === DocState.REFERENT_REVIEW || d.state === DocState.CONTROL_REVIEW) key = 'En Revisión';

            counts[key] = (counts[key] || 0) + 1;
        });

        return Object.keys(counts).filter(k => counts[k] > 0).map(name => ({ name, value: counts[name] }));
    }, [filteredDocs]);

    // 3. CHART: Analyst Performance (Independent by State, Renamed)
    const analystData = useMemo(() => {
        const stats: Record<string, { assigned: number, approved: number, inProgress: number }> = {};

        filteredDocs.forEach(d => {
            if (d.assignees && d.assignees.length > 0) {
                d.assignees.forEach(uid => {
                    if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0, inProgress: 0 };

                    // "Asignados" refers to Total in Matrix for that user
                    stats[uid].assigned += 1;

                    if (d.state === DocState.APPROVED) {
                        stats[uid].approved += 1;
                    } else if (d.state !== DocState.NOT_STARTED) {
                        stats[uid].inProgress += 1; // Anything started but not approved
                    }
                });
            }
        });

        return Object.keys(stats)
            .map(uid => {
                const userObj = users.find(u => u.id === uid);
                return {
                    name: userObj ? (userObj.nickname || userObj.name.split(' ')[0]) : 'Desc.',
                    Asignados: stats[uid].assigned,
                    Terminados: stats[uid].approved,
                    EnGestion: stats[uid].inProgress,
                };
            })
            .sort((a, b) => b.Asignados - a.Asignados)
            .slice(0, 10);
    }, [filteredDocs, users]);

    // 4. CHART: Compliance by Project (Required vs Finished)
    const projectData = useMemo(() => {
        const projStats: Record<string, { required: number, finished: number }> = {};

        const sourceDocs = filterProject ? filteredDocs : unifiedData;

        sourceDocs.forEach(d => {
            const p = d.project || 'Sin Proyecto';
            if (!projStats[p]) projStats[p] = { required: 0, finished: 0 };

            projStats[p].required += 1;
            if (d.state === DocState.APPROVED) {
                projStats[p].finished += 1;
            }
        });

        return Object.keys(projStats).map(p => ({
            name: p,
            Requeridos: projStats[p].required,
            Terminados: projStats[p].finished,
            Cumplimiento: Math.round((projStats[p].finished / projStats[p].required) * 100) || 0
        })).sort((a, b) => b.Cumplimiento - a.Cumplimiento);
    }, [unifiedData, filteredDocs, filterProject]);

    // 5. CHART: Monthly Activity
    const velocityData = useMemo(() => {
        const activityMap: Record<string, number> = {};
        const activeDocs = filteredDocs.filter(d => !d.isVirtual && d.state !== DocState.NOT_STARTED);

        activeDocs.forEach(d => {
            const date = new Date(d.updatedAt);
            const sortKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
            activityMap[sortKey] = (activityMap[sortKey] || 0) + 1;
        });

        const sortedKeys = Object.keys(activityMap).sort();
        const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];

        return sortedKeys.map(key => {
            const [year, month] = key.split('-');
            const monthIndex = parseInt(month, 10) - 1;
            return {
                name: `${months[monthIndex]}`,
                fullLabel: `${months[monthIndex]} ${year}`,
                actividad: activityMap[key]
            };
        });
    }, [filteredDocs]);

    const availableProjects = useMemo(() => Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))), [unifiedData]);

    // Navigation Handler to Dashboard with Filter Package
    const goToDashboard = (ids: string[]) => {
        // We pass the IDs to the Dashboard to filter specifically
        navigate('/', { state: { filterIds: ids, fromReport: true } });
    };

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Generando reporte...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" />
                        Reportes de Gestión
                    </h1>
                    <p className="text-slate-500">Métricas basadas en la Matriz de Asignaciones (Universo Total).</p>
                </div>

                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />

                    {/* Project Filter */}
                    <select 
                        value={filterProject} 
                        onChange={(e) => setFilterProject(e.target.value)}
                        className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px] border-r border-slate-100"
                    >
                        <option value="">Todos los Proyectos</option>
                        {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    {/* Analyst Filter */}
                    <div className="flex items-center gap-1 px-2">
                        <UserIcon size={14} className="text-slate-400" />
                        <select 
                            value={filterAnalyst} 
                            onChange={(e) => setFilterAnalyst(e.target.value)}
                            className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px]"
                        >
                            <option value="">Todos los Analistas</option>
                            {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                </div>
            </div>

            {/* ROW 1: KPI CARDS (Updated Structure) */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                <KPICard 
                    title="Total Requeridos" 
                    value={kpis.total} 
                    icon={FileText} color="indigo" sub="Universo Total" 
                    onClick={() => goToDashboard(kpis.totalIds)}
                    canClick={kpis.total > 0}
                />

                {/* Stall Group */}
                <KPICard 
                    title="Interno > 30d" 
                    value={kpis.stalledInternal} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledInternalIds)}
                    canClick={kpis.stalledInternal > 0}
                />
                <KPICard 
                    title="Referente > 30d" 
                    value={kpis.stalledReferent} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledReferentIds)}
                    canClick={kpis.stalledReferent > 0}
                />
                <KPICard 
                    title="Control > 30d" 
                    value={kpis.stalledControl} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledControlIds)}
                    canClick={kpis.stalledControl > 0}
                />

                <KPICard 
                    title="Terminados" 
                    value={kpis.approved} 
                    icon={CheckCircle} color="green" sub="100% Aprobados" 
                    onClick={() => goToDashboard(kpis.approvedIds)}
                    canClick={kpis.approved > 0}
                />
            </div>

            {/* ROW 2: MAIN CHARTS */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* 1. PERSPECTIVA INTERNA: ESTADO DE LOS DOCUMENTOS */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-1 flex flex-col">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Briefcase size={16} /> Estado del Universo
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Distribución detallada por estado actual.</p>

                    <div className="flex-1 min-h-[250px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={stateData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={60}
                                    outerRadius={80}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {stateData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} />
                                    ))}
                                </Pie>
                                <Tooltip />
                                <Legend verticalAlign="bottom" height={36}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 2. PERSPECTIVA APRENDIZAJE: DESEMPEÑO DEL EQUIPO (Modificado) */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Users size={16} /> Gestión por Analista
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Comparativa: Asignados vs. Gestión vs. Terminados.</p>

                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                data={analystData}
                                margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <Tooltip 
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    cursor={{fill: '#f8fafc'}}
                                />
                                <Legend />
                                <Bar dataKey="Asignados" fill="#94a3b8" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="EnGestion" name="En Gestión" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="Terminados" fill="#22c55e" radius={[4, 4, 0, 0]} barSize={20} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

            {/* ROW 3: TRENDS & RESULTS */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* 3. PERSPECTIVA RESULTADOS: CUMPLIMIENTO POR PROYECTO (Modificado) */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <TrendingUp size={16} /> Cumplimiento por Proyecto
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Total Requeridos vs. Documentos Terminados.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                layout="vertical"
                                data={projectData}
                                margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                                <XAxis type="number" hide />
                                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                                <Tooltip />
                                <Legend />
                                <Bar dataKey="Requeridos" fill="#94a3b8" radius={[0, 4, 4, 0]} barSize={15} />
                                <Bar dataKey="Terminados" fill="#22c55e" radius={[0, 4, 4, 0]} barSize={15} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 4. PERSPECTIVA CLIENTE: VELOCIDAD */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Clock size={16} /> Evolución Mensual
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Volumen de actividad (actualizaciones) ordenado cronológicamente.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <AreaChart
                                data={velocityData}
                                margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
                            >
                                <defs>
                                    <linearGradient id="colorAct" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#8884d8" stopOpacity={0.8}/>
                                        <stop offset="95%" stopColor="#8884d8" stopOpacity={0}/>
                                    </linearGradient>
                                </defs>
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <Tooltip labelFormatter={(label, payload) => payload[0]?.payload.fullLabel || label} />
                                <Area type="monotone" dataKey="actividad" stroke="#8884d8" fillOpacity={1} fill="url(#colorAct)" />
                            </AreaChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>
        </div>
    );
};

// --- SUBCOMPONENTS ---

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = {
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100',
        blue: 'bg-blue-50 text-blue-600 border-blue-100',
        green: 'bg-green-50 text-green-600 border-green-100',
        orange: 'bg-orange-50 text-orange-600 border-orange-100',
        red: 'bg-red-50 text-red-600 border-red-100',
    };

    return (
        <div 
            onClick={canClick ? onClick : undefined}
            className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} 
                ${canClick ? 'cursor-pointer hover:shadow-md hover:ring-2 hover:ring-opacity-50 hover:ring-indigo-300 transition-all active:scale-95' : ''}
            `}
        >
            <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span>
                <Icon size={18} />
            </div>
            <div>
                <span className="text-2xl font-bold">{value}</span>
                <div className="flex justify-between items-center mt-1">
                    <p className="text-[10px] opacity-80 font-medium">{sub}</p>
                    {canClick && <ArrowRight size={12} className="opacity-60" />}
                </div>
            </div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area 
} from 'recharts';
import { 
    TrendingUp, Users, AlertTriangle, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, User as UserIcon, ArrowRight
} from 'lucide-react';

interface Props {
    user: User;
}

// Extends Document to handle "Virtual" documents (not yet created but required)
interface ReportDoc extends Document {
    isVirtual?: boolean;
    requiredType?: string;
}

// Color Map matching Dashboard
const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#e2e8f0', // Slate 200
    'En Proceso': '#3b82f6',  // Blue 500
    'En Revisión': '#a855f7', // Purple 500 (Mix of Referente/Control)
    'Rechazado': '#ef4444',   // Red 500
    'Aprobado': '#22c55e'     // Green 500
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState('');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    // --- DATA PROCESSING (Link Matriz vs Realidad) ---

    // Genera el universo completo de documentos (Real + Virtual) basado en la Matriz
    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];

        const unifiedList: ReportDoc[] = [];

        // 1. Indexar documentos reales para búsqueda rápida
        const realDocMap = new Map<string, Document>();
        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                // Keep most recent
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        // 2. Recorrer la Jerarquía (Lo que DEBE existir)
        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    const nodes = hierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        // Skip inactive nodes in hierarchy for reporting
                        if (node.active === false) return;

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                            if (realDocMap.has(key)) {
                                // Existe documento real
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    // Ensure assignees are synced with matrix if doc is old
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false
                                });
                            } else {
                                // No existe -> Documento Virtual "No Iniciado"
                                unifiedList.push({
                                    id: `virtual-${key}`, // Special ID for virtual docs
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [], // Here we link analysts from Assignments Matrix
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(),
                                    hasPendingRequest: false,
                                    isVirtual: true,
                                    requiredType: type
                                });
                            }
                        });
                    });
                });
            });
        });

        return unifiedList;
    }, [realDocs, hierarchy]);


    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);


    // 1. KPI CARDS DATA (Updated Structure)
    const kpis = useMemo(() => {
        const total = filteredDocs.length;
        const totalIds = filteredDocs.map(d => d.id);

        const approvedDocs = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const approvedIds = approvedDocs.map(d => d.id);

        // Calculate 30 days threshold
        const thirtyDaysAgo = new Date();
        thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

        // Helper to check stall
        const isStalled = (d: ReportDoc) => {
            if (d.isVirtual || d.state === DocState.NOT_STARTED) return false;
            return new Date(d.updatedAt) < thirtyDaysAgo;
        };

        // Internal Stalled (Initiated, In Process, Internal Review)
        const internalStates = [DocState.INITIATED, DocState.IN_PROCESS, DocState.INTERNAL_REVIEW];
        const stalledInternalDocs = filteredDocs.filter(d => internalStates.includes(d.state) && isStalled(d));
        const stalledInternalIds = stalledInternalDocs.map(d => d.id);

        // Referent Stalled
        const referentStates = [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW];
        const stalledReferentDocs = filteredDocs.filter(d => referentStates.includes(d.state) && isStalled(d));
        const stalledReferentIds = stalledReferentDocs.map(d => d.id);

        // Control Stalled
        const controlStates = [DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW];
        const stalledControlDocs = filteredDocs.filter(d => controlStates.includes(d.state) && isStalled(d));
        const stalledControlIds = stalledControlDocs.map(d => d.id);

        return { 
            total, totalIds,
            approved: approvedDocs.length, approvedIds,
            stalledInternal: stalledInternalDocs.length, stalledInternalIds,
            stalledReferent: stalledReferentDocs.length, stalledReferentIds,
            stalledControl: stalledControlDocs.length, stalledControlIds
        };
    }, [filteredDocs]);

    // 2. CHART: State Distribution (Using Dashboard Criteria Colors)
    const stateData = useMemo(() => {
        const counts: Record<string, number> = {};

        // Initialize specific keys order
        counts['No Iniciado'] = 0;
        counts['En Proceso'] = 0;
        counts['En Revisión'] = 0;
        counts['Rechazado'] = 0;
        counts['Aprobado'] = 0;

        filteredDocs.forEach(d => {
            let key = 'En Proceso';
            if (d.state === DocState.NOT_STARTED) key = 'No Iniciado';
            else if (d.state === DocState.APPROVED) key = 'Aprobado';
            else if (d.state === DocState.REJECTED) key = 'Rechazado';
            else if (d.state === DocState.INTERNAL_REVIEW || d.state === DocState.SENT_TO_REFERENT || d.state === DocState.SENT_TO_CONTROL || d.state === DocState.REFERENT_REVIEW || d.state === DocState.CONTROL_REVIEW) key = 'En Revisión';

            counts[key] = (counts[key] || 0) + 1;
        });

        return Object.keys(counts).filter(k => counts[k] > 0).map(name => ({ name, value: counts[name] }));
    }, [filteredDocs]);

    // 3. CHART: Analyst Performance (Independent by State, Renamed)
    const analystData = useMemo(() => {
        const stats: Record<string, { assigned: number, approved: number, inProgress: number }> = {};

        filteredDocs.forEach(d => {
            if (d.assignees && d.assignees.length > 0) {
                d.assignees.forEach(uid => {
                    if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0, inProgress: 0 };

                    // "Asignados" refers to Total in Matrix for that user
                    stats[uid].assigned += 1;

                    if (d.state === DocState.APPROVED) {
                        stats[uid].approved += 1;
                    } else if (d.state !== DocState.NOT_STARTED) {
                        stats[uid].inProgress += 1; // Anything started but not approved
                    }
                });
            }
        });

        return Object.keys(stats)
            .map(uid => {
                const userObj = users.find(u => u.id === uid);
                return {
                    name: userObj ? (userObj.nickname || userObj.name.split(' ')[0]) : 'Desc.',
                    Asignados: stats[uid].assigned,
                    Terminados: stats[uid].approved,
                    EnGestion: stats[uid].inProgress,
                };
            })
            .sort((a, b) => b.Asignados - a.Asignados)
            .slice(0, 10);
    }, [filteredDocs, users]);

    // 4. CHART: Compliance by Project (Required vs Finished)
    const projectData = useMemo(() => {
        const projStats: Record<string, { required: number, finished: number }> = {};

        const sourceDocs = filterProject ? filteredDocs : unifiedData;

        sourceDocs.forEach(d => {
            const p = d.project || 'Sin Proyecto';
            if (!projStats[p]) projStats[p] = { required: 0, finished: 0 };

            projStats[p].required += 1;
            if (d.state === DocState.APPROVED) {
                projStats[p].finished += 1;
            }
        });

        return Object.keys(projStats).map(p => ({
            name: p,
            Requeridos: projStats[p].required,
            Terminados: projStats[p].finished,
            Cumplimiento: Math.round((projStats[p].finished / projStats[p].required) * 100) || 0
        })).sort((a, b) => b.Cumplimiento - a.Cumplimiento);
    }, [unifiedData, filteredDocs, filterProject]);

    // 5. CHART: Monthly Activity
    const velocityData = useMemo(() => {
        const activityMap: Record<string, number> = {};
        const activeDocs = filteredDocs.filter(d => !d.isVirtual && d.state !== DocState.NOT_STARTED);

        activeDocs.forEach(d => {
            const date = new Date(d.updatedAt);
            const sortKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
            activityMap[sortKey] = (activityMap[sortKey] || 0) + 1;
        });

        const sortedKeys = Object.keys(activityMap).sort();
        const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];

        return sortedKeys.map(key => {
            const [year, month] = key.split('-');
            const monthIndex = parseInt(month, 10) - 1;
            return {
                name: `${months[monthIndex]}`,
                fullLabel: `${months[monthIndex]} ${year}`,
                actividad: activityMap[key]
            };
        });
    }, [filteredDocs]);

    const availableProjects = useMemo(() => Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))), [unifiedData]);

    // Navigation Handler to Dashboard with Filter Package
    const goToDashboard = (ids: string[]) => {
        // We pass the IDs to the Dashboard to filter specifically
        navigate('/', { state: { filterIds: ids, fromReport: true } });
    };

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Generando reporte...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" />
                        Reportes de Gestión
                    </h1>
                    <p className="text-slate-500">Métricas basadas en la Matriz de Asignaciones (Universo Total).</p>
                </div>

                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />

                    {/* Project Filter */}
                    <select 
                        value={filterProject} 
                        onChange={(e) => setFilterProject(e.target.value)}
                        className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px] border-r border-slate-100"
                    >
                        <option value="">Todos los Proyectos</option>
                        {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    {/* Analyst Filter */}
                    <div className="flex items-center gap-1 px-2">
                        <UserIcon size={14} className="text-slate-400" />
                        <select 
                            value={filterAnalyst} 
                            onChange={(e) => setFilterAnalyst(e.target.value)}
                            className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 cursor-pointer min-w-[150px]"
                        >
                            <option value="">Todos los Analistas</option>
                            {users
                                .filter(u => u.role === UserRole.ANALYST) // Filter strictly by Role
                                .map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    </div>
                </div>
            </div>

            {/* ROW 1: KPI CARDS (Updated Structure) */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                <KPICard 
                    title="Total Requeridos" 
                    value={kpis.total} 
                    icon={FileText} color="indigo" sub="Universo Total" 
                    onClick={() => goToDashboard(kpis.totalIds)}
                    canClick={kpis.total > 0}
                />

                {/* Stall Group */}
                <KPICard 
                    title="Interno > 30d" 
                    value={kpis.stalledInternal} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledInternalIds)}
                    canClick={kpis.stalledInternal > 0}
                />
                <KPICard 
                    title="Referente > 30d" 
                    value={kpis.stalledReferent} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledReferentIds)}
                    canClick={kpis.stalledReferent > 0}
                />
                <KPICard 
                    title="Control > 30d" 
                    value={kpis.stalledControl} 
                    icon={Clock} color="orange" sub="Sin avance reciente" 
                    onClick={() => goToDashboard(kpis.stalledControlIds)}
                    canClick={kpis.stalledControl > 0}
                />

                <KPICard 
                    title="Terminados" 
                    value={kpis.approved} 
                    icon={CheckCircle} color="green" sub="100% Aprobados" 
                    onClick={() => goToDashboard(kpis.approvedIds)}
                    canClick={kpis.approved > 0}
                />
            </div>

            {/* ROW 2: MAIN CHARTS */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* 1. PERSPECTIVA INTERNA: ESTADO DE LOS DOCUMENTOS */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-1 flex flex-col">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Briefcase size={16} /> Estado del Universo
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Distribución detallada por estado actual.</p>

                    <div className="flex-1 min-h-[250px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={stateData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={60}
                                    outerRadius={80}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {stateData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} />
                                    ))}
                                </Pie>
                                <Tooltip />
                                <Legend verticalAlign="bottom" height={36}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 2. PERSPECTIVA APRENDIZAJE: DESEMPEÑO DEL EQUIPO (Modificado) */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Users size={16} /> Gestión por Analista
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Comparativa: Asignados vs. Gestión vs. Terminados.</p>

                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                data={analystData}
                                margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <Tooltip 
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    cursor={{fill: '#f8fafc'}}
                                />
                                <Legend />
                                <Bar dataKey="Asignados" fill="#94a3b8" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="EnGestion" name="En Gestión" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={20} />
                                <Bar dataKey="Terminados" fill="#22c55e" radius={[4, 4, 0, 0]} barSize={20} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

            {/* ROW 3: TRENDS & RESULTS */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* 3. PERSPECTIVA RESULTADOS: CUMPLIMIENTO POR PROYECTO (Modificado) */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <TrendingUp size={16} /> Cumplimiento por Proyecto
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Total Requeridos vs. Documentos Terminados.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                layout="vertical"
                                data={projectData}
                                margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                                <XAxis type="number" hide />
                                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                                <Tooltip />
                                <Legend />
                                <Bar dataKey="Requeridos" fill="#94a3b8" radius={[0, 4, 4, 0]} barSize={15} />
                                <Bar dataKey="Terminados" fill="#22c55e" radius={[0, 4, 4, 0]} barSize={15} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* 4. PERSPECTIVA CLIENTE: VELOCIDAD */}
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-sm font-bold text-slate-700 uppercase mb-1 flex items-center gap-2">
                        <Clock size={16} /> Evolución Mensual
                    </h3>
                    <p className="text-xs text-slate-500 mb-6">Volumen de actividad (actualizaciones) ordenado cronológicamente.</p>

                    <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <AreaChart
                                data={velocityData}
                                margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
                            >
                                <defs>
                                    <linearGradient id="colorAct" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#8884d8" stopOpacity={0.8}/>
                                        <stop offset="95%" stopColor="#8884d8" stopOpacity={0}/>
                                    </linearGradient>
                                </defs>
                                <XAxis dataKey="name" tick={{fontSize: 12}} />
                                <YAxis tick={{fontSize: 12}} />
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                <Tooltip labelFormatter={(label, payload) => payload[0]?.payload.fullLabel || label} />
                                <Area type="monotone" dataKey="actividad" stroke="#8884d8" fillOpacity={1} fill="url(#colorAct)" />
                            </AreaChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>
        </div>
    );
};

// --- SUBCOMPONENTS ---

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = {
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100',
        blue: 'bg-blue-50 text-blue-600 border-blue-100',
        green: 'bg-green-50 text-green-600 border-green-100',
        orange: 'bg-orange-50 text-orange-600 border-orange-100',
        red: 'bg-red-50 text-red-600 border-red-100',
    };

    return (
        <div 
            onClick={canClick ? onClick : undefined}
            className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} 
                ${canClick ? 'cursor-pointer hover:shadow-md hover:ring-2 hover:ring-opacity-50 hover:ring-indigo-300 transition-all active:scale-95' : ''}
            `}
        >
            <div className="flex justify-between items-start mb-2">
                <span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span>
                <Icon size={18} />
            </div>
            <div>
                <span className="text-2xl font-bold">{value}</span>
                <div className="flex justify-between items-center mt-1">
                    <p className="text-[10px] opacity-80 font-medium">{sub}</p>
                    {canClick && <ArrowRight size={12} className="opacity-60" />}
                </div>
            </div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Calendar, ArrowRight, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, AlertTriangle, Archive, PlayCircle
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

// Extend Document interface locally to handle the "Required" flag for the Dashboard view
interface DashboardDoc extends Document {
    isRequired: boolean; // True if it matches the Matrix, False if it's an extra historical doc
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); // Used to receive filters from Reports

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterAnalyst, setFilterAnalyst] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); // Dropdown state filter

  // External Filter (From Reports)
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);

  // Quick Stats Filter (Cards)
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'updatedAt',
    direction: 'desc'
  });

  useEffect(() => {
    // Check for incoming report filters
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        // Clear quick filter to avoid conflict logic
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  // Helper to normalize strings for robust comparison
  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);

        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        // 1. Map Real Docs for fast lookup & Deduplication
        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                // Assuming format "Microprocess Name - Type" if microprocess field is empty
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;

                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                // Keep the most recent version if duplicates exist (by updatedAt)
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        // 2. Generate Virtual List based on Hierarchy Rules (THE SOURCE OF TRUTH)
        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true // <--- MARK AS REQUIRED (Matches Matrix)
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                // Create Virtual Placeholder
                                finalDocsList.push({
                                    id: `virtual-${key}`, // Needs to match ID generation in Reports for linking to work (or close enough)
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true // <--- MARK AS REQUIRED (Placeholder from Matrix)
                                });
                            }
                        });
                    });
                });
            });
        });

        // 3. Add Orphans (Documents that exist but match NO active matrix requirement)
        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false // <--- MARK AS NOT REQUIRED (Extra/Historic)
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  // --- 1. CONTEXT FILTERING (Dropdowns + External) ---
  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;

      // PRIORITY: If external filter exists (from Reports), use it exclusively first
      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          // Standard Filters
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);

          if (filterAnalyst) {
              filtered = filtered.filter(d => {
                  return d.assignees && d.assignees.includes(filterAnalyst);
              });
          }

          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
      }

      return filtered;
  }, [mergedDocs, filterProject, filterAnalyst, filterMacro, filterProcess, filterDocType, filterState, externalFilterIds]);

  // --- 2. STATS CALCULATION (ONLY COUNT REQUIRED DOCS) ---
  const stats = useMemo(() => {
      // Filter the context to only include REQUIRED documents for stats
      const requiredDocs = contextDocs.filter(d => d.isRequired);

      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  // --- 3. TABLE FILTERING (Context + Quick Filter) ---
  const tableDocs = useMemo(() => {
      let filtered = contextDocs;

      // Apply Quick Filter (Cards) - Applies to ALL documents (Required + Orphans) visible in table
      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  // --- 4. SORTING ---
  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          // Priority Sort: Required first, then Orphans
          if (a.isRequired !== b.isRequired) {
              return a.isRequired ? -1 : 1;
          }

          const modifier = sortConfig.direction === 'asc' ? 1 : -1;
          switch (sortConfig.key) {
              case 'updatedAt': 
                  const timeA = new Date(a.updatedAt).getTime();
                  const timeB = new Date(b.updatedAt).getTime();
                  return (timeA - timeB) * modifier;
              case 'project': return (a.project || '').localeCompare(b.project || '') * modifier;
              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return (a.progress - b.progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);


  const chartData = [
    { name: 'No Iniciado', value: stats.notStarted, color: '#e2e8f0' },
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control', value: stats.control, color: '#f97316' },
    { name: 'Finalizado', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const handleSort = (key: SortKey) => {
      setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  };

  const handleQuickFilter = (type: QuickFilterType) => {
      setQuickFilter(quickFilter === type ? 'ALL' : type);
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterAnalyst('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterDocType('');
      setFilterState('');
      setQuickFilter('ALL');
      setExternalFilterIds(null); // Clear external filter
      // Clear location state
      navigate(location.pathname, { replace: true, state: {} });
  };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => {
      const set = new Set(mergedDocs.map(d => d.project).filter(Boolean));
      return Array.from(set).sort();
  }, [mergedDocs]);

  const availableMacros = useMemo(() => {
      const docs = filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs;
      const set = new Set(docs.map(d => d.macroprocess).filter(Boolean));
      return Array.from(set).sort();
  }, [mergedDocs, filterProject]);

  const availableProcesses = useMemo(() => {
      let docs = mergedDocs;
      if (filterProject) docs = docs.filter(d => d.project === filterProject);
      if (filterMacro) docs = docs.filter(d => d.macroprocess === filterMacro);
      const set = new Set(docs.map(d => d.process).filter(Boolean));
      return Array.from(set).sort();
  }, [mergedDocs, filterProject, filterMacro]);

  const getUserName = (id: string) => {
      const u = allUsers.find(user => user.id === id);
      return u ? u.name : 'Sin Asignar';
  };

  const isAssignedToMe = (doc: DashboardDoc) => {
      return doc.assignees && doc.assignees.includes(user.id);
  };

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6">
                  <Database size={40} className="text-indigo-600" />
              </div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">
                  La matriz de procesos está vacía. Para visualizar el avance, es necesario cargar la estructura de procesos inicial.
              </p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? (
                  <Link 
                    to="/admin/assignments" 
                    className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95"
                  >
                      <Database size={18} className="mr-2" />
                      Ir a Carga de Datos
                  </Link>
              ) : (
                  <div className="flex items-center gap-2 text-amber-600 bg-amber-50 px-4 py-2 rounded-lg border border-amber-100">
                      <AlertTriangle size={18} />
                      <span>Contacte al administrador para inicializar el sistema.</span>
                  </div>
              )}
          </div>
      );
  }

  const hasActiveFilters = filterProject || filterAnalyst || filterMacro || filterProcess || filterDocType || filterState || externalFilterIds;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <div><h1 className="text-2xl font-bold text-slate-900">Dashboard</h1><p className="text-slate-500">Vista general</p></div>
        {user.role === UserRole.ANALYST && <Link to="/new" className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
      </div>

      {/* STATS CARDS */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
        <StatCard title="Doc. Requeridos" value={stats.total} icon={BookOpen} color="bg-slate-50 text-slate-600 border-slate-200" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
        <StatCard title="No Iniciado" value={stats.notStarted} icon={Clock} color="bg-white text-slate-600 border-slate-200" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
        <StatCard title="En Proceso" value={stats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600 border-blue-100" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
        <StatCard title="Referente" value={stats.referent} icon={Users} color="bg-purple-50 text-purple-600 border-purple-100" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
        <StatCard title="Control Gestión" value={stats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600 border-orange-100" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
        <StatCard title="Terminados" value={stats.finished} icon={CheckCircle} color="bg-green-50 text-green-600 border-green-100" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* MAIN TABLE */}
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">

            {/* FILTER BAR */}
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm">
                        <Filter size={16} /> Filtros de Visualización
                    </div>
                    {hasActiveFilters && (
                        <button 
                            onClick={clearFilters}
                            className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium transition-colors"
                        >
                            <X size={14} /> Limpiar filtros
                        </button>
                    )}
                </div>

                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">
                            Filtro Activo desde Reportes: Visualizando {externalFilterIds.length} documentos específicos.
                        </span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600 hover:bg-blue-50">
                            Mostrar Todo
                        </button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-3">
                        <select value={filterProject} onChange={(e) => { setFilterProject(e.target.value); setFilterMacro(''); setFilterProcess(''); }} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-32">
                            <option value="">Proyecto (Todos)</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>

                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-36">
                            <option value="">Analista (Todos)</option>
                            {allUsers
                                .filter(u => u.role === UserRole.ANALYST) // Strict Filter
                                .map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>

                        <select value={filterMacro} onChange={(e) => { setFilterMacro(e.target.value); setFilterProcess(''); }} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Macro (Todos)</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>

                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-40">
                            <option value="">Proceso (Todos)</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>

                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-32">
                            <option value="">Doc (Todos)</option>
                            {['AS IS', 'FCE', 'PM', 'TO BE'].map(t => <option key={t} value={t}>{t}</option>)}
                        </select>

                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-xs p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none focus:ring-1 focus:ring-indigo-500 w-36">
                            <option value="">Estado (Todos)</option>
                            {Object.keys(STATE_CONFIG).map(k => <option key={k} value={k}>{STATE_CONFIG[k as DocState].label.split('(')[0]}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-xs text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO</th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO</th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL</th>
                            <th className="px-4 py-3 cursor-pointer group text-right" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {sortedDocs.length === 0 ? <tr><td colSpan={6} className="p-8 text-center text-slate-400">Sin resultados.</td></tr> : sortedDocs.map((doc, idx) => (
                            <tr 
                                key={`${doc.id}-${idx}`} 
                                className={`transition-colors ${
                                    !doc.isRequired 
                                        ? 'bg-gray-100 hover:bg-gray-200' // <--- VISUALIZACIÓN GRIS PARA DOCUMENTOS "EXTRA"
                                        : 'hover:bg-slate-50'
                                }`}
                            >
                                {/* PROYECTO */}
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>

                                {/* JERARQUÍA */}
                                <td className={`px-4 py-3 align-top ${!doc.isRequired ? 'text-gray-400' : ''}`}>
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className={`${!doc.isRequired ? 'text-gray-400' : 'text-slate-500'}`}>{doc.process}</div>
                                </td>

                                {/* MICROPROCESO & ANALISTA */}
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>
                                        {doc.microprocess}
                                        {!doc.isRequired && <span className="ml-2 text-[9px] uppercase bg-gray-200 text-gray-500 px-1 rounded">No Requerido</span>}
                                    </div>
                                    <div className={`flex items-center gap-1 ${!doc.isRequired ? 'text-gray-400' : 'text-slate-500'}`} title="Analista Asignado">
                                        <UserIcon size={10} />
                                        <span className={`text-[10px] font-medium ${!doc.isRequired ? 'text-gray-500' : 'text-indigo-600'}`}>
                                            {doc.assignees && doc.assignees.length > 0 
                                                ? getUserName(doc.assignees[0]) 
                                                : 'Sin Asignar'}
                                        </span>
                                    </div>
                                </td>

                                {/* DOCUMENTO (TYPE & LINK) */}
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${
                                        !doc.isRequired 
                                            ? 'bg-gray-200 text-gray-500 border-gray-300' 
                                            : 'bg-indigo-50 text-indigo-700 border-indigo-100'
                                    }`}>
                                        {doc.docType}
                                    </span>
                                    {/* LINK UNIFICADO "VER DETALLE" */}
                                    <Link 
                                        to={`/doc/${doc.id}`} 
                                        state={{ docData: doc }} // Pasamos el doc en state para manejar virtuales
                                        className={`flex items-center gap-1 text-[10px] font-bold ${!doc.isRequired ? 'text-gray-500 hover:text-gray-700' : 'text-indigo-500 hover:text-indigo-700'}`}
                                    >
                                        Ver Detalle <ArrowRight size={10}/>
                                    </Link>
                                </td>

                                {/* ESTADO ACTUAL */}
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${
                                        !doc.isRequired 
                                            ? 'bg-gray-200 text-gray-500 border-gray-300' 
                                            : STATE_CONFIG[doc.state].color
                                    }`}>
                                        {STATE_CONFIG[doc.state].label.split('(')[0]}
                                    </div>
                                    <div className={`text-[10px] font-mono ${!doc.isRequired ? 'text-gray-400' : 'text-slate-500'}`}>
                                        Ver: {doc.version} ({doc.progress}%)
                                    </div>
                                </td>

                                {/* ÚLTIMA ACTIVIDAD */}
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="flex flex-col items-end">
                                            <div className={`flex items-center gap-1 font-medium ${!doc.isRequired ? 'text-gray-500' : 'text-slate-600'}`}>
                                                <Calendar size={10} />
                                                {new Date(doc.updatedAt).toLocaleDateString()}
                                            </div>
                                            <span className="text-[10px] text-slate-400">
                                                {new Date(doc.updatedAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                            </span>
                                        </div>
                                    ) : (
                                        <span className="text-slate-300 text-[10px]">-</span>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>

        {/* RIGHT COLUMN: CHART & SUMMARY */}
        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-sm">Estado (Requeridos)</h3>
                {chartData.length > 0 ? (
                    <div className="h-48 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie 
                                    data={chartData} 
                                    cx="50%" cy="50%" 
                                    innerRadius={50} outerRadius={70} 
                                    paddingAngle={2} 
                                    dataKey="value"
                                >
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '12px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-xs">Sin datos requeridos.</p>}

                <div className="flex flex-wrap justify-center gap-2 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span>
                            <span className="text-[10px] text-slate-500">{d.name}</span>
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-sm mb-3">Resumen de Cumplimiento</h3>
                <p className="text-xs text-indigo-700 mb-3">
                    Visualizando {contextDocs.length} filas totales.<br/>
                    <strong>{stats.total} documentos requeridos.</strong>
                </p>
                <ul className="space-y-2 text-xs">
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-slate-600">
                        <span>No Iniciados:</span> <span>{stats.notStarted}</span>
                    </li>
                    <li className="flex justify-between text-blue-600 font-medium">
                        <span>En Proceso:</span> <span>{stats.inProcess}</span>
                    </li>
                    <li className="flex justify-between text-purple-600 font-medium">
                        <span>Referente:</span> <span>{stats.referent}</span>
                    </li>
                    <li className="flex justify-between text-orange-600 font-medium">
                        <span>Control Gestión:</span> <span>{stats.control}</span>
                    </li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold">
                        <span>Terminados:</span> <span>{stats.finished}</span>
                    </li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[10px] text-slate-500 flex items-center gap-2">
                    <Archive size={12} />
                    <span>Los registros en <span className="font-bold text-gray-500">GRIS</span> son históricos/extra y no suman al cumplimiento.</span>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div onClick={onClick} className={`p-3 rounded-xl shadow-sm border cursor-pointer flex items-center space-x-3 transition-all ${isActive ? 'ring-2 ring-indigo-200 scale-105' : 'hover:border-indigo-300'} ${color}`}>
        <div className="p-1.5 bg-white/50 rounded-lg"><Icon size={18}/></div>
        <div>
            <p className="text-[9px] uppercase font-bold opacity-70">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { HierarchyService, UserService, NotificationService } from '../services/firebaseBackend';
import { User, FullHierarchy, ProcessNode, DocType, UserRole } from '../types';
import { 
  FolderTree, Search, ChevronRight, ChevronDown, Plus, X, Edit, Users, CheckSquare, Square, Filter, RefreshCw, AlertCircle, Link, Layers, Trash2, Loader2
} from 'lucide-react';

interface Props {
  user: User; // Admin User
}

const AdminAssignments: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [seeding, setSeeding] = useState(false);

  // State for deletion
  const [hiddenIds, setHiddenIds] = useState<Set<string>>(new Set());
  const [deletingIds, setDeletingIds] = useState<Set<string>>(new Set());

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterMicro, setFilterMicro] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  const [expandedProjects, setExpandedProjects] = useState<Record<string, boolean>>({ 'HPC': true, 'HSR': true });

  // Edit Assignment Modal State
  const [showEditModal, setShowEditModal] = useState(false);
  const [modalProject, setModalProject] = useState('');
  const [modalMacro, setModalMacro] = useState('');
  const [modalProcess, setModalProcess] = useState('');
  const [modalMicro, setModalMicro] = useState('');
  const [currentAssignees, setCurrentAssignees] = useState<string[]>([]);
  const [originalAssignees, setOriginalAssignees] = useState<string[]>([]);
  const [matrixKeyToUpdate, setMatrixKeyToUpdate] = useState<string | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async (showLoader = true) => {
    if (showLoader) setLoading(true);
    try {
        const [h, u] = await Promise.all([
          HierarchyService.getFullHierarchy(),
          UserService.getAll()
        ]);
        setHierarchy(h);
        setAllUsers(u);
    } catch (e) {
        console.error("Error loading assignments data:", e);
    } finally {
        if (showLoader) setLoading(false);
    }
  };

  const handleSeedDefaults = async () => {
      if (!window.confirm("¿Restaurar configuración de procesos por defecto?\nEsto agregará los microprocesos base si la base de datos está vacía.")) return;
      setSeeding(true);
      try {
          await HierarchyService.seedDefaults();
          await loadData();
          alert("Datos restaurados correctamente.");
      } catch (e: any) {
          alert("Error: " + e.message);
      } finally {
          setSeeding(false);
      }
  };

  const toggleProject = (proj: string) => {
    setExpandedProjects(prev => ({ ...prev, [proj]: !prev[proj] }));
  };

  // --- DELETE HANDLER (Matching Production Message) ---
  const handleDelete = async (project: string, macro: string, process: string, id: string, microName: string, e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();

      const cleanId = id?.trim();
      if (!cleanId) return;

      // MENSAJE EXACTO DE LA CAPTURA DE PANTALLA
      const confirmMsg = `¿Estás seguro de que deseas eliminar el microproceso "${microName}" de la matriz?\nEsta acción es irreversible en esta vista.`;

      if(!window.confirm(confirmMsg)) return;

      // 1. Ocultar inmediatamente (Visual)
      setHiddenIds(prev => new Set(prev).add(cleanId));
      setDeletingIds(prev => new Set(prev).add(cleanId)); 

      // 2. ELIMINAR DEL ESTADO LOCAL
      setHierarchy(prev => {
          const next = { ...prev };
          if (next[project] && next[project][macro] && next[project][macro][process]) {
              next[project][macro][process] = next[project][macro][process].filter(node => node.docId !== cleanId);
          }
          return next;
      });

      try {
          await HierarchyService.deleteMicroprocess(cleanId);
      } catch (e: any) {
          console.error("Error API:", e);
          alert("Error en el servidor, pero se ha ocultado localmente: " + e.message);
      } finally {
          setDeletingIds(prev => {
              const next = new Set(prev);
              next.delete(cleanId);
              return next;
          });
      }
  };

  // --- Handlers for EDIT Modal ---
  const handleEditAssignment = (
      proj: string, macro: string, proc: string, microObj: ProcessNode
  ) => {
      setModalProject(proj);
      setModalMacro(macro);
      setModalProcess(proc);
      setModalMicro(microObj.name);
      setMatrixKeyToUpdate(microObj.docId);
      const existing = [...(microObj.assignees || [])];
      setCurrentAssignees(existing);
      setOriginalAssignees(existing);
      setShowEditModal(true);
  };

  const handleAddAssignee = (userId: string) => {
      if (!userId) return;
      if (!currentAssignees.includes(userId)) {
          setCurrentAssignees([...currentAssignees, userId]);
      }
  };

  const handleRemoveAssignee = (userId: string) => {
      setCurrentAssignees(currentAssignees.filter(id => id !== userId));
  };

  const handleSubmitAssignment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!matrixKeyToUpdate) return;

      try {
          await HierarchyService.updateMatrixAssignment(matrixKeyToUpdate, currentAssignees, user.id);

          const addedAssignees = currentAssignees.filter(id => !originalAssignees.includes(id));
          if (addedAssignees.length > 0) {
              await Promise.all(addedAssignees.map(async (targetId) => {
                  await NotificationService.create(
                      targetId,
                      matrixKeyToUpdate!,
                      'ASSIGNMENT',
                      'Nueva Asignación de Proceso',
                      `Se le ha asignado el proceso: ${modalMicro} (${modalProject})`,
                      user.name
                  );
              }));
          }

          setShowEditModal(false);
          await loadData(false); 
      } catch (err: any) {
          alert(err.message);
      }
  };

  const handleToggleRequiredType = async (matrixKey: string, type: DocType) => {
      await HierarchyService.toggleRequiredType(matrixKey, type);
      await loadData(false);
  };

  // --- Filters Helpers ---
  const getAvailableMacros = () => {
      const macros = new Set<string>();
      Object.keys(hierarchy).forEach(proj => {
          if (filterProject && proj !== filterProject) return;
          Object.keys(hierarchy[proj]).forEach(m => macros.add(m));
      });
      return Array.from(macros).sort();
  };

  const getAvailableProcesses = () => {
      const processes = new Set<string>();
      Object.keys(hierarchy).forEach(proj => {
          if (filterProject && proj !== filterProject) return;
          Object.keys(hierarchy[proj]).forEach(m => {
              if (filterMacro && m !== filterMacro) return;
              Object.keys(hierarchy[proj][m]).forEach(p => processes.add(p));
          });
      });
      return Array.from(processes).sort();
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterMicro('');
      setFilterAnalyst('');
  };

  // Flattened Data for Table View within Project
  const getFlattenedRows = (project: string) => {
      const rows: any[] = [];
      const macros = hierarchy[project] || {};

      Object.keys(macros).forEach(macro => {
          if (filterMacro && macro !== filterMacro) return;

          Object.keys(macros[macro]).forEach(proc => {
              if (filterProcess && proc !== filterProcess) return;

              const nodes = macros[macro][proc];
              nodes.forEach(node => {
                  if (hiddenIds.has(node.docId)) return; // Skip deleted locally

                  // IMPORTANT: Filter out inactive nodes (Soft Deleted in Hierarchy)
                  // This ensures consistency between views.
                  if (node.active === false) return; 

                  if (filterMicro && !node.name.toLowerCase().includes(filterMicro.toLowerCase())) return;
                  if (filterAnalyst && (!node.assignees || !node.assignees.includes(filterAnalyst))) return;
                  rows.push({ macro, proc, node });
              });
          });
      });
      return rows;
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando matriz de procesos...</div>;

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterMicro || filterAnalyst;
  const isHierarchyEmpty = Object.keys(hierarchy).length === 0;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Gestor de Asignaciones</h1>
          <p className="text-slate-500">Asigne analistas responsables y defina documentos requeridos.</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             {isHierarchyEmpty && (
                 <button 
                    onClick={handleSeedDefaults}
                    disabled={seeding}
                    className="flex items-center px-4 py-2 bg-yellow-50 text-yellow-700 border border-yellow-200 rounded-lg hover:bg-yellow-100 transition-colors shadow-sm font-medium whitespace-nowrap"
                >
                    <RefreshCw size={18} className={`mr-2 ${seeding ? 'animate-spin' : ''}`} />
                    {seeding ? 'Restaurando...' : 'Cargar Datos por Defecto'}
                </button>
             )}
        </div>
      </div>

      {/* FILTER BAR */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <div className="flex items-center justify-between mb-3 border-b border-slate-100 pb-2">
              <h3 className="font-semibold text-slate-700 flex items-center gap-2">
                  <Filter size={18} className="text-indigo-600" /> Filtros de Matriz
              </h3>
              {hasActiveFilters && (
                  <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1">
                      <X size={14} /> Limpiar Todo
                  </button>
              )}
          </div>
          <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
              <select 
                  value={filterProject} 
                  onChange={(e) => setFilterProject(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Proyecto (Todos)</option>
                  {Object.keys(hierarchy).map(p => <option key={p} value={p}>{p}</option>)}
              </select>

              <select 
                  value={filterMacro} 
                  onChange={(e) => setFilterMacro(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Macroproceso (Todos)</option>
                  {getAvailableMacros().map(m => <option key={m} value={m}>{m}</option>)}
              </select>

              <select 
                  value={filterProcess} 
                  onChange={(e) => setFilterProcess(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Proceso (Todos)</option>
                  {getAvailableProcesses().map(p => <option key={p} value={p}>{p}</option>)}
              </select>

              <div className="relative">
                  <Search size={16} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                      type="text" 
                      placeholder="Buscar Microproceso..."
                      value={filterMicro}
                      onChange={(e) => setFilterMicro(e.target.value)}
                      className="w-full pl-8 p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
              </div>

               <select 
                  value={filterAnalyst} 
                  onChange={(e) => setFilterAnalyst(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Analista (Todos)</option>
                  {allUsers
                    .filter(u => u.role === UserRole.ANALYST) // Strict Filter
                    .map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
              </select>
          </div>
      </div>

      {isHierarchyEmpty && (
          <div className="p-8 bg-slate-50 border border-slate-200 rounded-xl text-center">
              <Layers size={48} className="mx-auto text-slate-300 mb-3" />
              <h3 className="text-lg font-bold text-slate-700">La Matriz de Procesos está vacía</h3>
              <p className="text-slate-500 mb-4">No se han definido procesos ni asignaciones aún.</p>
              <button 
                onClick={handleSeedDefaults}
                disabled={seeding}
                className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm font-medium"
              >
                  Cargar Datos por Defecto
              </button>
          </div>
      )}

      <div className="space-y-4">
        {Object.keys(hierarchy).map(projectKey => {
            if (filterProject && projectKey !== filterProject) return null;

            const rows = getFlattenedRows(projectKey);
            if (rows.length === 0) return null;

            return (
                <div key={projectKey} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    {/* Project Header */}
                    <div 
                        onClick={() => toggleProject(projectKey)}
                        className="flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 cursor-pointer transition-colors border-b border-slate-200"
                    >
                        <div className="flex items-center gap-2 font-bold text-slate-800 text-lg">
                            {expandedProjects[projectKey] ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
                            <FolderTree size={20} className="text-indigo-600" />
                            Proyecto {projectKey}
                        </div>
                        <span className="text-xs text-slate-500 font-medium bg-white px-2 py-1 rounded border border-slate-200">
                            {rows.length} Microprocesos
                        </span>
                    </div>

                    {/* Table View */}
                    {expandedProjects[projectKey] && (
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-50/50">
                                    <tr>
                                        <th className="px-4 py-3 w-1/4">Jerarquía (Macro / Proceso)</th>
                                        <th className="px-4 py-3 w-1/4">Microproceso</th>
                                        <th className="px-4 py-3 w-1/5">Documentos Definidos</th>
                                        <th className="px-4 py-3 w-1/4">Analistas Responsables</th>
                                        <th className="px-4 py-3 text-right">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {rows.map((row, idx) => (
                                        <tr key={`${row.node.docId}-${idx}`} className="hover:bg-slate-50 transition-colors">
                                            {/* Jerarquía */}
                                            <td className="px-4 py-3 align-top text-slate-600">
                                                <div className="font-semibold text-xs text-slate-700 mb-0.5">{row.macro}</div>
                                                <div className="text-xs text-slate-500 pl-2 border-l-2 border-slate-200">{row.proc}</div>
                                            </td>

                                            {/* Microproceso */}
                                            <td className="px-4 py-3 align-top">
                                                <span className="font-medium text-slate-900">{row.node.name}</span>
                                            </td>

                                            {/* Documentos Checkboxes */}
                                            <td className="px-4 py-3 align-top">
                                                <div className="flex items-center gap-2 flex-wrap">
                                                    {['AS IS', 'FCE', 'PM', 'TO BE'].map((type) => {
                                                        const isChecked = row.node.requiredTypes && row.node.requiredTypes.includes(type as DocType);
                                                        return (
                                                            <button 
                                                                key={type}
                                                                onClick={() => handleToggleRequiredType(row.node.docId, type as DocType)}
                                                                className={`flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold border transition-all ${
                                                                    isChecked 
                                                                    ? 'bg-indigo-100 text-indigo-700 border-indigo-200 hover:bg-indigo-200' 
                                                                    : 'bg-slate-50 text-slate-300 border-slate-200 hover:border-slate-300'
                                                                }`}
                                                                title={`Alternar ${type}`}
                                                            >
                                                                {isChecked ? <CheckSquare size={10} /> : <Square size={10} />}
                                                                {type}
                                                            </button>
                                                        );
                                                    })}
                                                </div>
                                            </td>

                                            {/* Analistas */}
                                            <td className="px-4 py-3 align-top">
                                                {(row.node.assignees && row.node.assignees.length > 0) ? (
                                                    <>
                                                        <div className="flex -space-x-2 overflow-hidden py-1">
                                                            {row.node.assignees.map((aid: string) => {
                                                                const u = allUsers.find(user => user.id === aid);
                                                                if (!u) {
                                                                    return (
