export const DocumentService = {
  getAll: async (): Promise<Document[]> => {
    const q = query(collection(db, "documents"), orderBy("updatedAt", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Document));
  },
  getById: async (id: string): Promise<Document | null> => {
    const docRef = doc(db, "documents", id);
    const docSnap = await getDoc(docRef);
    if (docSnap.exists()) return { id: docSnap.id, ...docSnap.data() } as Document;
    return null;
  },
  create: async (title: string, description: string, author: User, initialState?: DocState, initialVersion?: string, initialProgress?: number, file?: File, hierarchy?: any): Promise<Document> => {
    const state = initialState || DocState.INITIATED;
    const isSubmission = state === DocState.INTERNAL_REVIEW || state === DocState.SENT_TO_REFERENT || state === DocState.SENT_TO_CONTROL;

    let uploadedFiles: DocFile[] = [];
    if (file && STORAGE_ALLOWED_STATES.includes(state)) {
        try {
            const url = await uploadToStorage(file, `new_${Date.now()}`);
            uploadedFiles.push({
               id: `file-${Date.now()}`, name: file.name, size: file.size, type: file.type,
               url: url, uploadedAt: new Date().toISOString()
            });
        } catch (e) {
            console.error("File upload skipped/failed:", e);
            // Continue creation even if upload 'fails' in simulated mode
        }
    }

    // Merge passed assignees (from Matrix) with Author
    const passedAssignees = hierarchy?.assignees || [];
    const mergedAssignees = Array.from(new Set([...passedAssignees, author.id]));

    const newDocData: Omit<Document, 'id'> = {
      title, description, authorId: author.id, authorName: author.name,
      assignedTo: author.id, 
      assignees: mergedAssignees, 
      state, version: initialVersion || '0.0', progress: initialProgress || 10,
      hasPendingRequest: isSubmission,
      files: uploadedFiles, 
      createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(),
      project: hierarchy?.project, macroprocess: hierarchy?.macro, process: hierarchy?.process, microprocess: hierarchy?.micro, docType: hierarchy?.docType
    };
    const safeDocData = JSON.parse(JSON.stringify(newDocData));
    const docRef = await addDoc(collection(db, "documents"), safeDocData);
    const docId = docRef.id;

    // Explicit History Logging for State Change
    const previousStateForLog = DocState.NOT_STARTED; 
    const stateLabel = STATE_CONFIG[state]?.label || 'Desconocido';

    await HistoryService.log(docId, author, 'Creación', previousStateForLog, state, `Documento creado en estado: ${stateLabel} (Versión ${initialVersion}).`);
    await HistoryService.log(docId, author, 'Asignación', state, state, `Asignado a: ${author.name} ${passedAssignees.length > 0 ? `y ${passedAssignees.length} analistas más` : ''}`);

    // --- NEW: Trigger Notification if created in Review State ---
    if (state === DocState.INTERNAL_REVIEW || state === DocState.SENT_TO_REFERENT || state === DocState.SENT_TO_CONTROL) {
        const allUsers = await UserService.getAll();
        const coordinators = allUsers.filter(u => u.role === UserRole.COORDINATOR || u.role === UserRole.ADMIN);

        coordinators.forEach(coord => {
            NotificationService.create(
                coord.id,
                docId,
                'ASSIGNMENT',
                'Nueva Solicitud de Revisión',
                `El documento "${title}" ha sido cargado directamente en etapa de revisión (${stateLabel}).`,
                author.name
            );
        });
    }

    return { id: docId, ...newDocData } as Document;
  },

  delete: async (id: string) => {
      const docRef = doc(db, "documents", id);
      const snap = await getDoc(docRef);
      if (snap.exists()) {
          const data = snap.data() as Document;
          await cleanupOldFiles(data.files);
      }
      await deleteDoc(doc(db, "documents", id));
  },

  transitionState: async (docId: string, user: User, action: 'ADVANCE' | 'REJECT' | 'APPROVE' | 'REQUEST_APPROVAL' | 'COMMENT', comment: string, file?: File, customVersion?: string): Promise<void> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) throw new Error("Doc not found");
      const currentDoc = docSnap.data() as Document;

      let newState = currentDoc.state;
      let newVersion = currentDoc.version;
      let hasPending = currentDoc.hasPendingRequest;

      // Determine next state
      if (customVersion) {
        newVersion = customVersion;
        // Auto-determine state from version structure
        const { state } = determineStateFromVersion(customVersion);
        newState = state;
      }

      // Force state override if provided by Approve/Reject logic
      if (action === 'APPROVE') {
          hasPending = false;
          // State is updated via determineStateFromVersion above if version changed
      } else if (action === 'REJECT') {
          hasPending = false;
          // IMPORTANT: Rejections might need to go back to specific states based on version
          const { state } = determineStateFromVersion(newVersion);
          newState = state;
          comment = `RECHAZADO: ${comment}`;
      } else if (action === 'REQUEST_APPROVAL') {
          hasPending = true;
          // If purely requesting approval from In Process, go to Internal Review
          if (currentDoc.state === DocState.IN_PROCESS || currentDoc.state === DocState.INITIATED || currentDoc.state === DocState.REJECTED || currentDoc.state === DocState.NOT_STARTED) {
              newState = DocState.INTERNAL_REVIEW;
          }
      } else if (action === 'ADVANCE') {
          hasPending = false; 
          if (currentDoc.state === DocState.REJECTED) newState = DocState.IN_PROCESS; 
      } else if (action === 'COMMENT') {
          comment = `OBSERVACIÓN: ${comment}`; 
      }

      let finalFiles = [...(currentDoc.files || [])];

      if (file) {
          // In simulation mode, we don't really delete old files either, but we reset the list
          // await cleanupOldFiles(currentDoc.files); 
          finalFiles = []; 
          if (STORAGE_ALLOWED_STATES.includes(newState) || newState === DocState.IN_PROCESS || newState === DocState.REJECTED) {
              try {
                  const url = await uploadToStorage(file, docId);
                  finalFiles.push({
                      id: `file-${Date.now()}`, name: file.name, size: file.size, type: file.type,
                      url: url, uploadedAt: new Date().toISOString()
                  });
              } catch (e) {
                  console.error("Transition upload skipped:", e);
              }
          }
      }

      const progress = STATE_CONFIG[newState]?.progress || currentDoc.progress;
      await updateDoc(docRef, {
          state: newState, version: newVersion, hasPendingRequest: hasPending,
          files: finalFiles, progress, updatedAt: new Date().toISOString()
      });
      const actionLabel = action === 'COMMENT' ? 'Observación' : action;
      await HistoryService.log(docId, user, actionLabel, currentDoc.state, newState, comment);

      // Async Notifications (Non-blocking)
      const notifyPromises = [];
      if (action === 'APPROVE' || action === 'REJECT') {
          const targetIds = currentDoc.assignees || [currentDoc.authorId];
          const type = action === 'APPROVE' ? 'APPROVAL' : 'REJECTION';
          const title = action === 'APPROVE' ? 'Documento Aprobado' : 'Documento Rechazado';
          targetIds.forEach(targetId => {
              if (targetId !== user.id) {
                  notifyPromises.push(NotificationService.create(targetId, docId, type, title, `${currentDoc.title}: ${comment}`, user.name));
              }
          });
      }

      if (action === 'COMMENT') {
           if (user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) {
               const targetIds = currentDoc.assignees || [currentDoc.authorId];
               targetIds.forEach(targetId => {
                  if (targetId !== user.id) notifyPromises.push(NotificationService.create(targetId, docId, 'COMMENT', 'Nueva Observación', `${currentDoc.title}: ${comment}`, user.name));
               });
           } else {
               const allUsers = await UserService.getAll();
               const coords = allUsers.filter(u => u.role === UserRole.COORDINATOR);
               coords.forEach(c => notifyPromises.push(NotificationService.create(c.id, docId, 'COMMENT', 'Comentario de Analista', `${currentDoc.title}: ${comment}`, user.name)));
           }
      }

      if (action === 'REQUEST_APPROVAL') {
           const allUsers = await UserService.getAll();
           let targets = allUsers.filter(u => u.role === UserRole.COORDINATOR);
           if (targets.length === 0) targets = allUsers.filter(u => u.role === UserRole.ADMIN);

           for (const target of targets) {
               notifyPromises.push(NotificationService.create(
                   target.id, 
                   docId, 
                   'ASSIGNMENT', 
                   'Solicitud de Aprobación', 
                   `El documento "${currentDoc.title}" (v${newVersion}) requiere su revisión.`, 
                   user.name
               ));
           }
      }
      // Execute notifications in background
      Promise.allSettled(notifyPromises);
  }
};

export const HierarchyService = {
  getFullHierarchy: async (): Promise<FullHierarchy> => {
    const q = query(collection(db, "process_matrix"));
    const snapshot = await getDocs(q);
    const hierarchy: FullHierarchy = {};

    snapshot.docs.forEach(doc => {
      const data = doc.data();
      const proj = data.project;
      // FIX: Read either 'macro' or 'macroprocess' to support legacy/migrated data without breaking UI
      const macro = data.macro || data.macroprocess || 'Sin Macroproceso';
      const process = data.process;
      const node: ProcessNode = {
        name: data.name,
        docId: doc.id,
        assignees: data.assignees || [],
        requiredTypes: data.requiredTypes || [],
        active: data.active !== false // Default true
      };

      if (!hierarchy[proj]) hierarchy[proj] = {};
      if (!hierarchy[proj][macro]) hierarchy[proj][macro] = {};
      if (!hierarchy[proj][macro][process]) hierarchy[proj][macro][process] = [];

      hierarchy[proj][macro][process].push(node);
    });

    return hierarchy;
  },

  getUserHierarchy: async (userId: string): Promise<UserHierarchy> => {
      const q = query(collection(db, "process_matrix"), where("assignees", "array-contains", userId));
      const snapshot = await getDocs(q);
      const hierarchy: UserHierarchy = {};

      snapshot.docs.forEach(doc => {
          const data = doc.data();
           if (data.active === false) return;

          const proj = data.project;
          // FIX: Read either 'macro' or 'macroprocess'
          const macro = data.macro || data.macroprocess || 'Sin Macroproceso';
          const process = data.process;

          if (!hierarchy[proj]) hierarchy[proj] = {};
          if (!hierarchy[proj][macro]) hierarchy[proj][macro] = {};
          if (!hierarchy[proj][macro][process]) hierarchy[proj][macro][process] = [];

          hierarchy[proj][macro][process].push(data.name);
      });
      return hierarchy;
  },

  getRequiredTypesMap: async (): Promise<Record<string, DocType[]>> => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const map: Record<string, DocType[]> = {};

      snapshot.docs.forEach(doc => {
          const data = doc.data();
          if (data.active === false) return;
          const key = `${normalizeHeader(data.project)}|${normalizeHeader(data.name)}`;
          map[key] = data.requiredTypes || [];
      });
      return map;
  },

  updateMatrixAssignment: async (docId: string, assignees: string[], assignedBy: string) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, { assignees });
  },

  toggleRequiredType: async (docId: string, type: DocType) => {
      const ref = doc(db, "process_matrix", docId);
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const data = snap.data();
          const current = new Set(data.requiredTypes || []);
          if (current.has(type)) current.delete(type);
          else current.add(type);
          await updateDoc(ref, { requiredTypes: Array.from(current) });
      }
  },

  addMicroprocess: async (project: string, macro: string, process: string, name: string, assignees: string[], requiredTypes: string[]) => {
      const id = generateMatrixId(project, name);
      const ref = doc(db, "process_matrix", id);
      await setDoc(ref, {
          project, macroprocess: macro, process, name, assignees, requiredTypes, active: true
      });
  },

  deleteMicroprocess: async (docId: string) => {
      await deleteDoc(doc(db, "process_matrix", docId));
  },

  toggleProcessStatus: async (docId: string, currentStatus: boolean) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, { active: !currentStatus }); // Invert status
  },

  updateHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', oldName: string, newName: string, context: { project?: string, macro?: string }) => {
      let q = query(collection(db, "process_matrix"));
      if (level === 'PROJECT') {
          q = query(collection(db, "process_matrix"), where("project", "==", oldName));
      } else if (level === 'MACRO') {
           q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", oldName));
      } else if (level === 'PROCESS') {
           q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", oldName));
      }

      const snapshot = await getDocs(q);
      const batch = writeBatch(db);

      snapshot.docs.forEach(d => {
          const update: any = {};
          if (level === 'PROJECT') update.project = newName;
          if (level === 'MACRO') update.macroprocess = newName;
          if (level === 'PROCESS') update.process = newName;

          if (level === 'PROJECT') {
              const data = d.data();
              const newId = generateMatrixId(newName, data.name);
              const newRef = doc(db, "process_matrix", newId);
              batch.set(newRef, { ...data, ...update });
              batch.delete(d.ref);
          } else {
              batch.update(d.ref, update);
          }
      });
      await batch.commit();
  },

  deleteHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, context: { project?: string, macro?: string }) => {
      let q = query(collection(db, "process_matrix"));
      if (level === 'PROJECT') {
          q = query(collection(db, "process_matrix"), where("project", "==", name));
      } else if (level === 'MACRO') {
           q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", name));
      } else if (level === 'PROCESS') {
           q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", name));
      }

      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
  },

  moveMicroprocess: async (docId: string, targetProject: string, targetMacro: string, targetProcess: string) => {
      const ref = doc(db, "process_matrix", docId);
      const snap = await getDoc(ref);
      if (!snap.exists()) throw new Error("Microprocess not found");

      const data = snap.data();
      if (data.project !== targetProject) {
          const newId = generateMatrixId(targetProject, data.name);
          const newRef = doc(db, "process_matrix", newId);
          await setDoc(newRef, { ...data, project: targetProject, macroprocess: targetMacro, process: targetProcess });
          await deleteDoc(ref);
      } else {
          await updateDoc(ref, { macroprocess: targetMacro, process: targetProcess });
      }
  },

  seedDefaults: async () => {
      const batch = writeBatch(db);
      for (const row of REQUIRED_DOCS_MATRIX) {
           const [project, micro, asis, fce, pm, tobe] = row;
           const requiredTypes: string[] = [];
           if (asis) requiredTypes.push('AS IS');
           if (fce) requiredTypes.push('FCE');
           if (pm) requiredTypes.push('PM');
           if (tobe) requiredTypes.push('TO BE');

           const id = generateMatrixId(project, micro);
           const ref = doc(db, "process_matrix", id);

           const snap = await getDoc(ref);
           if (!snap.exists()) {
               batch.set(ref, {
                   project,
                   macroprocess: 'Macroproceso General',
                   process: 'Proceso General',
                   name: micro,
                   assignees: [],
                   requiredTypes,
                   active: true
               });
           }
      }
      await batch.commit();
  }
};

export const DatabaseService = {
    exportData: async (): Promise<string> => {
        const collections = ['users', 'documents', 'history', 'process_matrix', 'notifications'];
        const data: any = {};

        for (const colName of collections) {
            const snapshot = await getDocs(collection(db, colName));
            data[colName] = snapshot.docs.map(d => ({ _id: d.id, ...d.data() }));
        }
        return JSON.stringify(data, null, 2);
    },

    importData: async (jsonString: string) => {
        const data = JSON.parse(jsonString);

        for (const colName of Object.keys(data)) {
            await deleteCollectionInBatches(colName);

            const items = data[colName];
            let batch = writeBatch(db);
            let count = 0;

            for (const item of items) {
                const { _id, ...docData } = item;
                const ref = doc(db, colName, _id);
                batch.set(ref, docData);
                count++;
                if (count >= 400) {
                    await batch.commit();
                    batch = writeBatch(db);
                    count = 0;
                }
            }
            if (count > 0) await batch.commit();
        }
    },

    fullSystemResetAndImport: async (rulesCSV: string, historyCSV: string, onProgress: (percent: number, status: string) => void): Promise<{ created: number, historyMatched: number }> => {
        // 1. Clear Database
        onProgress(5, "Limpiando base de datos...");
        await deleteCollectionInBatches("documents");
        await deleteCollectionInBatches("history");
        await deleteCollectionInBatches("process_matrix");
        await deleteCollectionInBatches("notifications");

        onProgress(10, "Procesando reglas de estructura...");

        // 2. Parse Rules CSV (Structure)
        const rows = rulesCSV.split(/\r?\n/).filter(r => r.trim().length > 0);
        const headers = rows[0].split(/[;,]/).map(h => normalizeHeader(h));

        const idxProject = headers.findIndex(h => h.includes('PROYECTO'));
        const idxMacro = headers.findIndex(h => h.includes('MACRO'));
        const idxProcess = headers.findIndex(h => h === 'PROCESO');
        const idxMicro = headers.findIndex(h => h.includes('MICRO'));
        const idxAnalyst = headers.findIndex(h => h.includes('ANALISTA') || h.includes('RESPONSABLE'));

        const idxAsis = headers.findIndex(h => h.includes('ASIS') || h.includes('AS IS'));
        const idxFce = headers.findIndex(h => h.includes('FCE'));
        const idxPm = headers.findIndex(h => h.includes('PM'));
        const idxTobe = headers.findIndex(h => h.includes('TOBE') || h.includes('TO BE'));

        const allUsers = await UserService.getAll();
        let createdCount = 0;
        let batch = writeBatch(db);
        let opCount = 0;

        const matrixMap = new Map<string, ProcessNode>();

        for (let i = 1; i < rows.length; i++) {
            const cols = rows[i].split(/[;,]/).map(c => c.trim());
            if (cols.length < 3) continue;

            const project = cols[idxProject] || 'GENERAL';
            const macro = cols[idxMacro] || 'General';
            const process = cols[idxProcess] || 'General';
            const micro = cols[idxMicro];

            if (!micro) continue;

            const analystRaw = cols[idxAnalyst];
            const assignees = findUserIdsFromCSV(allUsers, analystRaw);

            const requiredTypes: string[] = [];
            if (cols[idxAsis] === '1') requiredTypes.push('AS IS');
            if (cols[idxFce] === '1') requiredTypes.push('FCE');
            if (cols[idxPm] === '1') requiredTypes.push('PM');
            if (cols[idxTobe] === '1') requiredTypes.push('TO BE');
            if (requiredTypes.length === 0) {
                 requiredTypes.push('AS IS', 'FCE', 'PM', 'TO BE');
            }

            const id = generateMatrixId(project, micro);
            const nodeData = {
                project, macroprocess: macro, process, name: micro, assignees, requiredTypes, active: true
            };

            const ref = doc(db, "process_matrix", id);
            batch.set(ref, nodeData);

            // FIXME: Storing raw analyst name in memory map to allow fallback in Step 3
            matrixMap.set(id, { docId: id, ...nodeData, rawAnalyst: analystRaw } as any);

            opCount++;
            createdCount++;

            if (opCount >= 400) {
                await batch.commit();
                batch = writeBatch(db);
                opCount = 0;
                onProgress(10 + Math.floor((i / rows.length) * 40), `Estructurando: ${createdCount} nodos...`);
            }
        }
        if (opCount > 0) await batch.commit();

        // 3. Process History CSV (Optional)
        let historyMatched = 0;

        if (historyCSV) {
             onProgress(50, "Procesando histórico...");
             const hRows = historyCSV.split(/\r?\n/).filter(r => r.trim().length > 0);
             const hHeaders = hRows[0].split(/[;,]/).map(h => normalizeHeader(h));

             const hIdxProject = hHeaders.findIndex(h => h.includes('PROYECTO'));
             const hIdxMicro = hHeaders.findIndex(h => h.includes('MICRO'));

             // NEW: Identify separate column indices for Version and Date for each DocType
             const typeCols: { type: string, versionIndex: number, dateIndex: number }[] = [];
             ['AS IS', 'FCE', 'PM', 'TO BE'].forEach(t => {
                 const normType = normalizeHeader(t);
                 // Look for headers containing both Type and "VERSION"/"FECHA" respectively
                 // "Versión AS IS" -> "VERSION AS IS"
                 // "Fecha AS IS" -> "FECHA AS IS"
                 const versionIndex = hHeaders.findIndex(h => h.includes(normType) && h.includes('VERSION'));
                 const dateIndex = hHeaders.findIndex(h => h.includes(normType) && h.includes('FECHA'));

                 // Only add if at least Version column is found
                 if (versionIndex !== -1) {
                     typeCols.push({ type: t, versionIndex, dateIndex });
                 }
             });

             batch = writeBatch(db);
             opCount = 0;

             for (let i = 1; i < hRows.length; i++) {
                 const cols = hRows[i].split(/[;,]/).map(c => c.trim());
                 if (cols.length < 2) continue;

                 const project = cols[hIdxProject];
                 const micro = cols[hIdxMicro];

                 if (!project || !micro) continue;

                 const matrixId = generateMatrixId(project, micro);
                 const matrixNode = matrixMap.get(matrixId);

                 if (matrixNode) {
                     for (const tc of typeCols) {
                         // Extract Version and Date from separate columns
                         const versionCell = cols[tc.versionIndex];
                         const dateCell = tc.dateIndex !== -1 ? cols[tc.dateIndex] : '';

                         if (!versionCell || versionCell === '-' || versionCell === '0') continue;

                         const version = versionCell.trim();
                         let date = new Date().toISOString(); 

                         // Try to parse specific Date column if available
                         if (dateCell) {
                             const parsed = parseDateString(dateCell);
                             if (parsed) date = parsed;
                         } else {
                             // Fallback: Check if version cell itself contains a date (legacy logic support)
                             const match = versionCell.match(/\((.+?)\)/);
                             if (match) {
                                 const parsed = parseDateString(match[1]);
                                 if (parsed) date = parsed;
                             }
                         }

                         const { state, progress } = determineStateFromVersion(version);

                         const docId = generateDocumentId(project, micro, tc.type);
                         const docRef = doc(db, "documents", docId);

                         const authorId = (matrixNode.assignees && matrixNode.assignees.length > 0) 
                             ? matrixNode.assignees[0] 
                             : (allUsers.find(u => u.role === UserRole.ADMIN)?.id || 'admin');

                         // FIX 1: Resolve actual name or Fallback to Raw CSV Name
                         let authorName = 'Sistema (Carga)';
                         const authorUser = allUsers.find(u => u.id === authorId);
                         if (authorUser) {
                             authorName = authorUser.name;
                         } else if ((matrixNode as any).rawAnalyst) {
                             authorName = (matrixNode as any).rawAnalyst;
                         }

                         const docData = {
                             title: `${micro} - ${tc.type}`,
                             description: 'Carga Histórica',
                             project,
                             macroprocess: (matrixNode as any).macroprocess,
                             process: (matrixNode as any).process,
                             microprocess: micro,
                             docType: tc.type,
                             authorId,
                             authorName, // Using resolved or raw name
                             assignees: matrixNode.assignees,
                             state,
                             version, // Just the version string (e.g. v1.0ACG)
                             progress,
                             hasPendingRequest: false,
                             createdAt: date,
                             updatedAt: date, // FIX 2: Set activity date to historical date found in "Fecha X" column
                             files: []
                         };

                         batch.set(docRef, docData);
                         historyMatched++;
                         opCount++;
                         if (opCount >= 400) {
                             await batch.commit();
                             batch = writeBatch(db);
                             opCount = 0;
                         }
                     }
                 }

                 if (i % 50 === 0) onProgress(50 + Math.floor((i / hRows.length) * 40), `Importando documentos: ${historyMatched}...`);
             }
             if (opCount > 0) await batch.commit();
        }

        onProgress(100, "Finalizando...");
        return { created: createdCount, historyMatched };
    }
};

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State (Updated for File Upload)
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    // Priority: State (Virtual Doc) -> ID (Fetch)
    if (location.state?.docData) {
        setDoc(location.state.docData);
        setLoading(false);
        if (!location.state.docData.id.startsWith('virtual-')) {
             loadAuxiliaryData(location.state.docData.id);
        } else {
             const d = location.state.docData;
             if (d.assignees && d.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = d.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  // Helper to find assignees robustly
  const resolveAssignees = (d: Document, hierarchy: FullHierarchy): string[] => {
      let resolvedIds = d.assignees || [];
      const isLegacy = d.authorName.includes('Sistema') || d.authorName.includes('Carga');

      // Si no hay asignados explícitos O es un documento migrado (donde assignments pueden estar desactualizados),
      // buscamos en la Matriz viva.
      if ((resolvedIds.length === 0 || isLegacy) && d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);

           let node: any = null;

           // Búsqueda Profunda Normalizada
           if (hierarchy) {
               for (const projKey of Object.keys(hierarchy)) {
                   if (normalizeHeader(projKey) === targetProject) {
                       const projData = hierarchy[projKey];
                       for (const macroKey of Object.keys(projData)) {
                           const macroData = projData[macroKey];
                           for (const procKey of Object.keys(macroData)) {
                               const nodes = macroData[procKey];
                               const found = nodes.find(n => normalizeHeader(n.name) === targetMicro);
                               if (found) {
                                   node = found;
                                   break;
                               }
                           }
                           if (node) break;
                       }
                   }
                   if (node) break;
               }
           }

           if (node?.assignees && node.assignees.length > 0) resolvedIds = node.assignees;
      }
      return resolvedIds;
  };

  const loadAuxiliaryData = async (docId: string) => {
      try {
          const [h, allUsers, hierarchy] = await Promise.all([
              HistoryService.getHistory(docId),
              UserService.getAll(),
              HierarchyService.getFullHierarchy()
          ]);
          setHistory(h);

          if (doc) {
              const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
              if (coordinator) setCoordinatorEmail(coordinator.email);
              const author = allUsers.find(u => u.id === doc.authorId);
              if (author) setAuthorEmail(author.email);

              const resolvedIds = resolveAssignees(doc, hierarchy);

              if (resolvedIds.length > 0) {
                  const names = resolvedIds
                      .map(aid => allUsers.find(u => u.id === aid)?.name)
                      .filter(n => n) as string[];
                  setAssigneeNames(names);
              }
          }
      } catch (e) {
          console.error("Error loading aux data", e);
      }
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy()
        ]);

        if (d) {
            setDoc(d);
            setHistory(h);

            const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
            if (coordinator) setCoordinatorEmail(coordinator.email);

            const author = allUsers.find(u => u.id === d.authorId);
            if (author) setAuthorEmail(author.email);

            const resolvedIds = resolveAssignees(d, hierarchy);

            if (resolvedIds.length > 0) {
                const names = resolvedIds
                    .map(aid => allUsers.find(u => u.id === aid)?.name)
                    .filter(n => n) as string[];
                setAssigneeNames(names);
            } else {
                setAssigneeNames([]);
            }
        } else {
            setDoc(null);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---
  const handleNewRequest = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const handleDeleteClick = () => {
      setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
      if (!doc) return;
      try {
          setShowDeleteModal(false);
          setLoading(true); 
          await DocumentService.delete(doc.id);
          navigate('/', { replace: true });
      } catch (e: any) {
          console.error("Error eliminando documento:", e);
          alert('Error al eliminar: ' + e.message);
          setLoading(false);
      }
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(null);
          setFileError([]);
          setIsFileValid(false);
          setDetectedVersion('');
          setShowResponseModal(true);
      }
  };

  // --- FILE HANDLING FOR MODAL ---
  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0];
          setResponseFile(f);

          // 1. Base Parse
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);

          if (!result.valido) {
              setFileError(result.errores);
              setIsFileValid(false);
              return;
          }

          // 2. Coordinator Rules Logic
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) {
              setFileError([rules.error || 'Error de validación de versión.']);
              setIsFileValid(false);
              return;
          }

          setIsFileValid(true);
          setFileError([]);
          setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;

      const actionText = pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR';
      const msg = `¿Confirma ${actionText} la solicitud cargando el archivo ${detectedVersion}?`;

      if (window.confirm(msg)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? `Solicitud enviada tras validar archivo.` : `Gestión realizada.`),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  const handleGmailNotification = () => {
    if (!doc || !coordinatorEmail) return;
    const subject = encodeURIComponent(`Solicitud de Aprobación SGD: ${doc.project} - ${doc.microprocess}`);
    const body = encodeURIComponent(`Estimado Coordinador,\n\nSolicitud de revisión para ${doc.title}.\nVersión: ${doc.version}\n\nAtentamente,\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  if (!doc) return (
      <div className="p-12 text-center flex flex-col items-center justify-center">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <FileX size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2>
          <p className="text-slate-500 mb-6">El documento que buscas no existe o ha sido eliminado.</p>
          <button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
              Volver al Inicio
          </button>
      </div>
  );

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;

  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyCoordinator = isAnalystAssigned && coordinatorEmail && doc.state !== DocState.APPROVED;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button 
                type="button"
                onClick={handleDeleteClick}
                className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
            >
                <Trash2 size={16} className="mr-1" /> Eliminar
            </button>
        )}
      </div>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div>
                <p className="text-slate-500">Analistas</p>
                {assigneeNames.length > 0 ? (
                    assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-800">{doc.authorName}</p>
                )}
            </div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">

            {!canEdit && (
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
                    <div className="flex">
                        <div className="flex-shrink-0"><Lock size={20} className="text-yellow-400" /></div>
                        <div className="ml-3"><p className="text-sm text-yellow-700">Solo lectura.</p></div>
                    </div>
                </div>
            )}

            {/* Acciones */}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>

                     {/* NUEVA SOLICITUD (Available for Analysts independent of state, unless Approved) */}
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button 
                                onClick={handleNewRequest}
                                className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"
                             >
                                 <PlusCircle size={20} className="mr-2" />
                                 {doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}
                             </button>
                             <p className="text-xs text-center text-slate-500 mt-2">
                                 Crea una nueva solicitud basada en este documento para avanzar a la siguiente etapa.
                             </p>
                         </div>
                     )}

                     <textarea 
                        className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                        rows={3}
                        placeholder="Observaciones..."
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                     />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>

                        {canNotifyCoordinator && <button onClick={handleGmailNotification} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm"><Mail size={16} className="mr-2" /> Notificar Coord.</button>}
                        {canNotifyAuthor && <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm"><Mail size={16} className="mr-2" /> Notificar Analista</button>}

                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}

                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.length === 0 ? <p className="text-xs text-slate-400 italic">Sin historial registrado.</p> : history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (COORDINADOR) - CON CARGA DE ARCHIVO */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed">
                                        {getCoordinatorRuleHint(doc.state, pendingAction)}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* File Upload Zone */}
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleResponseFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={32} className="mx-auto mb-2" />
                                    <p className="font-medium text-sm">Click para cargar respuesta</p>
                                    <p className="text-xs mt-1 text-slate-400">
                                        Debe cumplir con la nomenclatura de la etapa.
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!isFileValid}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                <Save size={16} />
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6">
                      <p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p>
                      <div className="flex justify-end gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                          <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State (Updated for File Upload)
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    // Priority: State (Virtual Doc) -> ID (Fetch)
    if (location.state?.docData) {
        setDoc(location.state.docData);
        setLoading(false);
        if (!location.state.docData.id.startsWith('virtual-')) {
             loadAuxiliaryData(location.state.docData.id);
        } else {
             const d = location.state.docData;
             if (d.assignees && d.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = d.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  // Helper to find assignees robustly
  const resolveAssignees = (d: Document, hierarchy: FullHierarchy): string[] => {
      let resolvedIds = d.assignees || [];
      const isLegacy = d.authorName.includes('Sistema') || d.authorName.includes('Carga');

      // Si no hay asignados explícitos O es un documento migrado (donde assignments pueden estar desactualizados),
      // buscamos en la Matriz viva.
      if ((resolvedIds.length === 0 || isLegacy) && d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);

           let node: any = null;

           // Búsqueda Profunda Normalizada
           if (hierarchy) {
               for (const projKey of Object.keys(hierarchy)) {
                   if (normalizeHeader(projKey) === targetProject) {
                       const projData = hierarchy[projKey];
                       for (const macroKey of Object.keys(projData)) {
                           const macroData = projData[macroKey];
                           for (const procKey of Object.keys(macroData)) {
                               const nodes = macroData[procKey];
                               const found = nodes.find(n => normalizeHeader(n.name) === targetMicro);
                               if (found) {
                                   node = found;
                                   break;
                               }
                           }
                           if (node) break;
                       }
                   }
                   if (node) break;
               }
           }

           if (node?.assignees && node.assignees.length > 0) resolvedIds = node.assignees;
      }
      return resolvedIds;
  };

  const loadAuxiliaryData = async (docId: string) => {
      try {
          const [h, allUsers, hierarchy] = await Promise.all([
              HistoryService.getHistory(docId),
              UserService.getAll(),
              HierarchyService.getFullHierarchy()
          ]);
          setHistory(h);

          if (doc) {
              const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
              if (coordinator) setCoordinatorEmail(coordinator.email);
              const author = allUsers.find(u => u.id === doc.authorId);
              if (author) setAuthorEmail(author.email);

              const resolvedIds = resolveAssignees(doc, hierarchy);

              if (resolvedIds.length > 0) {
                  const names = resolvedIds
                      .map(aid => allUsers.find(u => u.id === aid)?.name)
                      .filter(n => n) as string[];
                  setAssigneeNames(names);
              }
          }
      } catch (e) {
          console.error("Error loading aux data", e);
      }
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy()
        ]);

        if (d) {
            setDoc(d);
            setHistory(h);

            const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
            if (coordinator) setCoordinatorEmail(coordinator.email);

            const author = allUsers.find(u => u.id === d.authorId);
            if (author) setAuthorEmail(author.email);

            const resolvedIds = resolveAssignees(d, hierarchy);

            if (resolvedIds.length > 0) {
                const names = resolvedIds
                    .map(aid => allUsers.find(u => u.id === aid)?.name)
                    .filter(n => n) as string[];
                setAssigneeNames(names);
            } else {
                setAssigneeNames([]);
            }
        } else {
            setDoc(null);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---
  const handleNewRequest = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const handleDeleteClick = () => {
      setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
      if (!doc) return;
      try {
          setShowDeleteModal(false);
          setLoading(true); 
          await DocumentService.delete(doc.id);
          navigate('/', { replace: true });
      } catch (e: any) {
          console.error("Error eliminando documento:", e);
          alert('Error al eliminar: ' + e.message);
          setLoading(false);
      }
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(null);
          setFileError([]);
          setIsFileValid(false);
          setDetectedVersion('');
          setShowResponseModal(true);
      }
  };

  // --- FILE HANDLING FOR MODAL ---
  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0];
          setResponseFile(f);

          // 1. Base Parse
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);

          if (!result.valido) {
              setFileError(result.errores);
              setIsFileValid(false);
              return;
          }

          // 2. Coordinator Rules Logic
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) {
              setFileError([rules.error || 'Error de validación de versión.']);
              setIsFileValid(false);
              return;
          }

          setIsFileValid(true);
          setFileError([]);
          setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;

      const actionText = pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR';
      const msg = `¿Confirma ${actionText} la solicitud cargando el archivo ${detectedVersion}?`;

      if (window.confirm(msg)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? `Solicitud enviada tras validar archivo.` : `Gestión realizada.`),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  const handleGmailNotification = () => {
    if (!doc || !coordinatorEmail) return;
    const subject = encodeURIComponent(`Solicitud de Aprobación SGD: ${doc.project} - ${doc.microprocess}`);
    const body = encodeURIComponent(`Estimado Coordinador,\n\nSolicitud de revisión para ${doc.title}.\nVersión: ${doc.version}\n\nAtentamente,\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // NOTIFICACIÓN EXTERNA PARA COORDINADOR (REFERENTE / CONTROL)
  const handleNotifyExternal = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.docType || ''} ${doc.microprocess || ''}`);
      const body = encodeURIComponent(
`Estimados,
Para vuestra aprobación, adjunto el Informe ${doc.docType || ''} - ${doc.microprocess || ''} ${doc.version}, 

Atento a comentarios
Saludos

${user.name}`
      );
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  if (!doc) return (
      <div className="p-12 text-center flex flex-col items-center justify-center">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <FileX size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2>
          <p className="text-slate-500 mb-6">El documento que buscas no existe o ha sido eliminado.</p>
          <button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
              Volver al Inicio
          </button>
      </div>
  );

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;

  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyCoordinator = isAnalystAssigned && coordinatorEmail && doc.state !== DocState.APPROVED;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  // Condiciones para mostrar botón de notificación externa (Coordinador)
  const canNotifyExternal = (isCoordinatorOrAdmin) && 
                            (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.SENT_TO_CONTROL);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button 
                type="button"
                onClick={handleDeleteClick}
                className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
            >
                <Trash2 size={16} className="mr-1" /> Eliminar
            </button>
        )}
      </div>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div>
                <p className="text-slate-500">Analistas</p>
                {assigneeNames.length > 0 ? (
                    assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-800">{doc.authorName}</p>
                )}
            </div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">

            {!canEdit && (
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
                    <div className="flex">
                        <div className="flex-shrink-0"><Lock size={20} className="text-yellow-400" /></div>
                        <div className="ml-3"><p className="text-sm text-yellow-700">Solo lectura.</p></div>
                    </div>
                </div>
            )}

            {/* Acciones */}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>

                     {/* NUEVA SOLICITUD (Available for Analysts independent of state, unless Approved) */}
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button 
                                onClick={handleNewRequest}
                                className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"
                             >
                                 <PlusCircle size={20} className="mr-2" />
                                 {doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}
                             </button>
                             <p className="text-xs text-center text-slate-500 mt-2">
                                 Crea una nueva solicitud basada en este documento para avanzar a la siguiente etapa.
                             </p>
                         </div>
                     )}

                     <textarea 
                        className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                        rows={3}
                        placeholder="Observaciones..."
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                     />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>

                        {canNotifyCoordinator && <button onClick={handleGmailNotification} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm"><Mail size={16} className="mr-2" /> Notificar Coord.</button>}
                        {canNotifyAuthor && <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm"><Mail size={16} className="mr-2" /> Notificar Analista</button>}

                        {/* Botón Nuevo para Referente/Control */}
                        {canNotifyExternal && (
                            <button 
                                onClick={handleNotifyExternal} 
                                className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium shadow-sm border border-purple-700 transition-colors"
                            >
                                <ExternalLink size={16} className="mr-2" /> 
                                Notificar Referente / Control
                            </button>
                        )}

                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}

                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.length === 0 ? <p className="text-xs text-slate-400 italic">Sin historial registrado.</p> : history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (COORDINADOR) - CON CARGA DE ARCHIVO */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed">
                                        {getCoordinatorRuleHint(doc.state, pendingAction)}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* File Upload Zone */}
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleResponseFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={32} className="mx-auto mb-2" />
                                    <p className="font-medium text-sm">Click para cargar respuesta</p>
                                    <p className="text-xs mt-1 text-slate-400">
                                        Debe cumplir con la nomenclatura de la etapa.
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!isFileValid}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                <Save size={16} />
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6">
                      <p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p>
                      <div className="flex justify-end gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                          <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State (Updated for File Upload)
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    // Priority: State (Virtual Doc) -> ID (Fetch)
    if (location.state?.docData) {
        setDoc(location.state.docData);
        setLoading(false);
        if (!location.state.docData.id.startsWith('virtual-')) {
             loadAuxiliaryData(location.state.docData.id);
        } else {
             const d = location.state.docData;
             if (d.assignees && d.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = d.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  // Helper to find assignees robustly
  const resolveAssignees = (d: Document, hierarchy: FullHierarchy): string[] => {
      let resolvedIds = d.assignees || [];
      const isLegacy = d.authorName.includes('Sistema') || d.authorName.includes('Carga');

      // Si no hay asignados explícitos O es un documento migrado (donde assignments pueden estar desactualizados),
      // buscamos en la Matriz viva.
      if ((resolvedIds.length === 0 || isLegacy) && d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);

           let node: any = null;

           // Búsqueda Profunda Normalizada
           if (hierarchy) {
               for (const projKey of Object.keys(hierarchy)) {
                   if (normalizeHeader(projKey) === targetProject) {
                       const projData = hierarchy[projKey];
                       for (const macroKey of Object.keys(projData)) {
                           const macroData = projData[macroKey];
                           for (const procKey of Object.keys(macroData)) {
                               const nodes = macroData[procKey];
                               const found = nodes.find(n => normalizeHeader(n.name) === targetMicro);
                               if (found) {
                                   node = found;
                                   break;
                               }
                           }
                           if (node) break;
                       }
                   }
                   if (node) break;
               }
           }

           if (node?.assignees && node.assignees.length > 0) resolvedIds = node.assignees;
      }
      return resolvedIds;
  };

  const loadAuxiliaryData = async (docId: string) => {
      try {
          const [h, allUsers, hierarchy] = await Promise.all([
              HistoryService.getHistory(docId),
              UserService.getAll(),
              HierarchyService.getFullHierarchy()
          ]);
          setHistory(h);

          if (doc) {
              const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
              if (coordinator) setCoordinatorEmail(coordinator.email);
              const author = allUsers.find(u => u.id === doc.authorId);
              if (author) setAuthorEmail(author.email);

              const resolvedIds = resolveAssignees(doc, hierarchy);

              if (resolvedIds.length > 0) {
                  const names = resolvedIds
                      .map(aid => allUsers.find(u => u.id === aid)?.name)
                      .filter(n => n) as string[];
                  setAssigneeNames(names);
              }
          }
      } catch (e) {
          console.error("Error loading aux data", e);
      }
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy()
        ]);

        if (d) {
            setDoc(d);
            setHistory(h);

            const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
            if (coordinator) setCoordinatorEmail(coordinator.email);

            const author = allUsers.find(u => u.id === d.authorId);
            if (author) setAuthorEmail(author.email);

            const resolvedIds = resolveAssignees(d, hierarchy);

            if (resolvedIds.length > 0) {
                const names = resolvedIds
                    .map(aid => allUsers.find(u => u.id === aid)?.name)
                    .filter(n => n) as string[];
                setAssigneeNames(names);
            } else {
                setAssigneeNames([]);
            }
        } else {
            setDoc(null);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---
  const handleNewRequest = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const handleDeleteClick = () => {
      setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
      if (!doc) return;
      try {
          setShowDeleteModal(false);
          setLoading(true); 
          await DocumentService.delete(doc.id);
          navigate('/', { replace: true });
      } catch (e: any) {
          console.error("Error eliminando documento:", e);
          alert('Error al eliminar: ' + e.message);
          setLoading(false);
      }
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(null);
          setFileError([]);
          setIsFileValid(false);
          setDetectedVersion('');
          setShowResponseModal(true);
      }
  };

  // --- FILE HANDLING FOR MODAL ---
  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0];
          setResponseFile(f);

          // 1. Base Parse
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);

          if (!result.valido) {
              setFileError(result.errores);
              setIsFileValid(false);
              return;
          }

          // 2. Coordinator Rules Logic
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) {
              setFileError([rules.error || 'Error de validación de versión.']);
              setIsFileValid(false);
              return;
          }

          setIsFileValid(true);
          setFileError([]);
          setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;

      const actionText = pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR';
      const msg = `¿Confirma ${actionText} la solicitud cargando el archivo ${detectedVersion}?`;

      if (window.confirm(msg)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? `Solicitud enviada tras validar archivo.` : `Gestión realizada.`),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  // --- NOTIFICATION HANDLERS ---

  // 1. ANALISTA -> COORDINADOR (NUEVA LÓGICA)
  const handleAnalystNotificationToCoordinator = () => {
    if (!doc || !coordinatorEmail) return;

    // Subject Format
    const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.project} - ${doc.docType || ''} - ${doc.microprocess}`);

    // Body Format
    const bodyRaw = `Estimado,
Para vuestra aprobación, adjunto el Informe:

- ${doc.project}
- ${doc.macroprocess || ''}
- ${doc.process || ''}
- ${doc.microprocess}
- ${doc.docType || ''}
- ${doc.version}

Atento a comentarios
Saludos
${user.name}`;

    const body = encodeURIComponent(bodyRaw);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 2. COORDINADOR -> ANALISTA (FEEDBACK)
  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 3. COORDINADOR -> EXTERNO (REFERENTE / CONTROL)
  const handleNotifyExternal = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.docType || ''} ${doc.microprocess || ''}`);
      const body = encodeURIComponent(
`Estimados,
Para vuestra aprobación, adjunto el Informe ${doc.docType || ''} - ${doc.microprocess || ''} ${doc.version}, 

Atento a comentarios
Saludos

${user.name}`
      );
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  if (!doc) return (
      <div className="p-12 text-center flex flex-col items-center justify-center">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <FileX size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2>
          <p className="text-slate-500 mb-6">El documento que buscas no existe o ha sido eliminado.</p>
          <button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
              Volver al Inicio
          </button>
      </div>
  );

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;

  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;

  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  // Condiciones Botón Coordinador -> Externo
  const canNotifyExternal = (isCoordinatorOrAdmin) && 
                            (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.SENT_TO_CONTROL);

  // Condiciones Botón Analista -> Coordinador
  const analystNotificationStates = [
      DocState.INTERNAL_REVIEW,
      DocState.SENT_TO_REFERENT,
      DocState.SENT_TO_CONTROL
  ];
  const canNotifyCoordinator = isAnalystAssigned && coordinatorEmail && analystNotificationStates.includes(doc.state);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button 
                type="button"
                onClick={handleDeleteClick}
                className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
            >
                <Trash2 size={16} className="mr-1" /> Eliminar
            </button>
        )}
      </div>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div>
                <p className="text-slate-500">Analistas</p>
                {assigneeNames.length > 0 ? (
                    assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-800">{doc.authorName}</p>
                )}
            </div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">

            {!canEdit && (
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
                    <div className="flex">
                        <div className="flex-shrink-0"><Lock size={20} className="text-yellow-400" /></div>
                        <div className="ml-3"><p className="text-sm text-yellow-700">Solo lectura.</p></div>
                    </div>
                </div>
            )}

            {/* Acciones */}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>

                     {/* NUEVA SOLICITUD (Available for Analysts independent of state, unless Approved) */}
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button 
                                onClick={handleNewRequest}
                                className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"
                             >
                                 <PlusCircle size={20} className="mr-2" />
                                 {doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}
                             </button>
                             <p className="text-xs text-center text-slate-500 mt-2">
                                 Crea una nueva solicitud basada en este documento para avanzar a la siguiente etapa.
                             </p>
                         </div>
                     )}

                     <textarea 
                        className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                        rows={3}
                        placeholder="Observaciones..."
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                     />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>

                        {/* Botón Analista -> Coordinador */}
                        {canNotifyCoordinator && (
                            <button 
                                onClick={handleAnalystNotificationToCoordinator} 
                                className="flex items-center px-4 py-2 bg-blue-100 text-blue-700 hover:bg-blue-200 rounded-lg text-sm font-medium border border-blue-200 shadow-sm"
                            >
                                <Mail size={16} className="mr-2" /> Notificar al coordinador
                            </button>
                        )}

                        {/* Botón Coordinador -> Analista */}
                        {canNotifyAuthor && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm">
                                <Mail size={16} className="mr-2" /> Notificar Analista
                            </button>
                        )}

                        {/* Botón Nuevo para Referente/Control */}
                        {canNotifyExternal && (
                            <button 
                                onClick={handleNotifyExternal} 
                                className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium shadow-sm border border-purple-700 transition-colors"
                            >
                                <ExternalLink size={16} className="mr-2" /> 
                                Notificar Referente / Control
                            </button>
                        )}

                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}

                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.length === 0 ? <p className="text-xs text-slate-400 italic">Sin historial registrado.</p> : history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (COORDINADOR) - CON CARGA DE ARCHIVO */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed">
                                        {getCoordinatorRuleHint(doc.state, pendingAction)}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* File Upload Zone */}
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleResponseFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={32} className="mx-auto mb-2" />
                                    <p className="font-medium text-sm">Click para cargar respuesta</p>
                                    <p className="text-xs mt-1 text-slate-400">
                                        Debe cumplir con la nomenclatura de la etapa.
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!isFileValid}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                <Save size={16} />
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6">
                      <p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p>
                      <div className="flex justify-end gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                          <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State (Updated for File Upload)
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    // Priority: State (Virtual Doc) -> ID (Fetch)
    if (location.state?.docData) {
        setDoc(location.state.docData);
        setLoading(false);
        if (!location.state.docData.id.startsWith('virtual-')) {
             loadAuxiliaryData(location.state.docData.id);
        } else {
             const d = location.state.docData;
             if (d.assignees && d.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = d.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  // Helper to find assignees robustly
  const resolveAssignees = (d: Document, hierarchy: FullHierarchy): string[] => {
      let resolvedIds = d.assignees || [];
      const isLegacy = d.authorName.includes('Sistema') || d.authorName.includes('Carga');

      // Si no hay asignados explícitos O es un documento migrado (donde assignments pueden estar desactualizados),
      // buscamos en la Matriz viva.
      if ((resolvedIds.length === 0 || isLegacy) && d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);

           let node: any = null;

           // Búsqueda Profunda Normalizada
           if (hierarchy) {
               for (const projKey of Object.keys(hierarchy)) {
                   if (normalizeHeader(projKey) === targetProject) {
                       const projData = hierarchy[projKey];
                       for (const macroKey of Object.keys(projData)) {
                           const macroData = projData[macroKey];
                           for (const procKey of Object.keys(macroData)) {
                               const nodes = macroData[procKey];
                               const found = nodes.find(n => normalizeHeader(n.name) === targetMicro);
                               if (found) {
                                   node = found;
                                   break;
                               }
                           }
                           if (node) break;
                       }
                   }
                   if (node) break;
               }
           }

           if (node?.assignees && node.assignees.length > 0) resolvedIds = node.assignees;
      }
      return resolvedIds;
  };

  const loadAuxiliaryData = async (docId: string) => {
      try {
          const [h, allUsers, hierarchy] = await Promise.all([
              HistoryService.getHistory(docId),
              UserService.getAll(),
              HierarchyService.getFullHierarchy()
          ]);
          setHistory(h);

          if (doc) {
              const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
              if (coordinator) setCoordinatorEmail(coordinator.email);
              const author = allUsers.find(u => u.id === doc.authorId);
              if (author) setAuthorEmail(author.email);

              const resolvedIds = resolveAssignees(doc, hierarchy);

              if (resolvedIds.length > 0) {
                  const names = resolvedIds
                      .map(aid => allUsers.find(u => u.id === aid)?.name)
                      .filter(n => n) as string[];
                  setAssigneeNames(names);
              }
          }
      } catch (e) {
          console.error("Error loading aux data", e);
      }
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy()
        ]);

        if (d) {
            setDoc(d);
            setHistory(h);

            const coordinator = allUsers.find(u => u.role === UserRole.COORDINATOR);
            if (coordinator) setCoordinatorEmail(coordinator.email);

            const author = allUsers.find(u => u.id === d.authorId);
            if (author) setAuthorEmail(author.email);

            const resolvedIds = resolveAssignees(d, hierarchy);

            if (resolvedIds.length > 0) {
                const names = resolvedIds
                    .map(aid => allUsers.find(u => u.id === aid)?.name)
                    .filter(n => n) as string[];
                setAssigneeNames(names);
            } else {
                setAssigneeNames([]);
            }
        } else {
            setDoc(null);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---
  const handleNewRequest = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const handleDeleteClick = () => {
      setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
      if (!doc) return;
      try {
          setShowDeleteModal(false);
          setLoading(true); 
          await DocumentService.delete(doc.id);
          navigate('/', { replace: true });
      } catch (e: any) {
          console.error("Error eliminando documento:", e);
          alert('Error al eliminar: ' + e.message);
          setLoading(false);
      }
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(null);
          setFileError([]);
          setIsFileValid(false);
          setDetectedVersion('');
          setShowResponseModal(true);
      }
  };

  // --- FILE HANDLING FOR MODAL ---
  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0];
          setResponseFile(f);

          // 1. Base Parse
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);

          if (!result.valido) {
              setFileError(result.errores);
              setIsFileValid(false);
              return;
          }

          // 2. Coordinator Rules Logic
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) {
              setFileError([rules.error || 'Error de validación de versión.']);
              setIsFileValid(false);
              return;
          }

          setIsFileValid(true);
          setFileError([]);
          setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;

      const actionText = pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR';
      const msg = `¿Confirma ${actionText} la solicitud cargando el archivo ${detectedVersion}?`;

      if (window.confirm(msg)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? `Solicitud enviada tras validar archivo.` : `Gestión realizada.`),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  // --- NOTIFICATION HANDLERS ---

  // 1. ANALISTA -> COORDINADOR (NUEVA LÓGICA)
  const handleAnalystNotificationToCoordinator = () => {
    if (!doc) return;

    // Safety check for missing coordinator
    if (!coordinatorEmail) {
        alert("Aviso: No se ha detectado un usuario 'Coordinador' en el sistema.\nPor favor, contacte al administrador para crear este rol.");
        return;
    }

    // Subject Format
    const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.project} - ${doc.docType || ''} - ${doc.microprocess}`);

    // Body Format
    const bodyRaw = `Estimado,
Para vuestra aprobación, adjunto el Informe:

- ${doc.project}
- ${doc.macroprocess || ''}
- ${doc.process || ''}
- ${doc.microprocess}
- ${doc.docType || ''}
- ${doc.version}

Atento a comentarios
Saludos
${user.name}`;

    const body = encodeURIComponent(bodyRaw);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 2. COORDINADOR -> ANALISTA (FEEDBACK)
  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 3. COORDINADOR -> EXTERNO (REFERENTE / CONTROL)
  const handleNotifyExternal = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.docType || ''} ${doc.microprocess || ''}`);
      const body = encodeURIComponent(
`Estimados,
Para vuestra aprobación, adjunto el Informe ${doc.docType || ''} - ${doc.microprocess || ''} ${doc.version}, 

Atento a comentarios
Saludos

${user.name}`
      );
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  if (!doc) return (
      <div className="p-12 text-center flex flex-col items-center justify-center">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <FileX size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2>
          <p className="text-slate-500 mb-6">El documento que buscas no existe o ha sido eliminado.</p>
          <button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
              Volver al Inicio
          </button>
      </div>
  );

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;

  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;

  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  // Condiciones Botón Coordinador -> Externo
  const canNotifyExternal = (isCoordinatorOrAdmin) && 
                            (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.SENT_TO_CONTROL);

  // Condiciones Botón Analista -> Coordinador
  const analystNotificationStates = [
      DocState.INTERNAL_REVIEW,
      DocState.SENT_TO_REFERENT,
      DocState.SENT_TO_CONTROL
  ];
  // Modificación: Permitir visibilidad del botón incluso si no hay coordinador email, para que el usuario sepa que la funcionalidad existe
  const canNotifyCoordinator = isAnalystAssigned && analystNotificationStates.includes(doc.state);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button 
                type="button"
                onClick={handleDeleteClick}
                className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
            >
                <Trash2 size={16} className="mr-1" /> Eliminar
            </button>
        )}
      </div>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div>
                <p className="text-slate-500">Analistas</p>
                {assigneeNames.length > 0 ? (
                    assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-800">{doc.authorName}</p>
                )}
            </div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">

            {!canEdit && (
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
                    <div className="flex">
                        <div className="flex-shrink-0"><Lock size={20} className="text-yellow-400" /></div>
                        <div className="ml-3"><p className="text-sm text-yellow-700">Solo lectura.</p></div>
                    </div>
                </div>
            )}

            {/* Acciones */}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>

                     {/* NUEVA SOLICITUD (Available for Analysts independent of state, unless Approved) */}
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button 
                                onClick={handleNewRequest}
                                className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"
                             >
                                 <PlusCircle size={20} className="mr-2" />
                                 {doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}
                             </button>
                             <p className="text-xs text-center text-slate-500 mt-2">
                                 Crea una nueva solicitud basada en este documento para avanzar a la siguiente etapa.
                             </p>
                         </div>
                     )}

                     <textarea 
                        className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                        rows={3}
                        placeholder="Observaciones..."
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                     />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>

                        {/* Botón Analista -> Coordinador */}
                        {canNotifyCoordinator && (
                            <button 
                                onClick={handleAnalystNotificationToCoordinator} 
                                className="flex items-center px-4 py-2 bg-blue-100 text-blue-700 hover:bg-blue-200 rounded-lg text-sm font-medium border border-blue-200 shadow-sm"
                            >
                                <Mail size={16} className="mr-2" /> Notificar al coordinador
                            </button>
                        )}

                        {/* Botón Coordinador -> Analista */}
                        {canNotifyAuthor && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm">
                                <Mail size={16} className="mr-2" /> Notificar Analista
                            </button>
                        )}

                        {/* Botón Nuevo para Referente/Control */}
                        {canNotifyExternal && (
                            <button 
                                onClick={handleNotifyExternal} 
                                className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium shadow-sm border border-purple-700 transition-colors"
                            >
                                <ExternalLink size={16} className="mr-2" /> 
                                Notificar Referente / Control
                            </button>
                        )}

                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}

                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.length === 0 ? <p className="text-xs text-slate-400 italic">Sin historial registrado.</p> : history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (COORDINADOR) - CON CARGA DE ARCHIVO */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed">
                                        {getCoordinatorRuleHint(doc.state, pendingAction)}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* File Upload Zone */}
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleResponseFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={32} className="mx-auto mb-2" />
                                    <p className="font-medium text-sm">Click para cargar respuesta</p>
                                    <p className="text-xs mt-1 text-slate-400">
                                        Debe cumplir con la nomenclatura de la etapa.
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!isFileValid}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                <Save size={16} />
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6">
                      <p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p>
                      <div className="flex justify-end gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                          <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State (Updated for File Upload)
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    // Priority: State (Virtual Doc) -> ID (Fetch)
    if (location.state?.docData) {
        setDoc(location.state.docData);
        setLoading(false);
        if (!location.state.docData.id.startsWith('virtual-')) {
             loadAuxiliaryData(location.state.docData.id);
        } else {
             const d = location.state.docData;
             if (d.assignees && d.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = d.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  // Helper to find assignees robustly
  const resolveAssignees = (d: Document, hierarchy: FullHierarchy): string[] => {
      let resolvedIds = d.assignees || [];
      const isLegacy = d.authorName.includes('Sistema') || d.authorName.includes('Carga');

      // Si no hay asignados explícitos O es un documento migrado (donde assignments pueden estar desactualizados),
      // buscamos en la Matriz viva.
      if ((resolvedIds.length === 0 || isLegacy) && d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);

           let node: any = null;

           // Búsqueda Profunda Normalizada
           if (hierarchy) {
               for (const projKey of Object.keys(hierarchy)) {
                   if (normalizeHeader(projKey) === targetProject) {
                       const projData = hierarchy[projKey];
                       for (const macroKey of Object.keys(projData)) {
                           const macroData = projData[macroKey];
                           for (const procKey of Object.keys(macroData)) {
                               const nodes = macroData[procKey];
                               const found = nodes.find(n => normalizeHeader(n.name) === targetMicro);
                               if (found) {
                                   node = found;
                                   break;
                               }
                           }
                           if (node) break;
                       }
                   }
                   if (node) break;
               }
           }

           if (node?.assignees && node.assignees.length > 0) resolvedIds = node.assignees;
      }
      return resolvedIds;
  };

  // Helper function to find coordinator robustly (Case Insensitive)
  const findCoordinator = (users: User[]) => {
      return users.find(u => {
          const role = (u.role || '').toString().toUpperCase();
          return role === 'COORDINATOR' || role === 'COORDINADOR';
      });
  };

  const loadAuxiliaryData = async (docId: string) => {
      try {
          const [h, allUsers, hierarchy] = await Promise.all([
              HistoryService.getHistory(docId),
              UserService.getAll(),
              HierarchyService.getFullHierarchy()
          ]);
          setHistory(h);

          if (doc) {
              const coordinator = findCoordinator(allUsers);
              if (coordinator) setCoordinatorEmail(coordinator.email);

              const author = allUsers.find(u => u.id === doc.authorId);
              if (author) setAuthorEmail(author.email);

              const resolvedIds = resolveAssignees(doc, hierarchy);

              if (resolvedIds.length > 0) {
                  const names = resolvedIds
                      .map(aid => allUsers.find(u => u.id === aid)?.name)
                      .filter(n => n) as string[];
                  setAssigneeNames(names);
              }
          }
      } catch (e) {
          console.error("Error loading aux data", e);
      }
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy()
        ]);

        if (d) {
            setDoc(d);
            setHistory(h);

            const coordinator = findCoordinator(allUsers);
            if (coordinator) setCoordinatorEmail(coordinator.email);

            const author = allUsers.find(u => u.id === d.authorId);
            if (author) setAuthorEmail(author.email);

            const resolvedIds = resolveAssignees(d, hierarchy);

            if (resolvedIds.length > 0) {
                const names = resolvedIds
                    .map(aid => allUsers.find(u => u.id === aid)?.name)
                    .filter(n => n) as string[];
                setAssigneeNames(names);
            } else {
                setAssigneeNames([]);
            }
        } else {
            setDoc(null);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---
  const handleNewRequest = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const handleDeleteClick = () => {
      setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
      if (!doc) return;
      try {
          setShowDeleteModal(false);
          setLoading(true); 
          await DocumentService.delete(doc.id);
          navigate('/', { replace: true });
      } catch (e: any) {
          console.error("Error eliminando documento:", e);
          alert('Error al eliminar: ' + e.message);
          setLoading(false);
      }
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(null);
          setFileError([]);
          setIsFileValid(false);
          setDetectedVersion('');
          setShowResponseModal(true);
      }
  };

  // --- FILE HANDLING FOR MODAL ---
  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0];
          setResponseFile(f);

          // 1. Base Parse
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);

          if (!result.valido) {
              setFileError(result.errores);
              setIsFileValid(false);
              return;
          }

          // 2. Coordinator Rules Logic
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) {
              setFileError([rules.error || 'Error de validación de versión.']);
              setIsFileValid(false);
              return;
          }

          setIsFileValid(true);
          setFileError([]);
          setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;

      const actionText = pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR';
      const msg = `¿Confirma ${actionText} la solicitud cargando el archivo ${detectedVersion}?`;

      if (window.confirm(msg)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? `Solicitud enviada tras validar archivo.` : `Gestión realizada.`),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  // --- NOTIFICATION HANDLERS ---

  // 1. ANALISTA -> COORDINADOR (NUEVA LÓGICA)
  const handleAnalystNotificationToCoordinator = () => {
    if (!doc) return;

    // Safety check for missing coordinator
    if (!coordinatorEmail) {
        alert("Aviso: No se ha detectado un usuario 'Coordinador' en el sistema.\nPor favor, contacte al administrador para crear este rol.");
        return;
    }

    // Subject Format
    const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.project} - ${doc.docType || ''} - ${doc.microprocess}`);

    // Body Format
    const bodyRaw = `Estimado,
Para vuestra aprobación, adjunto el Informe:

- ${doc.project}
- ${doc.macroprocess || ''}
- ${doc.process || ''}
- ${doc.microprocess}
- ${doc.docType || ''}
- ${doc.version}

Atento a comentarios
Saludos
${user.name}`;

    const body = encodeURIComponent(bodyRaw);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 2. COORDINADOR -> ANALISTA (FEEDBACK)
  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 3. COORDINADOR -> EXTERNO (REFERENTE / CONTROL)
  const handleNotifyExternal = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.docType || ''} ${doc.microprocess || ''}`);
      const body = encodeURIComponent(
`Estimados,
Para vuestra aprobación, adjunto el Informe ${doc.docType || ''} - ${doc.microprocess || ''} ${doc.version}, 

Atento a comentarios
Saludos

${user.name}`
      );
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  if (!doc) return (
      <div className="p-12 text-center flex flex-col items-center justify-center">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <FileX size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2>
          <p className="text-slate-500 mb-6">El documento que buscas no existe o ha sido eliminado.</p>
          <button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
              Volver al Inicio
          </button>
      </div>
  );

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;

  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;

  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  // Condiciones Botón Coordinador -> Externo
  const canNotifyExternal = (isCoordinatorOrAdmin) && 
                            (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.SENT_TO_CONTROL);

  // Condiciones Botón Analista -> Coordinador
  const analystNotificationStates = [
      DocState.INTERNAL_REVIEW,
      DocState.SENT_TO_REFERENT,
      DocState.SENT_TO_CONTROL
  ];
  // Modificación: Permitir visibilidad del botón incluso si no hay coordinador email
  const canNotifyCoordinator = isAnalystAssigned && analystNotificationStates.includes(doc.state);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button 
                type="button"
                onClick={handleDeleteClick}
                className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
            >
                <Trash2 size={16} className="mr-1" /> Eliminar
            </button>
        )}
      </div>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div>
                <p className="text-slate-500">Analistas</p>
                {assigneeNames.length > 0 ? (
                    assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-800">{doc.authorName}</p>
                )}
            </div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">

            {!canEdit && (
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
                    <div className="flex">
                        <div className="flex-shrink-0"><Lock size={20} className="text-yellow-400" /></div>
                        <div className="ml-3"><p className="text-sm text-yellow-700">Solo lectura.</p></div>
                    </div>
                </div>
            )}

            {/* Acciones */}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>

                     {/* NUEVA SOLICITUD (Available for Analysts independent of state, unless Approved) */}
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button 
                                onClick={handleNewRequest}
                                className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"
                             >
                                 <PlusCircle size={20} className="mr-2" />
                                 {doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}
                             </button>
                             <p className="text-xs text-center text-slate-500 mt-2">
                                 Crea una nueva solicitud basada en este documento para avanzar a la siguiente etapa.
                             </p>
                         </div>
                     )}

                     <textarea 
                        className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                        rows={3}
                        placeholder="Observaciones..."
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                     />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>

                        {/* Botón Analista -> Coordinador */}
                        {canNotifyCoordinator && (
                            <button 
                                onClick={handleAnalystNotificationToCoordinator} 
                                className="flex items-center px-4 py-2 bg-blue-100 text-blue-700 hover:bg-blue-200 rounded-lg text-sm font-medium border border-blue-200 shadow-sm"
                            >
                                <Mail size={16} className="mr-2" /> Notificar al coordinador
                            </button>
                        )}

                        {/* Botón Coordinador -> Analista */}
                        {canNotifyAuthor && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm">
                                <Mail size={16} className="mr-2" /> Notificar Analista
                            </button>
                        )}

                        {/* Botón Nuevo para Referente/Control */}
                        {canNotifyExternal && (
                            <button 
                                onClick={handleNotifyExternal} 
                                className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium shadow-sm border border-purple-700 transition-colors"
                            >
                                <ExternalLink size={16} className="mr-2" /> 
                                Notificar Referente / Control
                            </button>
                        )}

                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}

                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.length === 0 ? <p className="text-xs text-slate-400 italic">Sin historial registrado.</p> : history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (COORDINADOR) - CON CARGA DE ARCHIVO */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed">
                                        {getCoordinatorRuleHint(doc.state, pendingAction)}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* File Upload Zone */}
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleResponseFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={32} className="mx-auto mb-2" />
                                    <p className="font-medium text-sm">Click para cargar respuesta</p>
                                    <p className="text-xs mt-1 text-slate-400">
                                        Debe cumplir con la nomenclatura de la etapa.
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!isFileValid}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                <Save size={16} />
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6">
                      <p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p>
                      <div className="flex justify-end gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                          <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State (Updated for File Upload)
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    // Priority: State (Virtual Doc) -> ID (Fetch)
    if (location.state?.docData) {
        setDoc(location.state.docData);
        setLoading(false);
        if (!location.state.docData.id.startsWith('virtual-')) {
             loadAuxiliaryData(location.state.docData.id);
        } else {
             const d = location.state.docData;
             if (d.assignees && d.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = d.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  // Helper to find assignees robustly
  const resolveAssignees = (d: Document, hierarchy: FullHierarchy): string[] => {
      let resolvedIds = d.assignees || [];
      const isLegacy = d.authorName.includes('Sistema') || d.authorName.includes('Carga');

      // Si no hay asignados explícitos O es un documento migrado (donde assignments pueden estar desactualizados),
      // buscamos en la Matriz viva.
      if ((resolvedIds.length === 0 || isLegacy) && d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);

           let node: any = null;

           // Búsqueda Profunda Normalizada
           if (hierarchy) {
               for (const projKey of Object.keys(hierarchy)) {
                   if (normalizeHeader(projKey) === targetProject) {
                       const projData = hierarchy[projKey];
                       for (const macroKey of Object.keys(projData)) {
                           const macroData = projData[macroKey];
                           for (const procKey of Object.keys(macroData)) {
                               const nodes = macroData[procKey];
                               const found = nodes.find(n => normalizeHeader(n.name) === targetMicro);
                               if (found) {
                                   node = found;
                                   break;
                               }
                           }
                           if (node) break;
                       }
                   }
                   if (node) break;
               }
           }

           if (node?.assignees && node.assignees.length > 0) resolvedIds = node.assignees;
      }
      return resolvedIds;
  };

  // Helper function to find coordinator robustly (Case Insensitive)
  // UPDATED: Now falls back to ADMIN if no COORDINATOR is found.
  const findCoordinator = (users: User[]) => {
      // 1. Priority: Explicit Coordinator
      const coord = users.find(u => {
          const role = (u.role || '').toString().toUpperCase();
          return role === 'COORDINATOR' || role === 'COORDINADOR';
      });
      if (coord) return coord;

      // 2. Fallback: Admin (Admins act as super-coordinators)
      const admin = users.find(u => {
          const role = (u.role || '').toString().toUpperCase();
          return role === 'ADMIN' || role === 'ADMINISTRADOR';
      });
      return admin;
  };

  const loadAuxiliaryData = async (docId: string) => {
      try {
          const [h, allUsers, hierarchy] = await Promise.all([
              HistoryService.getHistory(docId),
              UserService.getAll(),
              HierarchyService.getFullHierarchy()
          ]);
          setHistory(h);

          if (doc) {
              const coordinator = findCoordinator(allUsers);
              if (coordinator) setCoordinatorEmail(coordinator.email);

              const author = allUsers.find(u => u.id === doc.authorId);
              if (author) setAuthorEmail(author.email);

              const resolvedIds = resolveAssignees(doc, hierarchy);

              if (resolvedIds.length > 0) {
                  const names = resolvedIds
                      .map(aid => allUsers.find(u => u.id === aid)?.name)
                      .filter(n => n) as string[];
                  setAssigneeNames(names);
              }
          }
      } catch (e) {
          console.error("Error loading aux data", e);
      }
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy()
        ]);

        if (d) {
            setDoc(d);
            setHistory(h);

            const coordinator = findCoordinator(allUsers);
            if (coordinator) setCoordinatorEmail(coordinator.email);

            const author = allUsers.find(u => u.id === d.authorId);
            if (author) setAuthorEmail(author.email);

            const resolvedIds = resolveAssignees(d, hierarchy);

            if (resolvedIds.length > 0) {
                const names = resolvedIds
                    .map(aid => allUsers.find(u => u.id === aid)?.name)
                    .filter(n => n) as string[];
                setAssigneeNames(names);
            } else {
                setAssigneeNames([]);
            }
        } else {
            setDoc(null);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---
  const handleNewRequest = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const handleDeleteClick = () => {
      setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
      if (!doc) return;
      try {
          setShowDeleteModal(false);
          setLoading(true); 
          await DocumentService.delete(doc.id);
          navigate('/', { replace: true });
      } catch (e: any) {
          console.error("Error eliminando documento:", e);
          alert('Error al eliminar: ' + e.message);
          setLoading(false);
      }
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(null);
          setFileError([]);
          setIsFileValid(false);
          setDetectedVersion('');
          setShowResponseModal(true);
      }
  };

  // --- FILE HANDLING FOR MODAL ---
  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0];
          setResponseFile(f);

          // 1. Base Parse
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);

          if (!result.valido) {
              setFileError(result.errores);
              setIsFileValid(false);
              return;
          }

          // 2. Coordinator Rules Logic
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) {
              setFileError([rules.error || 'Error de validación de versión.']);
              setIsFileValid(false);
              return;
          }

          setIsFileValid(true);
          setFileError([]);
          setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;

      const actionText = pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR';
      const msg = `¿Confirma ${actionText} la solicitud cargando el archivo ${detectedVersion}?`;

      if (window.confirm(msg)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? `Solicitud enviada tras validar archivo.` : `Gestión realizada.`),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  // --- NOTIFICATION HANDLERS ---

  // 1. ANALISTA -> COORDINADOR (NUEVA LÓGICA)
  const handleAnalystNotificationToCoordinator = () => {
    if (!doc) return;

    // Safety check for missing coordinator
    if (!coordinatorEmail) {
        alert("Aviso: No se ha detectado un usuario con rol 'Coordinador' ni 'Administrador' en el sistema.\nPor favor, contacte al administrador.");
        return;
    }

    // Subject Format
    const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.project} - ${doc.docType || ''} - ${doc.microprocess}`);

    // Body Format
    const bodyRaw = `Estimado,
Para vuestra aprobación, adjunto el Informe:

- ${doc.project}
- ${doc.macroprocess || ''}
- ${doc.process || ''}
- ${doc.microprocess}
- ${doc.docType || ''}
- ${doc.version}

Atento a comentarios
Saludos
${user.name}`;

    const body = encodeURIComponent(bodyRaw);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 2. COORDINADOR -> ANALISTA (FEEDBACK)
  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 3. COORDINADOR -> EXTERNO (REFERENTE / CONTROL)
  const handleNotifyExternal = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.docType || ''} ${doc.microprocess || ''}`);
      const body = encodeURIComponent(
`Estimados,
Para vuestra aprobación, adjunto el Informe ${doc.docType || ''} - ${doc.microprocess || ''} ${doc.version}, 

Atento a comentarios
Saludos

${user.name}`
      );
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  if (!doc) return (
      <div className="p-12 text-center flex flex-col items-center justify-center">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <FileX size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2>
          <p className="text-slate-500 mb-6">El documento que buscas no existe o ha sido eliminado.</p>
          <button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
              Volver al Inicio
          </button>
      </div>
  );

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;

  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;

  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  // Condiciones Botón Coordinador -> Externo
  const canNotifyExternal = (isCoordinatorOrAdmin) && 
                            (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.SENT_TO_CONTROL);

  // Condiciones Botón Analista -> Coordinador
  const analystNotificationStates = [
      DocState.INTERNAL_REVIEW,
      DocState.SENT_TO_REFERENT,
      DocState.SENT_TO_CONTROL
  ];
  // Modificación: Permitir visibilidad del botón incluso si no hay coordinador email
  const canNotifyCoordinator = isAnalystAssigned && analystNotificationStates.includes(doc.state);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button 
                type="button"
                onClick={handleDeleteClick}
                className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
            >
                <Trash2 size={16} className="mr-1" /> Eliminar
            </button>
        )}
      </div>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div>
                <p className="text-slate-500">Analistas</p>
                {assigneeNames.length > 0 ? (
                    assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-800">{doc.authorName}</p>
                )}
            </div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">

            {!canEdit && (
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
                    <div className="flex">
                        <div className="flex-shrink-0"><Lock size={20} className="text-yellow-400" /></div>
                        <div className="ml-3"><p className="text-sm text-yellow-700">Solo lectura.</p></div>
                    </div>
                </div>
            )}

            {/* Acciones */}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>

                     {/* NUEVA SOLICITUD (Available for Analysts independent of state, unless Approved) */}
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button 
                                onClick={handleNewRequest}
                                className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"
                             >
                                 <PlusCircle size={20} className="mr-2" />
                                 {doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}
                             </button>
                             <p className="text-xs text-center text-slate-500 mt-2">
                                 Crea una nueva solicitud basada en este documento para avanzar a la siguiente etapa.
                             </p>
                         </div>
                     )}

                     <textarea 
                        className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                        rows={3}
                        placeholder="Observaciones..."
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                     />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>

                        {/* Botón Analista -> Coordinador */}
                        {canNotifyCoordinator && (
                            <button 
                                onClick={handleAnalystNotificationToCoordinator} 
                                className="flex items-center px-4 py-2 bg-blue-100 text-blue-700 hover:bg-blue-200 rounded-lg text-sm font-medium border border-blue-200 shadow-sm"
                            >
                                <Mail size={16} className="mr-2" /> Notificar al coordinador
                            </button>
                        )}

                        {/* Botón Coordinador -> Analista */}
                        {canNotifyAuthor && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm">
                                <Mail size={16} className="mr-2" /> Notificar Analista
                            </button>
                        )}

                        {/* Botón Nuevo para Referente/Control */}
                        {canNotifyExternal && (
                            <button 
                                onClick={handleNotifyExternal} 
                                className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium shadow-sm border border-purple-700 transition-colors"
                            >
                                <ExternalLink size={16} className="mr-2" /> 
                                Notificar Referente / Control
                            </button>
                        )}

                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}

                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.length === 0 ? <p className="text-xs text-slate-400 italic">Sin historial registrado.</p> : history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (COORDINADOR) - CON CARGA DE ARCHIVO */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed">
                                        {getCoordinatorRuleHint(doc.state, pendingAction)}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* File Upload Zone */}
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleResponseFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={32} className="mx-auto mb-2" />
                                    <p className="font-medium text-sm">Click para cargar respuesta</p>
                                    <p className="text-xs mt-1 text-slate-400">
                                        Debe cumplir con la nomenclatura de la etapa.
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!isFileValid}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                <Save size={16} />
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6">
                      <p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p>
                      <div className="flex justify-end gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                          <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State (Updated for File Upload)
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    // Priority: State (Virtual Doc) -> ID (Fetch)
    if (location.state?.docData) {
        setDoc(location.state.docData);
        setLoading(false);
        if (!location.state.docData.id.startsWith('virtual-')) {
             loadAuxiliaryData(location.state.docData.id);
        } else {
             const d = location.state.docData;
             if (d.assignees && d.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = d.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  // Helper to find assignees robustly
  const resolveAssignees = (d: Document, hierarchy: FullHierarchy): string[] => {
      let resolvedIds = d.assignees || [];
      const isLegacy = d.authorName.includes('Sistema') || d.authorName.includes('Carga');

      // Si no hay asignados explícitos O es un documento migrado (donde assignments pueden estar desactualizados),
      // buscamos en la Matriz viva.
      if ((resolvedIds.length === 0 || isLegacy) && d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);

           let node: any = null;

           // Búsqueda Profunda Normalizada
           if (hierarchy) {
               for (const projKey of Object.keys(hierarchy)) {
                   if (normalizeHeader(projKey) === targetProject) {
                       const projData = hierarchy[projKey];
                       for (const macroKey of Object.keys(projData)) {
                           const macroData = projData[macroKey];
                           for (const procKey of Object.keys(macroData)) {
                               const nodes = macroData[procKey];
                               const found = nodes.find(n => normalizeHeader(n.name) === targetMicro);
                               if (found) {
                                   node = found;
                                   break;
                               }
                           }
                           if (node) break;
                       }
                   }
                   if (node) break;
               }
           }

           if (node?.assignees && node.assignees.length > 0) resolvedIds = node.assignees;
      }
      return resolvedIds;
  };

  // Helper function to find coordinator robustly (Case Insensitive)
  // UPDATED: Now falls back to ADMIN if no COORDINATOR is found.
  const findCoordinator = (users: User[]) => {
      // 1. Priority: Explicit Coordinator
      const coord = users.find(u => {
          const role = (u.role || '').toString().toUpperCase();
          return role === 'COORDINATOR' || role === 'COORDINADOR';
      });
      if (coord) return coord;

      // 2. Fallback: Admin (Admins act as super-coordinators)
      const admin = users.find(u => {
          const role = (u.role || '').toString().toUpperCase();
          return role === 'ADMIN' || role === 'ADMINISTRADOR';
      });
      return admin;
  };

  const loadAuxiliaryData = async (docId: string) => {
      try {
          const [h, allUsers, hierarchy] = await Promise.all([
              HistoryService.getHistory(docId),
              UserService.getAll(),
              HierarchyService.getFullHierarchy()
          ]);
          setHistory(h);

          // DIAGNÓSTICO: Imprimir usuarios en consola para ver qué roles existen realmente
          console.group("SGD Debug: Carga Auxiliar");
          console.log("Usuarios cargados:", allUsers.length);
          allUsers.forEach(u => console.log(`Usuario: ${u.name} | Rol: "${u.role}" | Email: ${u.email}`));
          console.groupEnd();

          if (doc) {
              const coordinator = findCoordinator(allUsers);
              if (coordinator) {
                  console.log("Coordinador detectado:", coordinator.name);
                  setCoordinatorEmail(coordinator.email);
              } else {
                  console.warn("ADVERTENCIA: No se encontró ningún usuario con rol COORDINATOR ni ADMIN.");
              }

              const author = allUsers.find(u => u.id === doc.authorId);
              if (author) setAuthorEmail(author.email);

              const resolvedIds = resolveAssignees(doc, hierarchy);

              if (resolvedIds.length > 0) {
                  const names = resolvedIds
                      .map(aid => allUsers.find(u => u.id === aid)?.name)
                      .filter(n => n) as string[];
                  setAssigneeNames(names);
              }
          }
      } catch (e) {
          console.error("Error loading aux data", e);
      }
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy()
        ]);

        // DIAGNÓSTICO: Imprimir usuarios en consola para ver qué roles existen realmente
        console.group("SGD Debug: Carga Principal");
        console.log("Usuarios cargados:", allUsers.length);
        allUsers.forEach(u => console.log(`Usuario: ${u.name} | Rol: "${u.role}" | Email: ${u.email}`));
        console.groupEnd();

        if (d) {
            setDoc(d);
            setHistory(h);

            const coordinator = findCoordinator(allUsers);
            if (coordinator) {
                console.log("Coordinador detectado:", coordinator.name);
                setCoordinatorEmail(coordinator.email);
            } else {
                console.warn("ADVERTENCIA: No se encontró ningún usuario con rol COORDINATOR ni ADMIN.");
            }

            const author = allUsers.find(u => u.id === d.authorId);
            if (author) setAuthorEmail(author.email);

            const resolvedIds = resolveAssignees(d, hierarchy);

            if (resolvedIds.length > 0) {
                const names = resolvedIds
                    .map(aid => allUsers.find(u => u.id === aid)?.name)
                    .filter(n => n) as string[];
                setAssigneeNames(names);
            } else {
                setAssigneeNames([]);
            }
        } else {
            setDoc(null);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---
  const handleNewRequest = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const handleDeleteClick = () => {
      setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
      if (!doc) return;
      try {
          setShowDeleteModal(false);
          setLoading(true); 
          await DocumentService.delete(doc.id);
          navigate('/', { replace: true });
      } catch (e: any) {
          console.error("Error eliminando documento:", e);
          alert('Error al eliminar: ' + e.message);
          setLoading(false);
      }
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(null);
          setFileError([]);
          setIsFileValid(false);
          setDetectedVersion('');
          setShowResponseModal(true);
      }
  };

  // --- FILE HANDLING FOR MODAL ---
  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0];
          setResponseFile(f);

          // 1. Base Parse
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);

          if (!result.valido) {
              setFileError(result.errores);
              setIsFileValid(false);
              return;
          }

          // 2. Coordinator Rules Logic
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) {
              setFileError([rules.error || 'Error de validación de versión.']);
              setIsFileValid(false);
              return;
          }

          setIsFileValid(true);
          setFileError([]);
          setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;

      const actionText = pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR';
      const msg = `¿Confirma ${actionText} la solicitud cargando el archivo ${detectedVersion}?`;

      if (window.confirm(msg)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? `Solicitud enviada tras validar archivo.` : `Gestión realizada.`),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  // --- NOTIFICATION HANDLERS ---

  // 1. ANALISTA -> COORDINADOR (NUEVA LÓGICA)
  const handleAnalystNotificationToCoordinator = () => {
    if (!doc) return;

    // Safety check for missing coordinator
    if (!coordinatorEmail) {
        alert("Aviso: No se ha detectado un usuario con rol 'Coordinador' ni 'Administrador' en el sistema.\n\nPor favor, presione F12 y revise la Consola para ver detalles de los usuarios cargados y sus roles.");
        return;
    }

    // Subject Format
    const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.project} - ${doc.docType || ''} - ${doc.microprocess}`);

    // Body Format
    const bodyRaw = `Estimado,
Para vuestra aprobación, adjunto el Informe:

- ${doc.project}
- ${doc.macroprocess || ''}
- ${doc.process || ''}
- ${doc.microprocess}
- ${doc.docType || ''}
- ${doc.version}

Atento a comentarios
Saludos
${user.name}`;

    const body = encodeURIComponent(bodyRaw);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 2. COORDINADOR -> ANALISTA (FEEDBACK)
  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 3. COORDINADOR -> EXTERNO (REFERENTE / CONTROL)
  const handleNotifyExternal = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.docType || ''} ${doc.microprocess || ''}`);
      const body = encodeURIComponent(
`Estimados,
Para vuestra aprobación, adjunto el Informe ${doc.docType || ''} - ${doc.microprocess || ''} ${doc.version}, 

Atento a comentarios
Saludos

${user.name}`
      );
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  if (!doc) return (
      <div className="p-12 text-center flex flex-col items-center justify-center">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <FileX size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2>
          <p className="text-slate-500 mb-6">El documento que buscas no existe o ha sido eliminado.</p>
          <button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
              Volver al Inicio
          </button>
      </div>
  );

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;

  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;

  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  // Condiciones Botón Coordinador -> Externo
  const canNotifyExternal = (isCoordinatorOrAdmin) && 
                            (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.SENT_TO_CONTROL);

  // Condiciones Botón Analista -> Coordinador
  const analystNotificationStates = [
      DocState.INTERNAL_REVIEW,
      DocState.SENT_TO_REFERENT,
      DocState.SENT_TO_CONTROL
  ];
  // Modificación: Permitir visibilidad del botón incluso si no hay coordinador email
  const canNotifyCoordinator = isAnalystAssigned && analystNotificationStates.includes(doc.state);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button 
                type="button"
                onClick={handleDeleteClick}
                className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
            >
                <Trash2 size={16} className="mr-1" /> Eliminar
            </button>
        )}
      </div>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div>
                <p className="text-slate-500">Analistas</p>
                {assigneeNames.length > 0 ? (
                    assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-800">{doc.authorName}</p>
                )}
            </div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">

            {!canEdit && (
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
                    <div className="flex">
                        <div className="flex-shrink-0"><Lock size={20} className="text-yellow-400" /></div>
                        <div className="ml-3"><p className="text-sm text-yellow-700">Solo lectura.</p></div>
                    </div>
                </div>
            )}

            {/* Acciones */}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>

                     {/* NUEVA SOLICITUD (Available for Analysts independent of state, unless Approved) */}
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button 
                                onClick={handleNewRequest}
                                className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"
                             >
                                 <PlusCircle size={20} className="mr-2" />
                                 {doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}
                             </button>
                             <p className="text-xs text-center text-slate-500 mt-2">
                                 Crea una nueva solicitud basada en este documento para avanzar a la siguiente etapa.
                             </p>
                         </div>
                     )}

                     <textarea 
                        className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                        rows={3}
                        placeholder="Observaciones..."
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                     />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>

                        {/* Botón Analista -> Coordinador */}
                        {canNotifyCoordinator && (
                            <button 
                                onClick={handleAnalystNotificationToCoordinator} 
                                className="flex items-center px-4 py-2 bg-blue-100 text-blue-700 hover:bg-blue-200 rounded-lg text-sm font-medium border border-blue-200 shadow-sm"
                            >
                                <Mail size={16} className="mr-2" /> Notificar al coordinador
                            </button>
                        )}

                        {/* Botón Coordinador -> Analista */}
                        {canNotifyAuthor && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm">
                                <Mail size={16} className="mr-2" /> Notificar Analista
                            </button>
                        )}

                        {/* Botón Nuevo para Referente/Control */}
                        {canNotifyExternal && (
                            <button 
                                onClick={handleNotifyExternal} 
                                className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium shadow-sm border border-purple-700 transition-colors"
                            >
                                <ExternalLink size={16} className="mr-2" /> 
                                Notificar Referente / Control
                            </button>
                        )}

                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}

                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.length === 0 ? <p className="text-xs text-slate-400 italic">Sin historial registrado.</p> : history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (COORDINADOR) - CON CARGA DE ARCHIVO */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed">
                                        {getCoordinatorRuleHint(doc.state, pendingAction)}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* File Upload Zone */}
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleResponseFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={32} className="mx-auto mb-2" />
                                    <p className="font-medium text-sm">Click para cargar respuesta</p>
                                    <p className="text-xs mt-1 text-slate-400">
                                        Debe cumplir con la nomenclatura de la etapa.
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!isFileValid}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                <Save size={16} />
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6">
                      <p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p>
                      <div className="flex justify-end gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                          <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink } from 'lucide-react';

interface Props {
  user: User;
}

type ApprovalContext = 'INTERNAL' | 'REFERENT' | 'CONTROL';

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State (Updated for File Upload)
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    // Priority: State (Virtual Doc) -> ID (Fetch)
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        setLoading(false);
        if (!passedDoc.id.startsWith('virtual-')) {
             // PASS passedDoc explicitly to avoid stale state closure
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  // Helper to find assignees robustly
  const resolveAssignees = (d: Document, hierarchy: FullHierarchy): string[] => {
      let resolvedIds = d.assignees || [];
      const isLegacy = d.authorName.includes('Sistema') || d.authorName.includes('Carga');

      // Si no hay asignados explícitos O es un documento migrado (donde assignments pueden estar desactualizados),
      // buscamos en la Matriz viva.
      if ((resolvedIds.length === 0 || isLegacy) && d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);

           let node: any = null;

           // Búsqueda Profunda Normalizada
           if (hierarchy) {
               for (const projKey of Object.keys(hierarchy)) {
                   if (normalizeHeader(projKey) === targetProject) {
                       const projData = hierarchy[projKey];
                       for (const macroKey of Object.keys(projData)) {
                           const macroData = projData[macroKey];
                           for (const procKey of Object.keys(macroData)) {
                               const nodes = macroData[procKey];
                               const found = nodes.find(n => normalizeHeader(n.name) === targetMicro);
                               if (found) {
                                   node = found;
                                   break;
                               }
                           }
                           if (node) break;
                       }
                   }
                   if (node) break;
               }
           }

           if (node?.assignees && node.assignees.length > 0) resolvedIds = node.assignees;
      }
      return resolvedIds;
  };

  // Helper function to find coordinator robustly (Case Insensitive)
  // UPDATED: Now falls back to ADMIN if no COORDINATOR is found.
  const findCoordinator = (users: User[]) => {
      // 1. Priority: Explicit Coordinator
      const coord = users.find(u => {
          const role = (u.role || '').toString().toUpperCase();
          return role === 'COORDINATOR' || role === 'COORDINADOR';
      });
      if (coord) return coord;

      // 2. Fallback: Admin (Admins act as super-coordinators)
      const admin = users.find(u => {
          const role = (u.role || '').toString().toUpperCase();
          return role === 'ADMIN' || role === 'ADMINISTRADOR';
      });
      return admin;
  };

  const loadAuxiliaryData = async (docId: string, currentDoc: Document | null) => {
      try {
          const [h, allUsers, hierarchy] = await Promise.all([
              HistoryService.getHistory(docId),
              UserService.getAll(),
              HierarchyService.getFullHierarchy()
          ]);
          setHistory(h);

          // Debug logs preserved
          console.group("SGD Debug: Carga Auxiliar");
          console.log("Usuarios cargados:", allUsers.length);
          allUsers.forEach(u => console.log(`Usuario: ${u.name} | Rol: "${u.role}" | Email: ${u.email}`));
          console.groupEnd();

          // Use the passed document object, fallback to state if not provided (though state might be stale)
          const targetDoc = currentDoc || doc;

          if (targetDoc) {
              const coordinator = findCoordinator(allUsers);
              if (coordinator) {
                  console.log("Coordinador detectado:", coordinator.name);
                  setCoordinatorEmail(coordinator.email);
              } else {
                  console.warn("ADVERTENCIA: No se encontró ningún usuario con rol COORDINATOR ni ADMIN.");
              }

              const author = allUsers.find(u => u.id === targetDoc.authorId);
              if (author) setAuthorEmail(author.email);

              const resolvedIds = resolveAssignees(targetDoc, hierarchy);

              if (resolvedIds.length > 0) {
                  const names = resolvedIds
                      .map(aid => allUsers.find(u => u.id === aid)?.name)
                      .filter(n => n) as string[];
                  setAssigneeNames(names);
              }
          }
      } catch (e) {
          console.error("Error loading aux data", e);
      }
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const [d, h, allUsers, hierarchy] = await Promise.all([
          DocumentService.getById(docId),
          HistoryService.getHistory(docId),
          UserService.getAll(),
          HierarchyService.getFullHierarchy()
        ]);

        // Debug logs preserved
        console.group("SGD Debug: Carga Principal");
        console.log("Usuarios cargados:", allUsers.length);
        allUsers.forEach(u => console.log(`Usuario: ${u.name} | Rol: "${u.role}" | Email: ${u.email}`));
        console.groupEnd();

        if (d) {
            setDoc(d);
            setHistory(h);

            const coordinator = findCoordinator(allUsers);
            if (coordinator) {
                console.log("Coordinador detectado:", coordinator.name);
                setCoordinatorEmail(coordinator.email);
            } else {
                console.warn("ADVERTENCIA: No se encontró ningún usuario con rol COORDINATOR ni ADMIN.");
            }

            const author = allUsers.find(u => u.id === d.authorId);
            if (author) setAuthorEmail(author.email);

            const resolvedIds = resolveAssignees(d, hierarchy);

            if (resolvedIds.length > 0) {
                const names = resolvedIds
                    .map(aid => allUsers.find(u => u.id === aid)?.name)
                    .filter(n => n) as string[];
                setAssigneeNames(names);
            } else {
                setAssigneeNames([]);
            }
        } else {
            setDoc(null);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---
  const handleNewRequest = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const handleDeleteClick = () => {
      setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
      if (!doc) return;
      try {
          setShowDeleteModal(false);
          setLoading(true); 
          await DocumentService.delete(doc.id);
          navigate('/', { replace: true });
      } catch (e: any) {
          console.error("Error eliminando documento:", e);
          alert('Error al eliminar: ' + e.message);
          setLoading(false);
      }
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;

      if (action === 'COMMENT') {
          if (!comment.trim()) {
              alert('Por favor escribe una observación antes de guardar.');
              return;
          }
          executeTransition('COMMENT', null, null);
          return;
      }

      if (action === 'ADVANCE') {
          executeTransition('ADVANCE', null, null);
          return;
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) {
              alert('Por favor agrega un comentario/observación antes de rechazar.');
              return;
          }
          setPendingAction(action);
          setResponseFile(null);
          setFileError([]);
          setIsFileValid(false);
          setDetectedVersion('');
          setShowResponseModal(true);
      }
  };

  // --- FILE HANDLING FOR MODAL ---
  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0];
          setResponseFile(f);

          // 1. Base Parse
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);

          if (!result.valido) {
              setFileError(result.errores);
              setIsFileValid(false);
              return;
          }

          // 2. Coordinator Rules Logic
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) {
              setFileError([rules.error || 'Error de validación de versión.']);
              setIsFileValid(false);
              return;
          }

          setIsFileValid(true);
          setFileError([]);
          setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;

      const actionText = pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR';
      const msg = `¿Confirma ${actionText} la solicitud cargando el archivo ${detectedVersion}?`;

      if (window.confirm(msg)) {
          setShowResponseModal(false);
          await executeTransition(pendingAction, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, file: File | null, customVersion: string | null) => {
      if (!doc) return;
      setActionLoading(true);
      try {
        await DocumentService.transitionState(
            doc.id, user, action, 
            comment || (action === 'REQUEST_APPROVAL' ? `Solicitud enviada tras validar archivo.` : `Gestión realizada.`),
            file || undefined,
            customVersion || undefined
        );
        setComment('');
        await loadData(doc.id);
      } catch (err: any) {
        alert('Error: ' + err.message);
      } finally {
        setActionLoading(false);
      }
  };

  // --- NOTIFICATION HANDLERS ---

  // 1. ANALISTA -> COORDINADOR (NUEVA LÓGICA)
  const handleAnalystNotificationToCoordinator = () => {
    if (!doc) return;

    // Safety check for missing coordinator
    if (!coordinatorEmail) {
        // Fallback: If no email found, try to find one on the fly (Last Resort)
        // This handles cases where state might still be weird
        alert(`Aviso: No se ha detectado un usuario con rol 'Coordinador' ni 'Administrador' en el sistema.

Esto puede deberse a que la lista de usuarios no se cargó correctamente.
Por favor, refresque la página (F5) e intente nuevamente.

Si el error persiste, contacte a soporte.`);
        return;
    }

    // Subject Format
    const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.project} - ${doc.docType || ''} - ${doc.microprocess}`);

    // Body Format
    const bodyRaw = `Estimado,
Para vuestra aprobación, adjunto el Informe:

- ${doc.project}
- ${doc.macroprocess || ''}
- ${doc.process || ''}
- ${doc.microprocess}
- ${doc.docType || ''}
- ${doc.version}

Atento a comentarios
Saludos
${user.name}`;

    const body = encodeURIComponent(bodyRaw);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 2. COORDINADOR -> ANALISTA (FEEDBACK)
  const handleNotifyAnalyst = () => {
      if (!doc || !authorEmail) return;
      const subject = encodeURIComponent(`Respuesta Solicitud SGD: ${doc.project} - ${doc.microprocess}`);
      const body = encodeURIComponent(`Estimado/a ${doc.authorName},\n\nRevisión completada.\nEstado: ${STATE_CONFIG[doc.state].label}\nObservaciones: ${comment}\n\nAtentamente,\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${authorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  // 3. COORDINADOR -> EXTERNO (REFERENTE / CONTROL)
  const handleNotifyExternal = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.docType || ''} ${doc.microprocess || ''}`);
      const body = encodeURIComponent(
`Estimados,
Para vuestra aprobación, adjunto el Informe ${doc.docType || ''} - ${doc.microprocess || ''} ${doc.version}, 

Atento a comentarios
Saludos

${user.name}`
      );
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;

  if (!doc) return (
      <div className="p-12 text-center flex flex-col items-center justify-center">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400">
              <FileX size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2>
          <p className="text-slate-500 mb-6">El documento que buscas no existe o ha sido eliminado.</p>
          <button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
              Volver al Inicio
          </button>
      </div>
  );

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;

  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;

  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyAuthor = isCoordinatorOrAdmin && authorEmail && doc.authorId !== user.id;

  // Condiciones Botón Coordinador -> Externo
  const canNotifyExternal = (isCoordinatorOrAdmin) && 
                            (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.SENT_TO_CONTROL);

  // Condiciones Botón Analista -> Coordinador
  const analystNotificationStates = [
      DocState.INTERNAL_REVIEW,
      DocState.SENT_TO_REFERENT,
      DocState.SENT_TO_CONTROL
  ];
  // Modificación: Permitir visibilidad del botón incluso si no hay coordinador email
  const canNotifyCoordinator = isAnalystAssigned && analystNotificationStates.includes(doc.state);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button 
                type="button"
                onClick={handleDeleteClick}
                className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"
            >
                <Trash2 size={16} className="mr-1" /> Eliminar
            </button>
        )}
      </div>

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}>
                <Activity size={16} className="mr-2" />
                {config.label}
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div>
                <p className="text-slate-500">Analistas</p>
                {assigneeNames.length > 0 ? (
                    assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-800">{doc.authorName}</p>
                )}
            </div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${doc.progress}%` }}></div></div><span className="font-medium">{doc.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">

            {!canEdit && (
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4">
                    <div className="flex">
                        <div className="flex-shrink-0"><Lock size={20} className="text-yellow-400" /></div>
                        <div className="ml-3"><p className="text-sm text-yellow-700">Solo lectura.</p></div>
                    </div>
                </div>
            )}

            {/* Acciones */}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4">Acciones de Flujo</h3>

                     {/* NUEVA SOLICITUD (Available for Analysts independent of state, unless Approved) */}
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button 
                                onClick={handleNewRequest}
                                className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"
                             >
                                 <PlusCircle size={20} className="mr-2" />
                                 {doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}
                             </button>
                             <p className="text-xs text-center text-slate-500 mt-2">
                                 Crea una nueva solicitud basada en este documento para avanzar a la siguiente etapa.
                             </p>
                         </div>
                     )}

                     <textarea 
                        className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500"
                        rows={3}
                        placeholder="Observaciones..."
                        value={comment}
                        onChange={(e) => setComment(e.target.value)}
                     />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>

                        {/* Botón Analista -> Coordinador */}
                        {canNotifyCoordinator && (
                            <button 
                                onClick={handleAnalystNotificationToCoordinator} 
                                className="flex items-center px-4 py-2 bg-blue-100 text-blue-700 hover:bg-blue-200 rounded-lg text-sm font-medium border border-blue-200 shadow-sm"
                            >
                                <Mail size={16} className="mr-2" /> Notificar al coordinador
                            </button>
                        )}

                        {/* Botón Coordinador -> Analista */}
                        {canNotifyAuthor && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm">
                                <Mail size={16} className="mr-2" /> Notificar Analista
                            </button>
                        )}

                        {/* Botón Nuevo para Referente/Control */}
                        {canNotifyExternal && (
                            <button 
                                onClick={handleNotifyExternal} 
                                className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium shadow-sm border border-purple-700 transition-colors"
                            >
                                <ExternalLink size={16} className="mr-2" /> 
                                Notificar Referente / Control
                            </button>
                        )}

                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}

                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* Historial (Right Column) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-fit max-h-[600px] overflow-y-auto">
            <h3 className="font-semibold text-slate-800 mb-4 border-b border-slate-100 pb-2">Historial</h3>
            <div className="space-y-6 pl-4 border-l-2 border-slate-100 relative">
                {history.length === 0 ? <p className="text-xs text-slate-400 italic">Sin historial registrado.</p> : history.map(h => (
                    <div key={h.id} className="relative">
                        <div className={`absolute -left-[21px] top-1 h-3 w-3 rounded-full border-2 border-white ${h.action === 'Observación' ? 'bg-indigo-400' : 'bg-slate-300'}`}></div>
                        <div className="text-xs text-slate-400 mb-0.5">{new Date(h.timestamp).toLocaleString()}</div>
                        <p className="text-sm font-medium text-slate-800">{h.action} <span className="font-normal text-slate-500">por {h.userName}</span></p>
                        {h.comment && <div className="mt-1 p-2 bg-slate-50 rounded text-xs text-slate-600 italic border border-slate-100">"{h.comment}"</div>}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* MODAL DE RESPUESTA (COORDINADOR) - CON CARGA DE ARCHIVO */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>
                          {pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}
                          {pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}
                      </h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>

                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed">
                                        {getCoordinatorRuleHint(doc.state, pendingAction)}
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* File Upload Zone */}
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : 
                              fileError.length > 0 ? 'border-red-300 bg-red-50' : 
                              'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>

                            <input 
                                type="file" 
                                ref={fileInputRef}
                                onChange={handleResponseFileSelect}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            />

                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={32} className="mx-auto mb-2" />
                                        <p className="font-semibold text-sm">{responseFile.name}</p>
                                        <div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200">
                                            <ul className="list-disc pl-4 space-y-1">
                                                {fileError.map((err, idx) => (
                                                    <li key={idx}>{err}</li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={32} className="mx-auto mb-2" />
                                    <p className="font-medium text-sm">Click para cargar respuesta</p>
                                    <p className="text-xs mt-1 text-slate-400">
                                        Debe cumplir con la nomenclatura de la etapa.
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button>
                            <button 
                                onClick={handleSubmitResponse}
                                disabled={!isFileValid}
                                className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2
                                    ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}
                                    disabled:opacity-50 disabled:cursor-not-allowed`}
                            >
                                <Save size={16} />
                                Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6">
                      <p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p>
                      <div className="flex justify-end gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button>
                          <button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;
